    pub(crate) fn allocate_structure_stub_repatch_code_id(&mut self) -> JitCodeId {
        let mut raw =
            if self.next_structure_stub_repatch_code_id < STRUCTURE_STUB_REPATCH_CODE_ID_BASE {
                STRUCTURE_STUB_REPATCH_CODE_ID_BASE
            } else {
                self.next_structure_stub_repatch_code_id.saturating_add(1)
            };

        while self.jit_code_id_is_recorded(JitCodeId(raw)) {
            raw = raw
                .checked_add(1)
                .filter(|id| *id >= STRUCTURE_STUB_REPATCH_CODE_ID_BASE)
                .unwrap_or(STRUCTURE_STUB_REPATCH_CODE_ID_BASE);
        }

        self.next_structure_stub_repatch_code_id = raw;
        JitCodeId(raw)
    }

    fn jit_code_id_is_recorded(&self, code_id: JitCodeId) -> bool {
        self.baseline_entry_artifacts
            .iter()
            .any(|artifact| artifact.id == code_id)
            || self
                .baseline_generated_code_artifacts
                .iter()
                .any(|artifact| artifact.id == code_id)
            || self
                .structure_stub_repatch_transactions
                .iter()
                .any(|transaction| transaction.code_id == code_id)
    }

