    pub(crate) fn property_store_mutation_candidate_table_for_owner_with_attached(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        attached: &[VmAttachedPropertyInlineCacheCandidate],
    ) -> Result<PropertyStoreMutationCandidateTable, InlineCacheValidationError> {
        let mut candidates = Vec::new();

        for readiness in self
            .generated_property_store_mutation_readiness_records
            .iter()
            .filter(|record| record.owner == owner && record.bytecode_snapshot == bytecode_snapshot)
        {
            let Some(candidate) = self.property_store_mutation_candidate_from_readiness_record(
                owner,
                bytecode_snapshot,
                readiness,
            )?
            else {
                continue;
            };

            // Projection only suppresses repeated valid readiness records, not malformed metadata.
            PropertyStoreMutationCandidateTable::new(owner, vec![candidate.clone()])?;
            vm_push_projected_property_store_mutation_candidate(&mut candidates, candidate);
        }

        for attached in attached {
            let Some(candidate) = self
                .property_store_mutation_candidate_from_attached_inline_cache(
                    owner,
                    bytecode_snapshot,
                    attached,
                )?
            else {
                continue;
            };
            // Projection only suppresses repeated valid attached metadata, not malformed metadata.
            PropertyStoreMutationCandidateTable::new(owner, vec![candidate.clone()])?;
            vm_push_projected_property_store_mutation_candidate(&mut candidates, candidate);
        }

        PropertyStoreMutationCandidateTable::new(owner, candidates)
    }

    fn property_store_mutation_candidate_from_readiness_record(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        readiness: &VmGeneratedPropertyStoreMutationReadinessRecord,
    ) -> Result<Option<PropertyStoreMutationCandidate>, InlineCacheValidationError> {
        self.property_store_mutation_candidate_from_readiness_record_with_plan_lifecycle(
            owner,
            bytecode_snapshot,
            readiness,
            VmStoreCandidatePlanLifecycleRequirement::Active,
        )
    }

    fn property_store_mutation_candidate_from_readiness_record_with_plan_lifecycle(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        readiness: &VmGeneratedPropertyStoreMutationReadinessRecord,
        plan_lifecycle: VmStoreCandidatePlanLifecycleRequirement,
    ) -> Result<Option<PropertyStoreMutationCandidate>, InlineCacheValidationError> {
        if readiness.owner != owner || readiness.bytecode_snapshot != bytecode_snapshot {
            return Ok(None);
        }

        let VmGeneratedPropertyStoreMutationReadinessOutcome::Accepted {
            observation_ordinal,
            barrier_evidence,
        } = readiness.outcome
        else {
            return Ok(None);
        };
        if readiness.observation_ordinal != Some(observation_ordinal)
            || readiness.barrier_evidence != Some(barrier_evidence)
        {
            return Ok(None);
        }

        let Some(plan_record) = self
            .property_store_access_case_plans
            .iter()
            .find(|record| record.ordinal == readiness.store_plan_ordinal)
        else {
            return Ok(None);
        };
        if !vm_store_candidate_plan_lifecycle_matches(plan_record.lifecycle, plan_lifecycle)
            || plan_record.owner != owner
            || plan_record.bytecode_index != readiness.bytecode_index
            || plan_record.bytecode_snapshot != bytecode_snapshot
            || plan_record.observation_ordinal != observation_ordinal
        {
            return Ok(None);
        }

        let plan = &plan_record.plan;
        if plan.owner != owner
            || plan.slot != readiness.slot
            || plan.bytecode_index != readiness.bytecode_index.offset()
            || plan.key != readiness.key
            || plan.access_case.key != readiness.key
            || plan.plan_kind != readiness.plan_kind
            || plan.access_case.base_structure != readiness.base_structure
            || plan.access_case.new_structure != readiness.planned_new_structure
            || plan.access_case.offset != readiness.planned_offset
        {
            return Ok(None);
        }

        PropertyStoreAccessCasePlanTable::new(owner, vec![plan.clone()])?;

        let Some(install_recheck) = self
            .property_store_access_case_install_rechecks
            .iter()
            .find(|record| record.ordinal == readiness.install_recheck_ordinal)
        else {
            return Ok(None);
        };
        if install_recheck.store_plan_ordinal != plan_record.ordinal
            || install_recheck.owner != owner
            || install_recheck.slot != readiness.slot
            || install_recheck.bytecode_index != readiness.bytecode_index
            || install_recheck.bytecode_snapshot != bytecode_snapshot
            || install_recheck.observation_ordinal != Some(observation_ordinal)
        {
            return Ok(None);
        }

        let VmPropertyStoreAccessCaseInstallRecheckOutcome::Accepted {
            barrier_evidence: recheck_barrier_evidence,
        } = install_recheck.outcome
        else {
            return Ok(None);
        };
        if install_recheck.barrier_evidence != Some(recheck_barrier_evidence)
            || recheck_barrier_evidence != barrier_evidence
        {
            return Ok(None);
        }

        let recheck_request = VmPropertyStoreAccessCaseInstallRecheckRequest {
            owner: install_recheck.owner,
            slot: install_recheck.slot,
            bytecode_index: install_recheck.bytecode_index,
            bytecode_snapshot: install_recheck.bytecode_snapshot,
            store_plan_ordinal: install_recheck.store_plan_ordinal,
        };
        let (_, current_barrier_evidence, current_recheck_outcome) =
            vm_property_store_access_case_install_recheck_outcome_with_plan_lifecycle(
                self,
                &recheck_request,
                plan_lifecycle,
            );
        let VmPropertyStoreAccessCaseInstallRecheckOutcome::Accepted {
            barrier_evidence: current_recheck_barrier_evidence,
        } = current_recheck_outcome
        else {
            return Ok(None);
        };
        if current_barrier_evidence != Some(current_recheck_barrier_evidence)
            || current_recheck_barrier_evidence != barrier_evidence
        {
            return Ok(None);
        }

        Ok(Some(PropertyStoreMutationCandidate {
            plan: plan.clone(),
            store_plan_ordinal: plan_record.ordinal,
            install_recheck_ordinal: install_recheck.ordinal,
            readiness_ordinal: readiness.ordinal,
            observation_ordinal,
            barrier_evidence: barrier_evidence.into(),
            stored_value_kind: readiness.stored_value_kind,
        }))
    }

    fn property_load_access_case_plan_from_attached_inline_cache(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        attached: &VmAttachedPropertyInlineCacheCandidate,
    ) -> Result<Option<PropertyLoadAccessCasePlan>, InlineCacheValidationError> {
        if attached.owner != owner
            || attached.bytecode_snapshot != bytecode_snapshot
            || attached.kind != VmPropertyInlineCacheAttachmentKind::OwnDataLoad
            || attached.stub_mode != PropertyInlineCacheStubMode::MetadataOnly
        {
            return Ok(None);
        }

        let Some(plan_record) = self
            .property_load_access_case_plans
            .iter()
            .find(|record| record.ordinal == attached.source_plan_ordinal)
        else {
            return Ok(None);
        };
        if plan_record.lifecycle
            != (VmPropertyLoadAccessCasePlanLifecycle::Attached {
                attachment_ordinal: attached.attachment_ordinal,
            })
            || plan_record.owner != owner
            || plan_record.bytecode_index != attached.bytecode_index
            || plan_record.bytecode_snapshot != bytecode_snapshot
            || plan_record.plan.owner != owner
            || plan_record.plan.slot != attached.slot
            || plan_record.plan.bytecode_index != attached.bytecode_index.offset()
        {
            return Ok(None);
        }

        let plan = &plan_record.plan;
        if plan.plan_kind != PropertyLoadAccessCasePlanKind::DataOnlyOwnLoad
            || plan.key != attached.key
            || plan.access_case.key != attached.key
            || plan.access_case.kind != AccessCaseKind::Load
            || plan.access_case.base_structure != Some(attached.base_structure)
            || plan.access_case.holder.is_some()
            || plan.access_case.new_structure.is_some()
            || attached.holder_structure.is_some()
            || attached.new_structure.is_some()
            || plan.access_case.offset != attached.offset
            || attached.offset.is_none()
            || plan.access_case.may_call_js
            || plan.access_case.via_global_proxy
            || !plan.access_case.dependencies.is_empty()
            || !plan.effect_contract.supports_generated_data_only_own_load()
        {
            return Ok(None);
        }

        PropertyLoadAccessCasePlanTable::new(owner, vec![plan.clone()])?;
        Ok(Some(plan.clone()))
    }

    fn property_load_access_case_plan_from_structure_stub_descriptor(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        candidate: &VmStructureStubPropertyInlineCacheCandidate,
    ) -> Result<Option<PropertyLoadAccessCasePlan>, InlineCacheValidationError> {
        if candidate.owner != owner || candidate.bytecode_snapshot != bytecode_snapshot {
            return Ok(None);
        }
        if validate_structure_stub_candidate_shape(candidate).is_err() {
            return Ok(None);
        }

        let Some(attachment) = self
            .property_inline_cache_attachment_records
            .iter()
            .find(|record| record.ordinal == candidate.attachment_ordinal)
        else {
            return Ok(None);
        };
        if !structure_stub_attachment_matches_candidate(attachment, candidate) {
            return Ok(None);
        }

        let Some(plan_record) = self
            .property_load_access_case_plans
            .iter()
            .find(|record| record.ordinal == candidate.source_plan_ordinal)
        else {
            return Ok(None);
        };
        if !structure_stub_plan_record_matches_candidate(
            plan_record,
            owner,
            bytecode_snapshot,
            candidate,
        ) {
            return Ok(None);
        }

        let Some(transaction) = self
            .structure_stub_repatch_transactions
            .iter()
            .find(|record| structure_stub_repatch_transaction_matches_candidate(record, candidate))
        else {
            return Ok(None);
        };
        if transaction.lifecycle != VmStructureStubRepatchTransactionLifecycle::Reserved
            || !matches!(
                transaction.outcome,
                VmStructureStubRepatchTransactionOutcome::Reserved
            )
            || !structure_stub_repatch_transaction_matches_plan_and_attachment(
                transaction,
                plan_record,
                attachment,
            )
        {
            return Ok(None);
        }
        let Some(access_case_ref) = structure_stub_repatch_transaction_access_case_ref(transaction)
        else {
            return Ok(None);
        };
        if !candidate
            .structure_stub_info
            .access_cases
            .contains(&access_case_ref)
        {
            return Ok(None);
        }

        let Some(link) = self.structure_stub_access_case_links.iter().find(|record| {
            structure_stub_access_case_link_matches(
                record,
                candidate,
                transaction.ordinal,
                access_case_ref,
            )
        }) else {
            return Ok(None);
        };
        if link.lifecycle != VmStructureStubAccessCaseLinkLifecycle::Active
            || !structure_stub_access_case_link_matches_plan_and_attachment(
                link,
                plan_record,
                attachment,
            )
        {
            return Ok(None);
        }
        let VmStructureStubAccessCaseLinkOutcome::Accepted { outcome } = &link.outcome else {
            return Ok(None);
        };
        if !structure_stub_access_case_link_outcome_matches_candidate(
            outcome,
            candidate,
            access_case_ref,
        ) {
            return Ok(None);
        }

        let plan = plan_record.plan.clone();
        PropertyLoadAccessCasePlanTable::new(owner, vec![plan.clone()])?;
        Ok(Some(plan))
    }

    fn property_load_guarded_candidate_from_attached_inline_cache(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        attached: &VmAttachedPropertyInlineCacheCandidate,
    ) -> Result<Option<JitPropertyLoadGuardedCandidate>, InlineCacheValidationError> {
        if attached.owner != owner
            || attached.bytecode_snapshot != bytecode_snapshot
            || !attached.kind.is_guarded_load()
            || attached.stub_mode != PropertyInlineCacheStubMode::MetadataOnly
        {
            return Ok(None);
        }

        let Some(guard_plan) = self
            .property_load_guard_plans
            .iter()
            .find(|record| record.ordinal == attached.source_plan_ordinal)
        else {
            return Ok(None);
        };
        if guard_plan.lifecycle
            != (VmPropertyLoadGuardPlanLifecycle::Attached {
                attachment_ordinal: attached.attachment_ordinal,
            })
            || guard_plan.owner != owner
            || guard_plan.bytecode_index != attached.bytecode_index
            || guard_plan.bytecode_snapshot != bytecode_snapshot
            || guard_plan.plan.owner != owner
            || guard_plan.plan.slot != attached.slot
            || guard_plan.plan.bytecode_index != attached.bytecode_index.offset()
        {
            return Ok(None);
        }

        let Some(materialization_ordinal) = attached.guarded_materialization_ordinal else {
            return Ok(None);
        };
        let Some(materialization) = self
            .property_load_guard_watchpoint_materializations
            .iter()
            .find(|record| record.ordinal == materialization_ordinal)
        else {
            return Ok(None);
        };
        if materialization.guard_plan_ordinal != Some(guard_plan.ordinal)
            || materialization.lifecycle
                != VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
            || !matches!(
                &materialization.outcome,
                VmPropertyLoadGuardWatchpointMaterializationOutcome::Accepted { .. }
            )
            || materialization.dependency_ordinals != attached.guarded_dependency_ordinals
        {
            return Ok(None);
        }
        let binding_set_ids = materialization
            .bindings
            .iter()
            .map(|binding| binding.set_id)
            .collect::<Vec<_>>();
        if binding_set_ids != attached.guarded_binding_set_ids {
            return Ok(None);
        }

        let candidate_kind = attached
            .kind
            .expected_guarded_candidate_kind()
            .expect("guarded attachment kind has a candidate kind");
        if vm_property_load_guarded_candidate_kind_for_plan(&guard_plan.plan)
            != Some(candidate_kind)
        {
            return Ok(None);
        }

        let descriptor = &guard_plan.plan.descriptor;
        if descriptor.key != attached.key
            || descriptor.base_structure != attached.base_structure
            || attached.new_structure.is_some()
        {
            return Ok(None);
        }
        match (attached.kind, descriptor.chain.outcome) {
            (
                VmPropertyInlineCacheAttachmentKind::GuardedPrototypeDataLoad,
                PropertyLoadGuardChainOutcome::PrototypeData {
                    holder_index,
                    offset,
                },
            ) => {
                let Some(holder_structure) = attached.holder_structure else {
                    return Ok(None);
                };
                if attached.offset != Some(offset)
                    || descriptor.offset != Some(offset)
                    || descriptor
                        .chain
                        .entries
                        .get(holder_index)
                        .is_none_or(|entry| entry.structure != holder_structure)
                {
                    return Ok(None);
                }
            }
            (
                VmPropertyInlineCacheAttachmentKind::GuardedNegativeLookup,
                PropertyLoadGuardChainOutcome::Missing {
                    terminal_null: true,
                },
            ) => {
                if attached.holder_structure.is_some()
                    || attached.offset.is_some()
                    || descriptor.offset.is_some()
                    || descriptor.holder_object.is_some()
                {
                    return Ok(None);
                }
            }
            _ => return Ok(None),
        }

        let candidate = JitPropertyLoadGuardedCandidate {
            plan: guard_plan.plan.clone(),
            guard_plan_ordinal: guard_plan.ordinal,
            materialization_ordinal,
            dependency_ordinals: attached.guarded_dependency_ordinals.clone(),
            binding_set_ids: attached.guarded_binding_set_ids.clone(),
            candidate_kind,
        };
        PropertyLoadGuardedCandidateTable::new(owner, vec![candidate.clone()])?;
        Ok(Some(candidate))
    }

    fn property_store_mutation_candidate_from_attached_inline_cache(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        attached: &VmAttachedPropertyInlineCacheCandidate,
    ) -> Result<Option<PropertyStoreMutationCandidate>, InlineCacheValidationError> {
        if attached.owner != owner
            || attached.bytecode_snapshot != bytecode_snapshot
            || !attached.kind.is_store()
            || attached.stub_mode != PropertyInlineCacheStubMode::MetadataOnly
            || attached.holder_structure.is_some()
        {
            return Ok(None);
        }

        let Some(readiness_ordinal) = attached.store_readiness_ordinal else {
            return Ok(None);
        };
        let Some(readiness) = self
            .generated_property_store_mutation_readiness_records
            .iter()
            .find(|record| record.ordinal == readiness_ordinal)
        else {
            return Ok(None);
        };

        let Some(candidate) = self
            .property_store_mutation_candidate_from_readiness_record_with_plan_lifecycle(
                owner,
                bytecode_snapshot,
                readiness,
                VmStoreCandidatePlanLifecycleRequirement::Attached {
                    attachment_ordinal: attached.attachment_ordinal,
                },
            )?
        else {
            return Ok(None);
        };

        if Some(candidate.install_recheck_ordinal) != attached.store_install_recheck_ordinal
            || candidate.store_plan_ordinal != attached.source_plan_ordinal
            || candidate.readiness_ordinal != readiness_ordinal
            || candidate.plan.owner != attached.owner
            || candidate.plan.slot != attached.slot
            || candidate.plan.bytecode_index != attached.bytecode_index.offset()
            || candidate.plan.key != attached.key
            || candidate.plan.access_case.key != attached.key
            || candidate.plan.access_case.base_structure != Some(attached.base_structure)
            || candidate.plan.access_case.new_structure != attached.new_structure
            || candidate.plan.access_case.offset != attached.offset
            || candidate.plan.plan_kind != attached.kind.expected_store_plan_kind().unwrap()
            || candidate.plan.access_case.kind
                != attached.kind.expected_store_access_case_kind().unwrap()
        {
            return Ok(None);
        }

        Ok(Some(candidate))
    }

    #[allow(dead_code)]
    pub(crate) fn property_load_guarded_candidate_table_for_owner(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
    ) -> Result<PropertyLoadGuardedCandidateTable, InlineCacheValidationError> {
        self.property_load_guarded_candidate_table_for_owner_with_attached(
            owner,
            bytecode_snapshot,
            &[],
        )
    }

    pub(crate) fn property_load_guarded_candidate_table_for_owner_with_attached(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        attached: &[VmAttachedPropertyInlineCacheCandidate],
    ) -> Result<PropertyLoadGuardedCandidateTable, InlineCacheValidationError> {
        let projection = self.project_property_load_guarded_candidates(
            VmPropertyLoadGuardedCandidateProjectionRequest {
                owner,
                bytecode_snapshot,
                bytecode_index: None,
            },
        );
        let mut candidates = Vec::with_capacity(projection.candidates.len());

        for record in &projection.candidates {
            let Some(guard_plan) = self.property_load_guard_plans.iter().find(|guard_plan| {
                guard_plan.ordinal == record.guard_plan_ordinal && guard_plan.lifecycle.is_active()
            }) else {
                return Err(
                    InlineCacheValidationError::PropertyLoadGuardedCandidateMissingGuardPlan {
                        guard_plan_ordinal: record.guard_plan_ordinal,
                    },
                );
            };

            let (candidate_kind, binding_set_ids) = match &record.candidate {
                VmPropertyLoadGuardedCandidate::PrototypeData {
                    binding_set_ids, ..
                } => (
                    JitPropertyLoadGuardedCandidateKind::PrototypeData,
                    binding_set_ids.clone(),
                ),
                VmPropertyLoadGuardedCandidate::NegativeLookup {
                    binding_set_ids, ..
                } => (
                    JitPropertyLoadGuardedCandidateKind::NegativeLookup,
                    binding_set_ids.clone(),
                ),
            };

            let candidate = JitPropertyLoadGuardedCandidate {
                plan: guard_plan.plan.clone(),
                guard_plan_ordinal: record.guard_plan_ordinal,
                materialization_ordinal: record.materialization_ordinal,
                dependency_ordinals: record.dependency_ordinals.clone(),
                binding_set_ids,
                candidate_kind,
            };
            let key = vm_property_load_guarded_candidate_table_key(&candidate);
            if let Some(existing_index) = candidates.iter().position(|candidate| {
                vm_property_load_guarded_candidate_table_key(candidate) == key
            }) {
                // C++ PolymorphicAccess keeps access cases in addition order and, during
                // regeneration, removes older cases that a later AccessCase::canReplace().
                // Rust rebuilds this immutable sidecar table from VM records, so collapse
                // semantically equivalent guarded plans here and keep the newest active plan.
                candidates[existing_index] = candidate;
            } else {
                candidates.push(candidate);
            }
        }

        for attached in attached {
            let Some(candidate) = self.property_load_guarded_candidate_from_attached_inline_cache(
                owner,
                bytecode_snapshot,
                attached,
            )?
            else {
                continue;
            };
            // Projection only suppresses repeated valid attached metadata, not malformed metadata.
            PropertyLoadGuardedCandidateTable::new(owner, vec![candidate.clone()])?;
            let key = vm_property_load_guarded_candidate_table_key(&candidate);
            if candidates
                .iter()
                .any(|candidate| vm_property_load_guarded_candidate_table_key(candidate) == key)
            {
                continue;
            }
            candidates.push(candidate);
        }

        PropertyLoadGuardedCandidateTable::new(owner, candidates)
    }

    #[cfg(test)]
    pub(crate) fn property_load_access_case_candidates_for_bytecode(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        bytecode_index: BytecodeIndex,
    ) -> Result<Vec<PropertyLoadAccessCasePlan>, InlineCacheValidationError> {
        let table =
            self.property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)?;
        Ok(table
            .candidates_for_bytecode_index(bytecode_index.offset())
            .cloned()
            .collect())
    }

