    fn property_load_access_case_replaced_by_existing_handler_case(
        &self,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        candidate: &PropertyLoadAccessCasePlan,
    ) -> bool {
        self.property_load_access_case_plans.iter().any(|record| {
            record.bytecode_snapshot == bytecode_snapshot
                && matches!(
                    record.lifecycle,
                    VmPropertyLoadAccessCasePlanLifecycle::Active
                        | VmPropertyLoadAccessCasePlanLifecycle::Attached { .. }
                )
                && vm_property_load_access_case_can_replace(&record.plan, candidate)
        })
    }

    fn property_store_access_case_replaced_by_existing_handler_case(
        &self,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        candidate: &PropertyStoreAccessCasePlan,
    ) -> bool {
        self.property_store_access_case_plans.iter().any(|record| {
            record.bytecode_snapshot == bytecode_snapshot
                && matches!(
                    record.lifecycle,
                    VmPropertyStoreAccessCasePlanLifecycle::Active
                        | VmPropertyStoreAccessCasePlanLifecycle::Attached { .. }
                )
                && vm_property_store_access_case_can_replace(&record.plan, candidate)
        })
    }

    fn consider_property_inline_cache_evolution_for_store_plan(
        &mut self,
        request: &VmPropertyStoreObservationRequest,
        plan: &PropertyStoreAccessCasePlan,
        replaced_by_existing_case: bool,
    ) -> VmPropertyInlineCacheEvolutionRecord {
        let structure = plan
            .access_case
            .base_structure
            .filter(|structure| *structure != StructureId::INVALID);
        let key = matches!(
            request.descriptor.cache_kind,
            crate::jit::InlineCacheKind::ElementStore
        )
        .then_some(plan.key);
        self.consider_property_inline_cache_evolution(
            VmPropertyInlineCacheEvolutionSite {
                owner: request.owner,
                bytecode_index: request.bytecode_index,
                bytecode_snapshot: request.bytecode_snapshot,
                slot: plan.slot,
                kind: VmPropertyInlineCacheEvolutionKind::Store,
            },
            structure,
            key,
            replaced_by_existing_case,
            false,
            vm_property_store_plan_can_use_put_by_id_megamorphic(&request.descriptor, plan),
            false,
        )
    }

    fn consider_property_inline_cache_evolution(
        &mut self,
        site: VmPropertyInlineCacheEvolutionSite,
        structure: Option<StructureId>,
        key: Option<CacheKey>,
        replaced_by_existing_case: bool,
        can_use_get_by_id_megamorphic: bool,
        can_use_put_by_id_megamorphic: bool,
        can_use_in_by_id_megamorphic: bool,
    ) -> VmPropertyInlineCacheEvolutionRecord {
        let state_index = if let Some(index) = self
            .property_inline_cache_evolution_states
            .iter()
            .position(|state| state.site == site)
        {
            index
        } else {
            self.property_inline_cache_evolution_states
                .push(VmPropertyInlineCacheEvolutionState::new(site));
            self.property_inline_cache_evolution_states.len() - 1
        };

        let (decision, counters_before, counters_after) = {
            let state = &mut self.property_inline_cache_evolution_states[state_index];
            let counters_before = state.counters();
            let mut decision = match state.terminal {
                Some(VmPropertyInlineCacheEvolutionTerminalState::GaveUp) => {
                    VmPropertyInlineCacheEvolutionDecision::SkippedGaveUp
                }
                Some(VmPropertyInlineCacheEvolutionTerminalState::MegamorphicLoad) => {
                    VmPropertyInlineCacheEvolutionDecision::SkippedMegamorphicLoad
                }
                Some(VmPropertyInlineCacheEvolutionTerminalState::MegamorphicStore) => {
                    VmPropertyInlineCacheEvolutionDecision::SkippedMegamorphicStore
                }
                Some(VmPropertyInlineCacheEvolutionTerminalState::MegamorphicHas) => {
                    VmPropertyInlineCacheEvolutionDecision::SkippedMegamorphicHas
                }
                None if state.countdown == 0 => {
                    state.repatch_count = state.repatch_count.saturating_add(1);
                    let decision = if state.repatch_count > PROPERTY_IC_REPATCH_COUNT_FOR_COOLDOWN {
                        state.repatch_count = 0;
                        state.countdown =
                            property_inline_cache_evolution_cooldown(state.number_of_cooldowns);
                        state.number_of_cooldowns = state.number_of_cooldowns.saturating_add(1);
                        state.buffering_countdown = 0;
                        VmPropertyInlineCacheEvolutionDecision::Admitted
                    } else if state.buffering_countdown == 0 {
                        VmPropertyInlineCacheEvolutionDecision::Admitted
                    } else {
                        state.buffering_countdown = state.buffering_countdown.saturating_sub(1);
                        if let Some(structure) = structure {
                            let buffered =
                                VmPropertyInlineCacheBufferedStructureKey { structure, key };
                            if state.buffered_structures.contains(&buffered) {
                                VmPropertyInlineCacheEvolutionDecision::SkippedBufferedDuplicate
                            } else {
                                state.buffered_structures.push(buffered);
                                VmPropertyInlineCacheEvolutionDecision::Admitted
                            }
                        } else {
                            VmPropertyInlineCacheEvolutionDecision::Admitted
                        }
                    };
                    decision
                }
                None => {
                    state.countdown = state.countdown.saturating_sub(1);
                    if state.number_of_cooldowns == 0 && state.repatch_count == 0 {
                        VmPropertyInlineCacheEvolutionDecision::SkippedInitialCountdown
                    } else {
                        VmPropertyInlineCacheEvolutionDecision::SkippedCooldown
                    }
                }
            };
            if decision == VmPropertyInlineCacheEvolutionDecision::Admitted
                && replaced_by_existing_case
            {
                decision = VmPropertyInlineCacheEvolutionDecision::SkippedReplacedByExistingCase;
            }
            if decision == VmPropertyInlineCacheEvolutionDecision::Admitted {
                state.all_accepted_cases_can_use_get_by_id_megamorphic &=
                    can_use_get_by_id_megamorphic
                        && site.kind == VmPropertyInlineCacheEvolutionKind::Load;
                state.all_accepted_cases_can_use_put_by_id_megamorphic &=
                    can_use_put_by_id_megamorphic
                        && site.kind == VmPropertyInlineCacheEvolutionKind::Store;
                state.all_accepted_cases_can_use_in_by_id_megamorphic &=
                    can_use_in_by_id_megamorphic
                        && site.kind == VmPropertyInlineCacheEvolutionKind::Has;
                state.accepted_access_case_count = state
                    .accepted_access_case_count
                    .saturating_add(1)
                    .min(PROPERTY_IC_MAX_ACCESS_VARIANT_LIST_SIZE);
                if state.accepted_access_case_count >= PROPERTY_IC_MAX_ACCESS_VARIANT_LIST_SIZE {
                    if state.all_accepted_cases_can_use_get_by_id_megamorphic {
                        state.terminal =
                            Some(VmPropertyInlineCacheEvolutionTerminalState::MegamorphicLoad);
                        decision = VmPropertyInlineCacheEvolutionDecision::GeneratedMegamorphicLoad;
                    } else if state.all_accepted_cases_can_use_put_by_id_megamorphic {
                        state.terminal =
                            Some(VmPropertyInlineCacheEvolutionTerminalState::MegamorphicStore);
                        decision =
                            VmPropertyInlineCacheEvolutionDecision::GeneratedMegamorphicStore;
                    } else if state.all_accepted_cases_can_use_in_by_id_megamorphic {
                        state.terminal =
                            Some(VmPropertyInlineCacheEvolutionTerminalState::MegamorphicHas);
                        decision = VmPropertyInlineCacheEvolutionDecision::GeneratedMegamorphicHas;
                    } else {
                        state.terminal = Some(VmPropertyInlineCacheEvolutionTerminalState::GaveUp);
                    }
                }
            }
            let counters_after = state.counters();
            (decision, counters_before, counters_after)
        };

        let record = VmPropertyInlineCacheEvolutionRecord {
            ordinal: self.next_record_ordinal(),
            owner: site.owner,
            bytecode_index: site.bytecode_index,
            bytecode_snapshot: site.bytecode_snapshot,
            slot: site.slot,
            kind: site.kind,
            structure,
            key,
            decision,
            counters_before,
            counters_after,
        };
        self.property_inline_cache_evolution_records
            .push(record.clone());
        record
    }

    pub(crate) fn record_property_store_observation(
        &mut self,
        request: VmPropertyStoreObservationRequest,
    ) -> Result<VmPropertyStoreObservationRecord, InlineCacheValidationError> {
        if request.descriptor.validate().is_err() {
            return Err(
                InlineCacheValidationError::PropertyObservationUnsupportedCacheKind {
                    expected: crate::jit::InlineCacheKind::PropertyStore,
                    actual: request.descriptor.cache_kind,
                },
            );
        }
        if request.descriptor.owner != request.owner {
            return Err(
                InlineCacheValidationError::PropertyObservationHandoffOwnerMismatch {
                    observation: request.owner,
                    handoff: request.descriptor.owner,
                },
            );
        }
        if request.descriptor.bytecode_index != request.bytecode_index.offset() {
            return Err(
                InlineCacheValidationError::PropertyObservationHandoffBytecodeIndexMismatch {
                    observation: request.bytecode_index.offset(),
                    handoff: request.descriptor.bytecode_index,
                },
            );
        }

        let record = VmPropertyStoreObservationRecord {
            ordinal: self.next_record_ordinal(),
            owner: request.owner,
            frame: request.frame,
            bytecode_index: request.bytecode_index,
            bytecode_snapshot: request.bytecode_snapshot,
            descriptor: request.descriptor.clone(),
        };
        self.property_store_observations.push(record.clone());
        if let Some(plan) = vm_property_store_access_case_plan_from_observation(&record.descriptor)
        {
            let replaced_by_existing_case = self
                .property_store_access_case_replaced_by_existing_handler_case(
                    request.bytecode_snapshot,
                    &plan,
                );
            let evolution = self.consider_property_inline_cache_evolution_for_store_plan(
                &request,
                &plan,
                replaced_by_existing_case,
            );
            if matches!(
                evolution.decision,
                VmPropertyInlineCacheEvolutionDecision::GeneratedMegamorphicStore
                    | VmPropertyInlineCacheEvolutionDecision::SkippedMegamorphicStore
            ) {
                self.record_property_store_megamorphic_cache_entry(
                    &request,
                    record.ordinal,
                    evolution.ordinal,
                    &plan,
                );
            }
            if !evolution.decision.admits_plan() {
                return Ok(record);
            }
            let ordinal = self.next_record_ordinal();
            self.bump_plan_generation();
            self.property_store_access_case_plans
                .push(VmPropertyStoreAccessCasePlanRecord {
                    ordinal,
                    observation_ordinal: record.ordinal,
                    owner: request.owner,
                    frame: request.frame,
                    bytecode_index: request.bytecode_index,
                    bytecode_snapshot: request.bytecode_snapshot,
                    lifecycle: VmPropertyStoreAccessCasePlanLifecycle::Active,
                    plan,
                });
        }
        Ok(record)
    }

    #[allow(dead_code)]
    pub(crate) fn record_property_store_access_case_install_recheck(
        &mut self,
        request: VmPropertyStoreAccessCaseInstallRecheckRequest,
    ) -> VmPropertyStoreAccessCaseInstallRecheckRecord {
        let (observation_ordinal, barrier_evidence, outcome) =
            vm_property_store_access_case_install_recheck_outcome(self, &request);
        let record = VmPropertyStoreAccessCaseInstallRecheckRecord {
            ordinal: self.next_record_ordinal(),
            owner: request.owner,
            slot: request.slot,
            bytecode_index: request.bytecode_index,
            bytecode_snapshot: request.bytecode_snapshot,
            store_plan_ordinal: request.store_plan_ordinal,
            observation_ordinal,
            barrier_evidence,
            outcome,
        };
        // UN-CAPPED (hotfix, redesign-audit Unit 0): 8ad6f87's cap comment was
        // wrong — property_store_mutation_candidate_from_readiness_record_with_
        // plan_lifecycle (:1228-1234) reads this vec back by exact ordinal from
        // baseline-JIT codegen paths; a cap silently drops store-IC candidates
        // past the limit (perf cliff). Unbounded growth is the pre-existing
        // divergence; the permanent fix moves the barrier-evidence outcome onto
        // the store plan's resident field (redesign Unit 5), retiring this log.
        self.property_store_access_case_install_rechecks
            .push(record.clone());
        record
    }

    pub(crate) fn record_call_observation(
        &mut self,
        request: VmCallObservationRequest,
    ) -> Result<VmCallObservationRecord, InlineCacheValidationError> {
        validate_vm_call_observation_request(&request)?;

        let record = VmCallObservationRecord {
            ordinal: self.next_record_ordinal(),
            owner: request.owner,
            frame: request.frame,
            bytecode_index: request.bytecode_index,
            opcode: request.opcode,
            bytecode_snapshot: request.bytecode_snapshot,
            descriptor: request.descriptor.clone(),
        };
        self.call_observations.push(record.clone());
        let call_link_descriptor =
            metadata_only_call_link_descriptor_from_observation(record.opcode, &record.descriptor);
        let call_link_descriptor_ordinal = call_link_descriptor
            .as_ref()
            .map(|_| self.next_record_ordinal());
        let blockers =
            derive_call_link_readiness_blockers(&record.descriptor, call_link_descriptor.is_some());
        debug_assert!(!blockers.is_empty());
        let readiness_record = VmCallLinkReadinessRecord {
            ordinal: self.next_record_ordinal(),
            owner: record.owner,
            frame: record.frame,
            bytecode_index: record.bytecode_index,
            opcode: record.opcode,
            bytecode_snapshot: record.bytecode_snapshot,
            observation_ordinal: record.ordinal,
            call_link_descriptor_ordinal,
            blockers,
        };
        self.call_link_readiness_records
            .push(readiness_record.clone());
        if let (Some(ordinal), Some(descriptor)) =
            (call_link_descriptor_ordinal, call_link_descriptor)
        {
            self.call_link_descriptor_records
                .push(VmCallLinkDescriptorRecord {
                    ordinal,
                    owner: record.owner,
                    frame: record.frame,
                    bytecode_index: record.bytecode_index,
                    opcode: record.opcode,
                    bytecode_snapshot: record.bytecode_snapshot,
                    observation_ordinal: record.ordinal,
                    readiness_ordinal: readiness_record.ordinal,
                    lifecycle: VmCallLinkDescriptorLifecycle::MetadataOnly,
                    descriptor,
                    blockers,
                });
        }
        Ok(record)
    }

    pub(crate) fn record_vm_owned_call_target_validation(
        &mut self,
        request: VmOwnedCallTargetValidationRequest,
    ) -> VmOwnedCallTargetValidationRecord {
        let record = VmOwnedCallTargetValidationRecord {
            ordinal: self.next_record_ordinal(),
            owner: request.owner,
            frame: request.frame,
            bytecode_index: request.bytecode_index,
            opcode: request.opcode,
            target_code_block: request.target_code_block,
            expected_specialization: request.expected_specialization,
            outcome: request.outcome,
        };
        // Transitional cap: diagnostic-only (see `HOT_TELEMETRY_RECORD_RETAIN_LIMIT`).
        if self.vm_owned_call_target_validation_records.len() < HOT_TELEMETRY_RECORD_RETAIN_LIMIT {
            self.vm_owned_call_target_validation_records
                .push(record.clone());
        }
        record
    }

    pub(crate) fn record_call_link_boundary_validation(
        &mut self,
        request: VmCallLinkBoundaryValidationRequest,
    ) -> VmCallLinkBoundaryValidationRecord {
        let descriptor_record = self
            .call_link_descriptor_records
            .iter()
            .find(|record| record.ordinal == request.descriptor_ordinal)
            .cloned();

        let (owner, frame, bytecode_index, opcode, bytecode_snapshot, outcome) =
            match descriptor_record {
                Some(descriptor_record) => {
                    let outcome =
                        validate_call_link_boundary_request(&descriptor_record, request.evidence);
                    (
                        descriptor_record.owner,
                        descriptor_record.frame,
                        descriptor_record.bytecode_index,
                        descriptor_record.opcode,
                        descriptor_record.bytecode_snapshot,
                        outcome,
                    )
                }
                None => (
                    request.owner,
                    request.frame,
                    request.bytecode_index,
                    request.opcode,
                    request.bytecode_snapshot,
                    VmCallLinkBoundaryValidationOutcome::Rejected(
                        VmCallLinkBoundaryValidationRejection::MissingDescriptorRecord {
                            descriptor_ordinal: request.descriptor_ordinal,
                        },
                    ),
                ),
            };

        let record = VmCallLinkBoundaryValidationRecord {
            ordinal: self.next_record_ordinal(),
            descriptor_ordinal: request.descriptor_ordinal,
            owner,
            frame,
            bytecode_index,
            opcode,
            bytecode_snapshot,
            outcome,
        };
        self.call_link_boundary_validation_records
            .push(record.clone());
        record
    }

    pub(crate) fn record_call_link_attachment_plan(
        &mut self,
        request: VmCallLinkAttachmentPlanRequest,
    ) -> VmCallLinkAttachmentPlanRecord {
        let validation = self
            .call_link_boundary_validation_records
            .iter()
            .find(|record| record.ordinal == request.boundary_validation_ordinal)
            .cloned();
        let (owner, frame, bytecode_index, opcode, bytecode_snapshot, descriptor_ordinal, outcome) =
            match validation {
                Some(validation) => {
                    let descriptor_record = self
                        .call_link_descriptor_records
                        .iter()
                        .find(|record| record.ordinal == validation.descriptor_ordinal);
                    let outcome = derive_call_link_attachment_plan_outcome(
                        &validation,
                        descriptor_record,
                        request.slot,
                    );
                    (
                        validation.owner,
                        validation.frame,
                        validation.bytecode_index,
                        validation.opcode,
                        validation.bytecode_snapshot,
                        Some(validation.descriptor_ordinal),
                        outcome,
                    )
                }
                None => (
                    request.owner,
                    request.frame,
                    request.bytecode_index,
                    request.opcode,
                    request.bytecode_snapshot,
                    None,
                    VmCallLinkAttachmentPlanOutcome::Rejected {
                        reason:
                            VmCallLinkAttachmentPlanRejectionReason::BoundaryValidationMissing {
                                boundary_validation_ordinal: request.boundary_validation_ordinal,
                            },
                    },
                ),
            };

        let record = VmCallLinkAttachmentPlanRecord {
            ordinal: self.next_record_ordinal(),
            boundary_validation_ordinal: request.boundary_validation_ordinal,
            descriptor_ordinal,
            owner,
            frame,
            bytecode_index,
            opcode,
            bytecode_snapshot,
            lifecycle: VmCallLinkAttachmentPlanLifecycle::MetadataOnly,
            outcome,
        };
        self.bump_plan_generation();
        self.call_link_attachment_plan_records.push(record.clone());
        record
    }

    #[allow(dead_code)]
    pub(crate) fn record_call_link_attachment_install_recheck(
        &mut self,
        request: VmCallLinkAttachmentInstallRecheckRequest,
    ) -> VmCallLinkAttachmentInstallRecheckRecord {
        let accepted_evidence = call_link_attachment_install_recheck_evidence_summary(&request);
        let (derived_ordinals, outcome) =
            vm_call_link_attachment_install_recheck_outcome(self, &request);
        let record = VmCallLinkAttachmentInstallRecheckRecord {
            ordinal: self.next_record_ordinal(),
            owner: request.owner,
            slot: request.slot,
            bytecode_index: request.bytecode_index,
            bytecode_snapshot: request.bytecode_snapshot,
            attachment_plan_ordinal: request.attachment_plan_ordinal,
            boundary_validation_ordinal: derived_ordinals.boundary_validation_ordinal,
            descriptor_ordinal: derived_ordinals.descriptor_ordinal,
            observation_ordinal: derived_ordinals.observation_ordinal,
            readiness_ordinal: derived_ordinals.readiness_ordinal,
            accepted_evidence,
            outcome,
        };
        self.call_link_attachment_install_rechecks
            .push(record.clone());
        record
    }

