    #[allow(dead_code)]
    pub(crate) fn record_call_link_inline_cache_attachment(
        &mut self,
        request: VmCallLinkInlineCacheAttachmentRequest,
        outcome: VmCallLinkInlineCacheAttachmentOutcome,
    ) -> VmCallLinkInlineCacheAttachmentRecord {
        let code_block_outcome = match &outcome {
            VmCallLinkInlineCacheAttachmentOutcome::Accepted { outcome } => Some(outcome.clone()),
            VmCallLinkInlineCacheAttachmentOutcome::Rejected { .. } => None,
        };
        let code_block_error = match &outcome {
            VmCallLinkInlineCacheAttachmentOutcome::Rejected {
                reason:
                    VmCallLinkInlineCacheAttachmentRejectionReason::CodeBlockAttachmentError { error },
            } => Some(error.clone()),
            _ => None,
        };
        let ordinals = call_link_inline_cache_attachment_ordinals_for_request(self, &request);
        let lifecycle = if matches!(
            outcome,
            VmCallLinkInlineCacheAttachmentOutcome::Accepted { .. }
        ) {
            VmCallLinkInlineCacheAttachmentLifecycle::Active
        } else {
            VmCallLinkInlineCacheAttachmentLifecycle::Rejected
        };
        let record = VmCallLinkInlineCacheAttachmentRecord {
            ordinal: self.next_record_ordinal(),
            owner: request.owner,
            bytecode_index: request.bytecode_index,
            bytecode_snapshot: request.bytecode_snapshot,
            slot: request.slot,
            attachment_plan_ordinal: request.attachment_plan_ordinal,
            install_recheck_ordinal: request.install_recheck_ordinal,
            boundary_validation_ordinal: ordinals.boundary_validation_ordinal,
            descriptor_ordinal: ordinals.descriptor_ordinal,
            observation_ordinal: ordinals.observation_ordinal,
            readiness_ordinal: ordinals.readiness_ordinal,
            code_block_outcome,
            code_block_error,
            lifecycle,
            outcome: outcome.clone(),
        };

        self.bump_plan_generation();
        self.call_link_inline_cache_attachment_records
            .push(record.clone());
        record
    }

