    #[allow(dead_code)]
    pub(crate) fn record_call_link_inline_cache_clear(
        &mut self,
        request: VmCallLinkInlineCacheClearRequest,
        outcome: VmCallLinkInlineCacheClearOutcome,
    ) -> VmCallLinkInlineCacheClearRecord {
        let ordinal = self.next_record_ordinal();
        let code_block_outcome = match &outcome {
            VmCallLinkInlineCacheClearOutcome::Accepted { outcome } => Some(outcome.clone()),
            VmCallLinkInlineCacheClearOutcome::Rejected { .. } => None,
        };
        let code_block_error = match &outcome {
            VmCallLinkInlineCacheClearOutcome::Rejected {
                reason: VmCallLinkInlineCacheClearRejectionReason::CodeBlockClearError { error },
            } => Some(error.clone()),
            _ => None,
        };
        let lifecycle = if matches!(outcome, VmCallLinkInlineCacheClearOutcome::Accepted { .. }) {
            VmCallLinkInlineCacheClearLifecycle::Cleared
        } else {
            VmCallLinkInlineCacheClearLifecycle::Rejected
        };
        let record = VmCallLinkInlineCacheClearRecord {
            ordinal,
            owner: request.owner,
            bytecode_index: request.bytecode_index,
            bytecode_snapshot: request.bytecode_snapshot,
            slot: request.slot,
            attachment_ordinal: request.attachment_ordinal,
            attachment_plan_ordinal: request.attachment_plan_ordinal,
            install_recheck_ordinal: request.install_recheck_ordinal,
            boundary_validation_ordinal: request.boundary_validation_ordinal,
            descriptor_ordinal: request.descriptor_ordinal,
            observation_ordinal: request.observation_ordinal,
            readiness_ordinal: request.readiness_ordinal,
            target: request.target.clone(),
            code_block_outcome,
            code_block_error,
            lifecycle,
            outcome: outcome.clone(),
        };

        if matches!(outcome, VmCallLinkInlineCacheClearOutcome::Accepted { .. }) {
            self.retire_call_link_inline_cache_metadata_for_clear(&record);
        }

        self.call_link_inline_cache_clear_records
            .push(record.clone());
        record
    }

    fn retire_call_link_inline_cache_metadata_for_clear(
        &mut self,
        clear: &VmCallLinkInlineCacheClearRecord,
    ) {
        // Batch 2: this retires `call_link_inline_cache_attachment_records` and
        // `call_link_attachment_plan_records` entries (-> Cleared/RetiredByClear).
        // Bump unconditionally at entry; over-bump if no record matches is sound.
        self.bump_plan_generation();
        if let Some(attachment) = self
            .call_link_inline_cache_attachment_records
            .iter_mut()
            .find(|record| {
                record.ordinal == clear.attachment_ordinal
                    && call_link_inline_cache_attachment_matches_clear(record, clear)
            })
        {
            if attachment.lifecycle == VmCallLinkInlineCacheAttachmentLifecycle::Active {
                attachment.lifecycle = VmCallLinkInlineCacheAttachmentLifecycle::Cleared {
                    clear_ordinal: clear.ordinal,
                };
            }
        }

        for plan in self
            .call_link_attachment_plan_records
            .iter_mut()
            .filter(|record| call_link_attachment_plan_matches_clear(record, clear))
        {
            if plan.lifecycle == VmCallLinkAttachmentPlanLifecycle::MetadataOnly
                && matches!(
                    &plan.outcome,
                    VmCallLinkAttachmentPlanOutcome::Planned { .. }
                )
            {
                plan.lifecycle = VmCallLinkAttachmentPlanLifecycle::RetiredByClear {
                    clear_ordinal: clear.ordinal,
                    attachment_ordinal: clear.attachment_ordinal,
                };
            }
        }

        if let Some(descriptor_ordinal) = clear.descriptor_ordinal {
            if let Some(descriptor) = self.call_link_descriptor_records.iter_mut().find(|record| {
                record.ordinal == descriptor_ordinal
                    && call_link_descriptor_record_matches_clear(record, clear)
            }) {
                if descriptor.lifecycle == VmCallLinkDescriptorLifecycle::MetadataOnly {
                    descriptor.lifecycle = VmCallLinkDescriptorLifecycle::RetiredByClear {
                        clear_ordinal: clear.ordinal,
                        attachment_ordinal: clear.attachment_ordinal,
                    };
                }
            }
        }
    }

    pub(crate) fn call_link_attachment_plan_table_for_owner(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
    ) -> Result<CallLinkAttachmentPlanTable, InlineCacheValidationError> {
        let mut plans = Vec::new();
        for record in self
            .call_link_attachment_plan_records
            .iter()
            .filter(|record| {
                record.owner == owner
                    && record.bytecode_snapshot == bytecode_snapshot
                    && record.lifecycle == VmCallLinkAttachmentPlanLifecycle::MetadataOnly
            })
        {
            let VmCallLinkAttachmentPlanOutcome::Planned { plan } = &record.outcome else {
                continue;
            };
            CallLinkAttachmentPlanTable::new(owner, vec![(**plan).clone()])?;
            if plans.iter().any(|existing| {
                call_link_attachment_plan_key(existing) == call_link_attachment_plan_key(plan)
            }) {
                continue;
            }
            plans.push((**plan).clone());
        }
        CallLinkAttachmentPlanTable::new(owner, plans)
    }

    pub(crate) fn generated_call_link_candidate_table_for_owner_with_attached(
        &self,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        attached: &[CodeBlockRegistryAttachedCallLinkInlineCacheCandidate],
    ) -> Result<GeneratedCallLinkCandidateTable, InlineCacheValidationError> {
        let mut candidates = Vec::new();
        let mut semantic_keys = Vec::new();

        for attached_candidate in attached.iter().filter(|candidate| {
            candidate.owner == owner && candidate.bytecode_snapshot == bytecode_snapshot
        }) {
            let Some(attachment) = self
                .call_link_inline_cache_attachment_records
                .iter()
                .find(|record| record.ordinal == attached_candidate.attachment_ordinal)
            else {
                continue;
            };

            let Some(attached_outcome) =
                active_call_link_inline_cache_attachment_outcome(attachment)
            else {
                continue;
            };

            let plan = validate_generated_call_link_attached_candidate(
                self,
                owner,
                bytecode_snapshot,
                attached_candidate,
                attachment,
                attached_outcome,
            )?;
            let candidate =
                generated_call_link_candidate_from_attachment(attachment, attached_outcome, plan)?;
            let semantic_key = generated_call_link_candidate_key_from_target(&candidate);
            if semantic_keys.contains(&semantic_key) {
                continue;
            }
            semantic_keys.push(semantic_key);
            candidates.push(candidate);
        }

        for attachment in self
            .call_link_inline_cache_attachment_records
            .iter()
            .filter(|attachment| {
                attachment.owner == owner && attachment.bytecode_snapshot == bytecode_snapshot
            })
        {
            let Some(plan) = validate_generated_call_link_metadata_only_polymorphic_candidate(
                self,
                owner,
                bytecode_snapshot,
                attachment,
            )?
            else {
                continue;
            };
            let candidate =
                generated_call_link_candidate_from_metadata_only_attachment(attachment, plan)?;
            let semantic_key = generated_call_link_candidate_key_from_target(&candidate);
            if semantic_keys.contains(&semantic_key) {
                continue;
            }
            semantic_keys.push(semantic_key);
            candidates.push(candidate);
        }

        GeneratedCallLinkCandidateTable::new(owner, candidates)
    }

