    #[allow(dead_code)]
    pub(crate) fn project_property_load_guarded_candidates(
        &self,
        request: VmPropertyLoadGuardedCandidateProjectionRequest,
    ) -> VmPropertyLoadGuardedCandidateProjection {
        let mut projection = VmPropertyLoadGuardedCandidateProjection {
            owner: request.owner,
            bytecode_snapshot: request.bytecode_snapshot,
            bytecode_index: request.bytecode_index,
            candidates: Vec::new(),
            rejections: Vec::new(),
        };
        let mut accepted_guard_plan_ordinals = Vec::new();

        for materialization in &self.property_load_guard_watchpoint_materializations {
            match vm_property_load_guarded_candidate_outcome(self, &request, materialization) {
                VmPropertyLoadGuardedCandidateProjectionEntry::Accepted(record) => {
                    if accepted_guard_plan_ordinals.contains(&record.guard_plan_ordinal) {
                        continue;
                    }
                    accepted_guard_plan_ordinals.push(record.guard_plan_ordinal);
                    projection.candidates.push(record);
                }
                VmPropertyLoadGuardedCandidateProjectionEntry::Rejected(record) => {
                    projection.rejections.push(record)
                }
            }
        }

        projection
    }

    #[allow(dead_code)]
    pub(crate) fn record_property_load_guard_watchpoint_invalidation(
        &mut self,
        request: VmPropertyLoadGuardWatchpointInvalidationRequest,
    ) -> VmPropertyLoadGuardWatchpointInvalidationRecord {
        // Batch 2: on an Accepted invalidation this retires a
        // `property_load_guard_plans` entry (-> Retired). Bump unconditionally at
        // entry; over-bump on a non-retiring outcome is sound.
        self.bump_plan_generation();
        let ordinal = self.next_record_ordinal();
        let outcome = vm_property_load_guard_watchpoint_invalidation_outcome(self, &request);
        let retires_guard = matches!(
            &outcome,
            VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted { .. }
        );
        if let VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted {
            dependency_ordinal,
            set_id,
            fired_generation,
            ..
        } = outcome
        {
            let guard_plan_ordinal = self
                .property_load_guard_watchpoint_materializations
                .iter()
                .find(|record| record.ordinal == request.materialization_ordinal)
                .and_then(|record| record.guard_plan_ordinal);
            let generated_artifact_invalidation_owner =
                guard_plan_ordinal.and_then(|guard_plan_ordinal| {
                    self.property_load_guard_plans
                        .iter()
                        .find(|record| record.ordinal == guard_plan_ordinal)
                        .map(|record| record.owner)
                });
            if let Some(materialization) = self
                .property_load_guard_watchpoint_materializations
                .iter_mut()
                .find(|record| record.ordinal == request.materialization_ordinal)
            {
                materialization.lifecycle =
                    VmPropertyLoadGuardWatchpointMaterializationLifecycle::Invalidated {
                        invalidation_ordinal: ordinal,
                        dependency_ordinal,
                        set_id,
                        generation: fired_generation,
                    };
            }
            if let Some(guard_plan_ordinal) = guard_plan_ordinal {
                if let Some(guard_plan) = self
                    .property_load_guard_plans
                    .iter_mut()
                    .find(|record| record.ordinal == guard_plan_ordinal)
                {
                    guard_plan.lifecycle = VmPropertyLoadGuardPlanLifecycle::Retired {
                        invalidation_ordinal: ordinal,
                        dependency_ordinal,
                        set_id,
                        generation: fired_generation,
                    };
                }
            }
            if let Some(owner) = generated_artifact_invalidation_owner {
                self.record_baseline_generated_code_invalidation(
                    BaselineGeneratedCodeInvalidationRequest {
                        owner,
                        artifact_id: None,
                        // C++ JSC resets PropertyInlineCache through the owning CodeBlock,
                        // while on-stack stub code stays valid by handler/code lifetime.
                        // Rust snapshots are generated-code metadata and change with IC
                        // side-table mutation, so dependency retirement invalidates by owner/artifact.
                        bytecode_snapshot: None,
                        reason: CodeInvalidationReason::WatchpointFired,
                        source:
                            BaselineGeneratedCodeInvalidationSource::PropertyLoadGuardWatchpointInvalidation,
                    },
                );
            }
        }

        let record = VmPropertyLoadGuardWatchpointInvalidationRecord {
            ordinal,
            materialization_ordinal: request.materialization_ordinal,
            event: request.event,
            retires_guard,
            outcome,
        };
        // UN-CAPPED (hotfix, redesign-audit Unit 0): 8ad6f87 misclassified this
        // field as diagnostic-only, but property_inline_cache_clear_requests_
        // for_watchpoint_dispatch (below) does an exact-ordinal `.find()` on it
        // from the per-call-frame IC safepoint — a cap means guarded ICs stop
        // being CLEARED once VM-lifetime invalidations exceed the limit (stale
        // Active attachments = wrong-code hazard). Unbounded growth is the
        // known pre-existing divergence; the permanent fix is the watchpoint
        // dependents-list unit (redesign Unit 6), which retires this log.
        self.property_load_guard_watchpoint_invalidations
            .push(record.clone());
        record
    }

    #[allow(dead_code)]
    pub(crate) fn record_property_load_guard_watchpoint_event_dispatch(
        &mut self,
        event: WatchpointFireEvent,
    ) -> VmPropertyLoadGuardWatchpointEventDispatchRecord {
        let ordinal = self.next_record_ordinal();
        let materialization_ordinals = self
            .property_load_guard_watchpoint_materializations
            .iter()
            .filter(|record| {
                record.lifecycle == VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
                    && matches!(
                        record.outcome,
                        VmPropertyLoadGuardWatchpointMaterializationOutcome::Accepted { .. }
                    )
                    && record
                        .bindings
                        .iter()
                        .any(|binding| binding.set_id == event.set)
            })
            .map(|record| record.ordinal)
            .collect::<Vec<_>>();

        let mut invalidation_ordinals = Vec::new();
        let mut rejected = None;
        if materialization_ordinals.is_empty() {
            rejected = Some(
                VmPropertyLoadGuardWatchpointEventDispatchRejectionReason::NoActiveMaterialization {
                    set_id: event.set,
                },
            );
        } else {
            for materialization_ordinal in &materialization_ordinals {
                let invalidation = self.record_property_load_guard_watchpoint_invalidation(
                    VmPropertyLoadGuardWatchpointInvalidationRequest {
                        materialization_ordinal: *materialization_ordinal,
                        event,
                    },
                );
                invalidation_ordinals.push(invalidation.ordinal);
                if let VmPropertyLoadGuardWatchpointInvalidationOutcome::Rejected { reason } =
                    invalidation.outcome
                {
                    rejected = Some(
                        VmPropertyLoadGuardWatchpointEventDispatchRejectionReason::InvalidationRejected {
                            materialization_ordinal: *materialization_ordinal,
                            invalidation_ordinal: invalidation.ordinal,
                            reason,
                        },
                    );
                    break;
                }
            }
        }

        let outcome = match rejected {
            Some(reason) => VmPropertyLoadGuardWatchpointEventDispatchOutcome::Rejected { reason },
            None => VmPropertyLoadGuardWatchpointEventDispatchOutcome::Accepted {
                invalidation_count: invalidation_ordinals.len(),
            },
        };
        let record = VmPropertyLoadGuardWatchpointEventDispatchRecord {
            ordinal,
            event,
            materialization_ordinals,
            invalidation_ordinals,
            outcome,
        };
        // Transitional cap: diagnostic-only (see `HOT_TELEMETRY_RECORD_RETAIN_LIMIT`).
        if self.property_load_guard_watchpoint_event_dispatches.len()
            < HOT_TELEMETRY_RECORD_RETAIN_LIMIT
        {
            self.property_load_guard_watchpoint_event_dispatches
                .push(record.clone());
        }
        record
    }

    pub(crate) fn record_generated_property_load_probe_miss(
        &mut self,
        request: VmGeneratedPropertyLoadProbeMissRequest,
    ) -> VmGeneratedPropertyLoadProbeMissRecord {
        // Batch 2: a terminal miss invalidates matching
        // `property_load_access_case_plans` entries (-> Invalidated). Bump
        // unconditionally at entry; over-bump on a non-terminal miss is sound.
        self.bump_plan_generation();
        let ordinal = self.next_record_ordinal();
        let terminal = generated_property_load_probe_miss_invalidates_plan(request.reason);
        let mut invalidated_plan_ordinals = Vec::new();
        if terminal {
            for record in &mut self.property_load_access_case_plans {
                if !matches!(
                    record.lifecycle,
                    VmPropertyLoadAccessCasePlanLifecycle::Active
                        | VmPropertyLoadAccessCasePlanLifecycle::Attached { .. }
                ) || !vm_property_load_access_case_plan_matches_probe_miss(record, &request)
                {
                    continue;
                }
                record.lifecycle = VmPropertyLoadAccessCasePlanLifecycle::Invalidated {
                    reason: request.reason,
                    miss_ordinal: ordinal,
                };
                invalidated_plan_ordinals.push(record.ordinal);
            }
            if !invalidated_plan_ordinals.is_empty() {
                self.record_baseline_generated_code_invalidation(
                    BaselineGeneratedCodeInvalidationRequest {
                        owner: request.owner,
                        artifact_id: None,
                        // C++ JSC retires the property IC by owner/cache reset and keeps
                        // on-stack stub code alive separately; Rust IC snapshots are mutable
                        // metadata, so dependency misses invalidate the latest owner artifact.
                        bytecode_snapshot: None,
                        reason: CodeInvalidationReason::GeneratedInlineCacheDependencyInvalidated,
                        source: BaselineGeneratedCodeInvalidationSource::PropertyLoadProbeMiss,
                    },
                );
            }
        }

        let record = VmGeneratedPropertyLoadProbeMissRecord {
            ordinal,
            owner: request.owner,
            bytecode_index: request.bytecode_index,
            bytecode_snapshot: request.bytecode_snapshot,
            key: request.key,
            base_structure: request.base_structure,
            offset: request.offset,
            reason: request.reason,
            terminal,
            invalidated_plan_ordinals,
        };
        self.generated_property_load_probe_miss_count = self
            .generated_property_load_probe_miss_count
            .saturating_add(1);
        if self.generated_property_load_probe_misses.len() < HOT_TELEMETRY_RECORD_RETAIN_LIMIT {
            self.generated_property_load_probe_misses
                .push(record.clone());
        }
        record
    }

