#[derive(Clone, Debug, Eq, PartialEq)]
pub(crate) struct VmAttachedPropertyInlineCacheCandidate {
    pub owner: CodeBlockId,
    pub bytecode_index: BytecodeIndex,
    pub bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
    pub slot: InlineCacheSlotId,
    pub kind: VmPropertyInlineCacheAttachmentKind,
    pub attachment_ordinal: u64,
    pub source_plan_ordinal: u64,
    pub store_install_recheck_ordinal: Option<u64>,
    pub store_readiness_ordinal: Option<u64>,
    pub guarded_materialization_ordinal: Option<u64>,
    pub guarded_dependency_ordinals: Vec<u64>,
    pub guarded_binding_set_ids: Vec<WatchpointSetId>,
    pub key: CacheKey,
    pub base_structure: StructureId,
    pub holder_structure: Option<StructureId>,
    pub new_structure: Option<StructureId>,
    pub offset: Option<PropertyOffset>,
    pub dispatch: PropertyInlineCacheDispatch,
    pub stub_mode: PropertyInlineCacheStubMode,
}

impl VmAttachedPropertyInlineCacheCandidate {
    pub(crate) fn from_attachment_record_and_code_block_metadata(
        attachment: &VmPropertyInlineCacheAttachmentRecord,
        metadata: PropertyInlineCacheAttachedMetadata,
    ) -> Option<Self> {
        if attachment.lifecycle != VmPropertyInlineCacheAttachmentLifecycle::Active {
            return None;
        }
        let code_block_outcome = attachment.code_block_outcome?;
        if code_block_outcome.slot != metadata.slot
            || code_block_outcome.bytecode_index != metadata.bytecode_index
            || code_block_outcome.key != metadata.key
            || code_block_outcome.attachment_kind != metadata.attachment_kind
            || code_block_outcome.base_structure != metadata.base_structure
            || code_block_outcome.holder_structure != metadata.holder_structure
            || code_block_outcome.new_structure != metadata.new_structure
            || code_block_outcome.offset != metadata.offset
            || code_block_outcome.dispatch != metadata.dispatch
            || code_block_outcome.stub_mode != metadata.stub_mode
            || code_block_outcome.structure_stub_index.is_some()
            || attachment.requested_stub_mode != metadata.stub_mode
        {
            return None;
        }
        if attachment.kind.bytecode_attachment_kind() != metadata.attachment_kind {
            return None;
        }
        let key = CacheKey::Property(metadata.key);
        if attachment.key != key
            || attachment.bytecode_index != metadata.bytecode_index
            || attachment.slot.0 as usize != metadata.slot
            || attachment.base_structure != metadata.base_structure
            || attachment.holder_structure != metadata.holder_structure
            || attachment.new_structure != metadata.new_structure
            || attachment.offset != metadata.offset.map(|offset| PropertyOffset::new(offset.0))
        {
            return None;
        }

        Some(Self {
            owner: attachment.owner,
            bytecode_index: attachment.bytecode_index,
            bytecode_snapshot: attachment.bytecode_snapshot,
            slot: attachment.slot,
            kind: attachment.kind,
            attachment_ordinal: attachment.ordinal,
            source_plan_ordinal: attachment.source_plan_ordinal,
            store_install_recheck_ordinal: attachment.store_install_recheck_ordinal,
            store_readiness_ordinal: attachment.store_readiness_ordinal,
            guarded_materialization_ordinal: attachment.guarded_materialization_ordinal,
            guarded_dependency_ordinals: attachment.guarded_dependency_ordinals.clone(),
            guarded_binding_set_ids: attachment.guarded_binding_set_ids.clone(),
            key,
            base_structure: attachment.base_structure,
            holder_structure: attachment.holder_structure,
            new_structure: attachment.new_structure,
            offset: attachment.offset,
            dispatch: metadata.dispatch,
            stub_mode: metadata.stub_mode,
        })
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub(crate) struct VmStructureStubPropertyInlineCacheCandidate {
    pub owner: CodeBlockId,
    pub bytecode_index: BytecodeIndex,
    pub bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
    pub slot: InlineCacheSlotId,
    pub kind: VmPropertyInlineCacheAttachmentKind,
    pub attachment_ordinal: u64,
    pub source_plan_ordinal: u64,
    pub key: CacheKey,
    pub base_structure: StructureId,
    pub holder_structure: Option<StructureId>,
    pub new_structure: Option<StructureId>,
    pub offset: Option<PropertyOffset>,
    pub dispatch: PropertyInlineCacheDispatch,
    pub stub_mode: PropertyInlineCacheStubMode,
    pub structure_stub_index: usize,
    pub structure_stub_info: StructureStubInfo,
}

impl VmStructureStubPropertyInlineCacheCandidate {
    pub(crate) fn from_attachment_record_and_structure_stub_info(
        attachment: &VmPropertyInlineCacheAttachmentRecord,
        structure_stub_index: usize,
        structure_stub_info: &StructureStubInfo,
    ) -> Option<Self> {
        if attachment.lifecycle != VmPropertyInlineCacheAttachmentLifecycle::Active
            || attachment.kind != VmPropertyInlineCacheAttachmentKind::OwnDataLoad
            || attachment.requested_stub_mode != PropertyInlineCacheStubMode::StructureStub
            || attachment.holder_structure.is_some()
            || attachment.new_structure.is_some()
            || attachment.offset.is_none()
        {
            return None;
        }

        let CacheKey::Property(key) = attachment.key else {
            return None;
        };
        let code_block_outcome = attachment.code_block_outcome?;
        if code_block_outcome.stub_mode != PropertyInlineCacheStubMode::StructureStub
            || code_block_outcome.structure_stub_index != Some(structure_stub_index)
            || code_block_outcome.attachment_kind
                != PropertyInlineCacheAttachmentKind::GetByNameOwnDataLoad
            || code_block_outcome.slot != attachment.slot.0 as usize
            || code_block_outcome.bytecode_index != attachment.bytecode_index
            || code_block_outcome.key != key
            || code_block_outcome.base_structure != attachment.base_structure
            || code_block_outcome.holder_structure != attachment.holder_structure
            || code_block_outcome.new_structure != attachment.new_structure
            || code_block_outcome.offset
                != attachment
                    .offset
                    .map(|offset| BytecodePropertyOffset(offset.raw()))
        {
            return None;
        }

        let candidate = Self {
            owner: attachment.owner,
            bytecode_index: attachment.bytecode_index,
            bytecode_snapshot: attachment.bytecode_snapshot,
            slot: attachment.slot,
            kind: attachment.kind,
            attachment_ordinal: attachment.ordinal,
            source_plan_ordinal: attachment.source_plan_ordinal,
            key: attachment.key,
            base_structure: attachment.base_structure,
            holder_structure: attachment.holder_structure,
            new_structure: attachment.new_structure,
            offset: attachment.offset,
            dispatch: code_block_outcome.dispatch,
            stub_mode: code_block_outcome.stub_mode,
            structure_stub_index,
            structure_stub_info: structure_stub_info.clone(),
        };
        validate_structure_stub_candidate_shape(&candidate).ok()?;
        Some(candidate)
    }
}

