#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum VmPropertyInlineCacheAttachmentKind {
    OwnDataLoad,
    GuardedPrototypeDataLoad,
    GuardedNegativeLookup,
    StoreReplace,
    StoreTransition,
}

impl VmPropertyInlineCacheAttachmentKind {
    pub(crate) const fn is_store(self) -> bool {
        matches!(self, Self::StoreReplace | Self::StoreTransition)
    }

    pub(crate) const fn is_guarded_load(self) -> bool {
        matches!(
            self,
            Self::GuardedPrototypeDataLoad | Self::GuardedNegativeLookup
        )
    }

    pub(crate) const fn bytecode_attachment_kind(self) -> PropertyInlineCacheAttachmentKind {
        match self {
            Self::OwnDataLoad => PropertyInlineCacheAttachmentKind::GetByNameOwnDataLoad,
            Self::GuardedPrototypeDataLoad => {
                PropertyInlineCacheAttachmentKind::GetByNamePrototypeDataLoad
            }
            Self::GuardedNegativeLookup => {
                PropertyInlineCacheAttachmentKind::GetByNameNegativeLookup
            }
            Self::StoreReplace => PropertyInlineCacheAttachmentKind::PutByNameStoreReplace,
            Self::StoreTransition => PropertyInlineCacheAttachmentKind::PutByNameStoreTransition,
        }
    }

    const fn expected_store_plan_kind(self) -> Option<PropertyStoreAccessCasePlanKind> {
        match self {
            Self::OwnDataLoad | Self::GuardedPrototypeDataLoad | Self::GuardedNegativeLookup => {
                None
            }
            Self::StoreReplace => Some(PropertyStoreAccessCasePlanKind::DataOnlyReplace),
            Self::StoreTransition => Some(PropertyStoreAccessCasePlanKind::DataOnlyTransition),
        }
    }

    const fn expected_store_access_case_kind(self) -> Option<AccessCaseKind> {
        match self {
            Self::OwnDataLoad | Self::GuardedPrototypeDataLoad | Self::GuardedNegativeLookup => {
                None
            }
            Self::StoreReplace => Some(AccessCaseKind::Replace),
            Self::StoreTransition => Some(AccessCaseKind::Transition),
        }
    }

    const fn expected_guarded_candidate_kind(self) -> Option<JitPropertyLoadGuardedCandidateKind> {
        match self {
            Self::GuardedPrototypeDataLoad => {
                Some(JitPropertyLoadGuardedCandidateKind::PrototypeData)
            }
            Self::GuardedNegativeLookup => {
                Some(JitPropertyLoadGuardedCandidateKind::NegativeLookup)
            }
            _ => None,
        }
    }
}

