fn generated_property_has_megamorphic_cache_entry(
    entry: &VmPropertyHasMegamorphicCacheEntry,
) -> GeneratedPropertyHasMegamorphicCacheEntry {
    GeneratedPropertyHasMegamorphicCacheEntry {
        key: entry.key,
        base_structure: entry.base_structure,
        epoch: entry.epoch,
        result: entry.result,
    }
}

