    #[test]
    fn vm_property_inline_cache_evolution_uses_key_for_indexed_store_duplicates() {
        let owner = CodeBlockId(CellId(902));
        let bytecode_index = BytecodeIndex::from_offset(9);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut tiering = VmTieringIntegration::default();
        let mut first = property_store_observation(
            owner,
            InlineCacheSlotId(4),
            bytecode_index,
            PropertyStoreObservationOutcome::IndexedStore,
        );
        first.base_structure_before = Some(StructureId(801));
        first.base_structure_after = Some(StructureId(801));
        let mut second_key = first.clone();
        second_key.key = CacheKey::Property(PropertyKey::from_index(
            PropertyIndex::from_canonical_index(1),
        ));

        record_property_store_descriptor(&mut tiering, owner, bytecode_snapshot, first.clone());
        record_property_store_descriptor(&mut tiering, owner, bytecode_snapshot, first.clone());
        record_property_store_descriptor(&mut tiering, owner, bytecode_snapshot, first);
        record_property_store_descriptor(&mut tiering, owner, bytecode_snapshot, second_key);

        assert_eq!(tiering.property_store_observations().len(), 4);
        assert_eq!(tiering.property_store_access_case_plans().len(), 2);
        let evolution = tiering.property_inline_cache_evolution_records();
        assert_eq!(evolution.len(), 4);
        assert_eq!(
            evolution
                .iter()
                .map(|record| record.decision)
                .collect::<Vec<_>>(),
            vec![
                VmPropertyInlineCacheEvolutionDecision::SkippedInitialCountdown,
                VmPropertyInlineCacheEvolutionDecision::Admitted,
                VmPropertyInlineCacheEvolutionDecision::SkippedBufferedDuplicate,
                VmPropertyInlineCacheEvolutionDecision::Admitted,
            ]
        );
        assert_eq!(evolution[1].structure, Some(StructureId(801)));
        assert_eq!(evolution[1].key, evolution[2].key);
        assert_ne!(evolution[1].key, evolution[3].key);
    }

    #[test]
    fn vm_property_inline_cache_evolution_enters_cooldown_after_repatch_threshold() {
        let owner = CodeBlockId(CellId(903));
        let bytecode_index = BytecodeIndex::from_offset(10);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut tiering = VmTieringIntegration::default();
        let mut descriptor =
            property_handoff_observation(owner, InlineCacheSlotId(5), bytecode_index);
        descriptor.base_structure = Some(StructureId(900));
        descriptor.chain[0].structure = StructureId(900);

        for _ in 0..11 {
            record_property_load_descriptor(
                &mut tiering,
                owner,
                bytecode_snapshot,
                descriptor.clone(),
            );
        }

        assert_eq!(tiering.property_load_observations().len(), 11);
        assert_eq!(tiering.property_load_access_case_plans().len(), 1);
        let evolution = tiering.property_inline_cache_evolution_records();
        assert_eq!(
            evolution[0].decision,
            VmPropertyInlineCacheEvolutionDecision::SkippedInitialCountdown
        );
        assert_eq!(
            evolution[9].decision,
            VmPropertyInlineCacheEvolutionDecision::SkippedReplacedByExistingCase
        );
        assert_eq!(
            evolution[9].counters_after.countdown,
            PROPERTY_IC_INITIAL_COOLDOWN_COUNT
        );
        assert_eq!(
            evolution[10].decision,
            VmPropertyInlineCacheEvolutionDecision::SkippedCooldown
        );
        assert_eq!(
            evolution[10].counters_before.countdown,
            PROPERTY_IC_INITIAL_COOLDOWN_COUNT
        );
        assert_eq!(
            evolution[10].counters_after.countdown,
            PROPERTY_IC_INITIAL_COOLDOWN_COUNT - 1
        );
    }

    fn structure_stub_info_for_plan(
        plan: &VmPropertyLoadAccessCasePlanRecord,
    ) -> StructureStubInfo {
        let CacheKey::Property(key) = plan.plan.key else {
            panic!("test plan uses a property key");
        };
        StructureStubInfo {
            bytecode_index: plan.bytecode_index,
            inline_cache_slot: plan.plan.slot.0 as usize,
            attachment_kind: PropertyInlineCacheAttachmentKind::GetByNameOwnDataLoad,
            key,
            base_structure: plan.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: None,
            offset: plan
                .plan
                .access_case
                .offset
                .map(|offset| BytecodePropertyOffset(offset.raw())),
            requirements: PropertyInlineCacheAttachmentRequirements {
                requires_barrier: false,
                has_barrier_evidence: false,
                requires_watchpoint: false,
                may_call: false,
                may_allocate: false,
            },
            kind: StructureStubKind::GetById,
            cache_state: crate::bytecode::ic::InlineCacheState::Monomorphic,
            code_origin: crate::bytecode::origin::CodeOrigin::new(plan.bytecode_index),
            access_cases: Vec::new(),
            reset_by_gc: false,
        }
    }

    fn structure_stub_attachment_outcome_for_plan(
        plan: &VmPropertyLoadAccessCasePlanRecord,
        structure_stub_index: usize,
    ) -> PropertyInlineCacheAttachmentOutcome {
        let CacheKey::Property(key) = plan.plan.key else {
            panic!("test plan uses a property key");
        };
        PropertyInlineCacheAttachmentOutcome {
            slot: plan.plan.slot.0 as usize,
            bytecode_index: plan.bytecode_index,
            key,
            attachment_kind: PropertyInlineCacheAttachmentKind::GetByNameOwnDataLoad,
            state: crate::bytecode::ic::InlineCacheState::Monomorphic,
            dispatch: PropertyInlineCacheDispatch::Handler,
            base_structure: plan.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: None,
            offset: plan
                .plan
                .access_case
                .offset
                .map(|offset| BytecodePropertyOffset(offset.raw())),
            stub_mode: PropertyInlineCacheStubMode::StructureStub,
            structure_stub_index: Some(structure_stub_index),
        }
    }

    fn structure_stub_transaction_fixture() -> (
        VmTieringIntegration,
        VmPropertyLoadAccessCasePlanRecord,
        VmPropertyInlineCacheAttachmentRecord,
        VmStructureStubPropertyInlineCacheCandidate,
    ) {
        let owner = CodeBlockId(CellId(812));
        let bytecode_index = BytecodeIndex::from_offset(8);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut tiering = VmTieringIntegration::default();
        let descriptor = property_handoff_observation(owner, InlineCacheSlotId(3), bytecode_index);
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            descriptor,
        );
        let plan = tiering
            .property_load_access_case_plans()
            .last()
            .expect("property-load plan")
            .clone();
        let request = VmPropertyInlineCacheAttachmentRequest {
            owner: plan.owner,
            bytecode_index: plan.bytecode_index,
            bytecode_snapshot: plan.bytecode_snapshot,
            slot: plan.plan.slot,
            kind: VmPropertyInlineCacheAttachmentKind::OwnDataLoad,
            source_plan_ordinal: plan.ordinal,
            store_install_recheck_ordinal: None,
            store_readiness_ordinal: None,
            guarded_materialization_ordinal: None,
            guarded_dependency_ordinals: Vec::new(),
            guarded_binding_set_ids: Vec::new(),
            requested_stub_mode: PropertyInlineCacheStubMode::StructureStub,
            key: plan.plan.key,
            base_structure: plan.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: None,
            offset: plan.plan.access_case.offset,
        };
        let structure_stub_index = 5;
        let outcome = structure_stub_attachment_outcome_for_plan(&plan, structure_stub_index);
        let attachment = tiering.record_property_inline_cache_attachment(
            request,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { outcome },
        );
        let structure_stub_info = structure_stub_info_for_plan(&plan);
        let candidate =
            VmStructureStubPropertyInlineCacheCandidate::from_attachment_record_and_structure_stub_info(
                &attachment,
                structure_stub_index,
                &structure_stub_info,
            )
            .expect("structure-stub candidate");

        (tiering, plan, attachment, candidate)
    }

    fn structure_stub_access_case_link_outcome_for_candidate(
        candidate: &VmStructureStubPropertyInlineCacheCandidate,
        access_case_ref: AccessCaseRef,
    ) -> CodeBlockStructureStubAccessCaseLinkOutcome {
        let CacheKey::Property(key) = candidate.key else {
            panic!("test candidate uses a property key");
        };
        CodeBlockStructureStubAccessCaseLinkOutcome {
            structure_stub_index: candidate.structure_stub_index,
            bytecode_index: candidate.bytecode_index,
            slot: candidate.slot.0 as usize,
            key,
            attachment_kind: candidate.kind.bytecode_attachment_kind(),
            base_structure: candidate.base_structure,
            holder_structure: candidate.holder_structure,
            new_structure: candidate.new_structure,
            offset: candidate
                .offset
                .map(|offset| BytecodePropertyOffset(offset.raw())),
            access_case_ref,
            inserted: true,
            access_case_count: 1,
        }
    }

    #[test]
    fn vm_structure_stub_repatch_transaction_records_descriptor_only_metadata() {
        let (mut tiering, plan, attachment, candidate) = structure_stub_transaction_fixture();
        let code_id = JitCodeId(901);

        let record = tiering.record_structure_stub_repatch_transaction(
            VmStructureStubRepatchTransactionRequest {
                candidate: candidate.clone(),
                code_id,
            },
        );

        assert_eq!(
            record.outcome,
            VmStructureStubRepatchTransactionOutcome::Reserved
        );
        assert_eq!(
            record.lifecycle,
            VmStructureStubRepatchTransactionLifecycle::Reserved
        );
        assert_eq!(record.owner, candidate.owner);
        assert_eq!(record.bytecode_snapshot, candidate.bytecode_snapshot);
        assert_eq!(record.bytecode_index, candidate.bytecode_index);
        assert_eq!(record.slot, candidate.slot);
        assert_eq!(record.key, candidate.key);
        assert_eq!(record.base_structure, candidate.base_structure);
        assert_eq!(record.offset, candidate.offset);
        assert_eq!(record.attachment_ordinal, attachment.ordinal);
        assert_eq!(record.source_plan_ordinal, plan.ordinal);
        assert_eq!(record.structure_stub_index, candidate.structure_stub_index);
        assert_eq!(
            tiering.structure_stub_repatch_transactions(),
            std::slice::from_ref(&record)
        );

        let artifact = record.artifact.as_ref().expect("descriptor artifact");
        assert_eq!(artifact.id, code_id);
        assert_eq!(artifact.origin.kind, CodeOriginKind::InlineCacheStub);
        assert_eq!(artifact.origin.owner, Some(candidate.owner));
        assert_eq!(
            artifact.origin.bytecode_index,
            Some(candidate.bytecode_index.offset())
        );
        assert_eq!(artifact.liveness, CodeLiveness::Unallocated);
        assert!(artifact.native_code.is_none());
        assert!(artifact.machine_code.is_none());
        assert_eq!(artifact.entrypoint.kind, EntrypointKind::None);
        assert_eq!(artifact.entrypoint.code, None);
        assert_eq!(artifact.patchpoints.len(), 1);
        assert_eq!(
            artifact.patchpoints[0].kind,
            PatchpointKind::InlineCacheData
        );
        assert_eq!(artifact.patchpoints[0].owner_code, Some(code_id));
        artifact
            .validate()
            .expect("descriptor-only artifact validates");

        let stub = record.stub.as_ref().expect("inline-cache stub descriptor");
        assert_eq!(stub.kind, InlineCacheStubKind::DataOnlyHandler);
        assert_eq!(stub.owner_slot, candidate.slot);
        assert_eq!(stub.code, Some(code_id));
        assert_eq!(stub.cases, vec![plan.plan.access_case.clone()]);
        assert_eq!(stub.weak_structures, vec![candidate.base_structure]);
        assert!(stub.barrier_metadata.is_empty());
        assert!(stub.call_links.is_empty());

        let patch_plan = record.patch_plan.as_ref().expect("reserved patch plan");
        assert_eq!(patch_plan.owner, candidate.owner);
        assert_eq!(
            patch_plan.required_protection,
            ExecutableMemoryProtection::Unallocated
        );
        assert_eq!(patch_plan.records.len(), 1);
        assert_eq!(patch_plan.records[0].code, code_id);
        assert_eq!(patch_plan.records[0].state, CodePatchState::Reserved);
        assert_eq!(
            patch_plan.records[0].relocation,
            RelocationKind::InlineCacheData
        );
        assert!(patch_plan.records[0].range.is_none());
        patch_plan
            .validate()
            .expect("reserved patch plan validates");
    }

