    #[test]
    fn vm_structure_stub_descriptor_projection_ignores_rejected_or_retired_links_and_transactions()
    {
        let (mut tiering, _, _, candidate) = structure_stub_transaction_fixture();
        let transaction = tiering.record_structure_stub_repatch_transaction(
            VmStructureStubRepatchTransactionRequest {
                candidate: candidate.clone(),
                code_id: JitCodeId(908),
            },
        );
        let access_case_ref = structure_stub_repatch_transaction_access_case_ref(&transaction)
            .expect("reserved transaction access case ref");
        let rejected_link = tiering.record_structure_stub_access_case_link(
            VmStructureStubAccessCaseLinkRequest {
                candidate: candidate.clone(),
                transaction_ordinal: transaction.ordinal,
                access_case_ref,
            },
            VmStructureStubAccessCaseLinkOutcome::Rejected {
                reason: VmStructureStubAccessCaseLinkRejectionReason::CodeBlockNotRegistered,
            },
        );
        assert_eq!(
            rejected_link.lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Rejected
        );
        assert!(tiering
            .property_load_access_case_plan_table_for_owner_with_attached_and_structure_stubs(
                candidate.owner,
                candidate.bytecode_snapshot,
                &[],
                std::slice::from_ref(&candidate),
            )
            .expect("rejected link projection table")
            .is_empty());

        tiering.structure_stub_access_case_links.clear();
        let active_link = tiering.record_structure_stub_access_case_link(
            VmStructureStubAccessCaseLinkRequest {
                candidate: candidate.clone(),
                transaction_ordinal: transaction.ordinal,
                access_case_ref,
            },
            VmStructureStubAccessCaseLinkOutcome::Accepted {
                outcome: structure_stub_access_case_link_outcome_for_candidate(
                    &candidate,
                    access_case_ref,
                ),
            },
        );
        assert_eq!(
            active_link.lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Active
        );

        tiering.structure_stub_repatch_transactions[0].lifecycle =
            VmStructureStubRepatchTransactionLifecycle::Retired { clear_ordinal: 10 };
        assert!(tiering
            .property_load_access_case_plan_table_for_owner_with_attached_and_structure_stubs(
                candidate.owner,
                candidate.bytecode_snapshot,
                &[],
                std::slice::from_ref(&candidate),
            )
            .expect("retired transaction projection table")
            .is_empty());

        tiering.structure_stub_repatch_transactions[0].lifecycle =
            VmStructureStubRepatchTransactionLifecycle::Reserved;
        tiering.structure_stub_access_case_links[0].lifecycle =
            VmStructureStubAccessCaseLinkLifecycle::Retired { clear_ordinal: 11 };
        assert!(tiering
            .property_load_access_case_plan_table_for_owner_with_attached_and_structure_stubs(
                candidate.owner,
                candidate.bytecode_snapshot,
                &[],
                std::slice::from_ref(&candidate),
            )
            .expect("retired link projection table")
            .is_empty());
    }

