    #[test]
    fn vm_structure_stub_repatch_transaction_rejects_stale_snapshot_and_plan_metadata() {
        assert_structure_stub_repatch_rejection(
            |_| {},
            |candidate| {
                candidate.bytecode_snapshot = alternate_baseline_bytecode_snapshot(candidate.owner);
            },
            VmStructureStubRepatchTransactionRejectionReason::BytecodeSnapshotMismatch,
        );

        assert_structure_stub_repatch_rejection(
            |_| {},
            |candidate| {
                let key = PropertyKey::from_identifier(Identifier::from_atom(
                    AtomId::from_table_slot(444),
                ));
                candidate.key = CacheKey::Property(key);
                candidate.structure_stub_info.key = key;
            },
            VmStructureStubRepatchTransactionRejectionReason::PlanMetadataMismatch {
                field: VmStructureStubRepatchPlanMetadataMismatchField::Key,
            },
        );

        assert_structure_stub_repatch_rejection(
            |_| {},
            |candidate| {
                candidate.base_structure = StructureId(999);
                candidate.structure_stub_info.base_structure = StructureId(999);
            },
            VmStructureStubRepatchTransactionRejectionReason::PlanMetadataMismatch {
                field: VmStructureStubRepatchPlanMetadataMismatchField::BaseStructure,
            },
        );

        assert_structure_stub_repatch_rejection(
            |_| {},
            |candidate| {
                let offset = PropertyOffset::new(99);
                candidate.offset = Some(offset);
                candidate.structure_stub_info.offset = Some(BytecodePropertyOffset(offset.raw()));
            },
            VmStructureStubRepatchTransactionRejectionReason::PlanMetadataMismatch {
                field: VmStructureStubRepatchPlanMetadataMismatchField::Offset,
            },
        );
    }

