    fn accepted_attached_call_link_candidate(
        attachment: &VmCallLinkInlineCacheAttachmentRecord,
    ) -> CodeBlockRegistryAttachedCallLinkInlineCacheCandidate {
        let target = attachment
            .code_block_outcome
            .as_ref()
            .expect("accepted attachment has bytecode outcome")
            .target
            .clone();
        attached_call_link_candidate_from_attachment(attachment, target)
    }

    fn generated_call_link_candidate_for_attachment(
        tiering: &VmTieringIntegration,
        attachment: &VmCallLinkInlineCacheAttachmentRecord,
    ) -> GeneratedCallLinkCandidate {
        let attached = accepted_attached_call_link_candidate(attachment);
        let table = tiering
            .generated_call_link_candidate_table_for_owner_with_attached(
                attachment.owner,
                attachment.bytecode_snapshot,
                std::slice::from_ref(&attached),
            )
            .expect("active attached call-link candidate table");
        let [candidate] = table.candidates() else {
            panic!("expected exactly one generated call-link candidate")
        };
        candidate.clone()
    }

