    #[test]
    fn vm_call_link_attachment_install_recheck_rejects_missing_plan_and_request_mismatches() {
        let (mut tiering, _, _, _, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();

        let mut missing_plan =
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary);
        missing_plan.attachment_plan_ordinal += 100;
        let missing_plan = tiering.record_call_link_attachment_install_recheck(missing_plan);
        assert_eq!(missing_plan.boundary_validation_ordinal, None);
        assert_call_link_attachment_recheck_rejected(
            missing_plan,
            VmCallLinkAttachmentInstallRecheckRejectionReason::PlanMissing,
        );

        macro_rules! assert_request_rejection {
            ($mutate:expr, $reason:expr) => {{
                let mut request = call_link_attachment_install_recheck_request(
                    &attachment_plan,
                    target,
                    &boundary,
                );
                $mutate(&mut request);
                let recheck = tiering.record_call_link_attachment_install_recheck(request);
                assert_eq!(
                    recheck.boundary_validation_ordinal,
                    Some(attachment_plan.boundary_validation_ordinal)
                );
                assert_call_link_attachment_recheck_rejected(recheck, $reason);
            }};
        }

        assert_request_rejection!(
            |request: &mut VmCallLinkAttachmentInstallRecheckRequest| {
                request.owner = CodeBlockId(CellId(501));
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::OwnerMismatch
        );
        assert_request_rejection!(
            |request: &mut VmCallLinkAttachmentInstallRecheckRequest| {
                request.slot = InlineCacheSlotId(99);
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::SlotMismatch
        );
        assert_request_rejection!(
            |request: &mut VmCallLinkAttachmentInstallRecheckRequest| {
                request.bytecode_index = BytecodeIndex::from_offset(99);
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::BytecodeIndexMismatch
        );
        assert_request_rejection!(
            |request: &mut VmCallLinkAttachmentInstallRecheckRequest| {
                request.bytecode_snapshot = alternate_baseline_bytecode_snapshot(request.owner);
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::BytecodeSnapshotMismatch
        );
    }

    #[test]
    fn vm_call_link_attachment_install_recheck_rejects_fresh_target_or_boundary_evidence() {
        let (mut tiering, _, _, _, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();

        let mut rejected_target =
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary);
        rejected_target.evidence = VmCallLinkAttachmentInstallRecheckEvidence::Rejected(
            VmCallLinkTargetValidationRejection::MissingExecutable,
        );
        let rejected_target = tiering.record_call_link_attachment_install_recheck(rejected_target);
        assert!(rejected_target.accepted_evidence.is_none());
        assert_call_link_attachment_recheck_rejected(
            rejected_target,
            VmCallLinkAttachmentInstallRecheckRejectionReason::TargetRejected {
                reason: VmCallLinkTargetValidationRejection::MissingExecutable,
            },
        );

        let mut mismatched_target =
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary);
        if let VmCallLinkAttachmentInstallRecheckEvidence::Accepted { target, .. } =
            &mut mismatched_target.evidence
        {
            target.target_code_block = CodeBlockId(CellId(999));
        }
        let mismatched_target =
            tiering.record_call_link_attachment_install_recheck(mismatched_target);
        assert_call_link_attachment_recheck_rejected(
            mismatched_target,
            VmCallLinkAttachmentInstallRecheckRejectionReason::TargetMetadataMismatch {
                field: VmCallLinkAttachmentInstallRecheckTargetMismatchField::TargetCodeBlock,
            },
        );

        let mut mismatched_boundary =
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary);
        if let VmCallLinkAttachmentInstallRecheckEvidence::Accepted { boundary, .. } =
            &mut mismatched_boundary.evidence
        {
            boundary.may_throw = false;
        }
        let mismatched_boundary =
            tiering.record_call_link_attachment_install_recheck(mismatched_boundary);
        assert_call_link_attachment_recheck_rejected(
            mismatched_boundary,
            VmCallLinkAttachmentInstallRecheckRejectionReason::BoundaryMetadataMismatch {
                field: VmCallLinkAttachmentInstallRecheckBoundaryMismatchField::MayThrow,
            },
        );
    }

    #[test]
    fn vm_call_link_attachment_install_recheck_rejects_descriptor_readiness_and_observation_drift()
    {
        let assert_drift_rejected =
            |mutate: fn(&mut VmTieringIntegration),
             expected: VmCallLinkAttachmentInstallRecheckRejectionReason| {
                let (mut tiering, _, _, _, _, attachment_plan, target, boundary, _) =
                    record_call_link_attachment_plan_fixture();
                mutate(&mut tiering);
                let recheck = tiering.record_call_link_attachment_install_recheck(
                    call_link_attachment_install_recheck_request(
                        &attachment_plan,
                        target,
                        &boundary,
                    ),
                );
                assert_call_link_attachment_recheck_rejected(recheck, expected);
            };

        assert_drift_rejected(
            |tiering| {
                tiering.call_link_descriptor_records[0].descriptor.boundary =
                    Some(CallBoundaryId(77))
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::MetadataMismatch {
                field: VmCallLinkAttachmentInstallRecheckMetadataMismatchField::DescriptorBoundary,
            },
        );
        assert_drift_rejected(
            |tiering| {
                tiering.call_link_readiness_records[0]
                    .blockers
                    .insert(CallLinkReadinessBlocker::DirectCallDisallowed);
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::MetadataMismatch {
                field: VmCallLinkAttachmentInstallRecheckMetadataMismatchField::ReadinessBlockers,
            },
        );
        assert_drift_rejected(
            |tiering| {
                tiering.call_observations[0].descriptor.target_code_block =
                    Some(CodeBlockId(CellId(990)))
            },
            VmCallLinkAttachmentInstallRecheckRejectionReason::MetadataMismatch {
                field:
                    VmCallLinkAttachmentInstallRecheckMetadataMismatchField::ObservationDescriptor,
            },
        );

        let (mut missing_readiness, _, _, _, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();
        missing_readiness.call_link_readiness_records.clear();
        let recheck = missing_readiness.record_call_link_attachment_install_recheck(
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary),
        );
        assert_call_link_attachment_recheck_rejected(
            recheck,
            VmCallLinkAttachmentInstallRecheckRejectionReason::ReadinessRecordMissing {
                readiness_ordinal: attachment_plan
                    .descriptor_ordinal
                    .and_then(|ordinal| {
                        missing_readiness
                            .call_link_descriptor_records
                            .iter()
                            .find(|record| record.ordinal == ordinal)
                            .map(|record| record.readiness_ordinal)
                    })
                    .expect("descriptor readiness ordinal"),
            },
        );

        let (mut missing_observation, _, _, _, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();
        missing_observation.call_observations.clear();
        let recheck = missing_observation.record_call_link_attachment_install_recheck(
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary),
        );
        assert_call_link_attachment_recheck_rejected(
            recheck,
            VmCallLinkAttachmentInstallRecheckRejectionReason::ObservationRecordMissing {
                observation_ordinal: attachment_plan
                    .descriptor_ordinal
                    .and_then(|ordinal| {
                        missing_observation
                            .call_link_descriptor_records
                            .iter()
                            .find(|record| record.ordinal == ordinal)
                            .map(|record| record.observation_ordinal)
                    })
                    .expect("descriptor observation ordinal"),
            },
        );
    }

