    #[test]
    fn vm_call_link_attachment_install_recheck_rejects_drifted_plan_validation_and_keeps_original_records(
    ) {
        let (mut unsupported, _, _, _, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();
        let VmCallLinkAttachmentPlanOutcome::Planned { plan } =
            &mut unsupported.call_link_attachment_plan_records[0].outcome
        else {
            panic!("expected planned call-link attachment")
        };
        plan.remaining_blockers
            .insert(CallLinkReadinessBlocker::MissingCallSiteMetadata);
        let recheck = unsupported.record_call_link_attachment_install_recheck(
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary),
        );
        assert_call_link_attachment_recheck_rejected(
            recheck,
            VmCallLinkAttachmentInstallRecheckRejectionReason::UnsupportedRemainingBlockers {
                blockers: CallLinkReadinessBlockers::from_blocker(
                    CallLinkReadinessBlocker::MissingCallSiteMetadata,
                ),
            },
        );

        let (mut malformed, _, _, _, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();
        let VmCallLinkAttachmentPlanOutcome::Planned { plan } =
            &mut malformed.call_link_attachment_plan_records[0].outcome
        else {
            panic!("expected planned call-link attachment")
        };
        plan.planned_stub_kind = InlineCacheStubKind::RepatchingStub;
        plan.stub.kind = InlineCacheStubKind::RepatchingStub;
        let recheck = malformed.record_call_link_attachment_install_recheck(
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary),
        );
        assert_call_link_attachment_recheck_rejected(
            recheck,
            VmCallLinkAttachmentInstallRecheckRejectionReason::PlanValidationRejected {
                error: InlineCacheValidationError::CallLinkMismatch,
            },
        );

        let (mut tiering, _, _, descriptor_record, _, attachment_plan, target, boundary, _) =
            record_call_link_attachment_plan_fixture();
        let original_descriptor = tiering.call_link_descriptor_records()[0].clone();
        let original_plan = tiering.call_link_attachment_plan_records()[0].clone();
        let recheck = tiering.record_call_link_attachment_install_recheck(
            call_link_attachment_install_recheck_request(&attachment_plan, target, &boundary),
        );

        assert_eq!(
            recheck.outcome,
            VmCallLinkAttachmentInstallRecheckOutcome::Accepted
        );
        assert_eq!(
            tiering.call_link_descriptor_records()[0],
            original_descriptor
        );
        assert_eq!(
            tiering.call_link_attachment_plan_records()[0],
            original_plan
        );
        assert_eq!(
            descriptor_record.lifecycle,
            VmCallLinkDescriptorLifecycle::MetadataOnly
        );
    }

    #[test]
    fn vm_call_link_readiness_records_root_blocked_opaque_target() {
        let owner = CodeBlockId(CellId(10));
        let frame = CallFrameId(3);
        let bytecode_index = BytecodeIndex::from_offset(1);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut descriptor = call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        descriptor.root_safety = CallObservationRootSafety::Blocked;
        descriptor.target_kind = CallObservationTargetKind::Opaque;
        descriptor.may_call_js = true;
        descriptor.callee_object = None;
        let mut tiering = VmTieringIntegration::default();

        tiering
            .record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor,
            })
            .expect("root-blocked opaque call observation");

        let readiness = &tiering.call_link_readiness_records()[0];
        assert_call_link_readiness_has_blockers(
            readiness,
            &[
                CallLinkReadinessBlocker::DirectCallDisallowed,
                CallLinkReadinessBlocker::RootSafetyBlocked,
                CallLinkReadinessBlocker::UnsupportedTargetKind,
                CallLinkReadinessBlocker::MayCallJsBoundary,
            ],
        );
    }

    #[test]
    fn vm_call_link_readiness_records_unsupported_target_and_outcome_blockers() {
        let owner = CodeBlockId(CellId(10));
        let frame = CallFrameId(3);
        let bytecode_index = BytecodeIndex::from_offset(1);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut tiering = VmTieringIntegration::default();

        let mut native = call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        native.target_kind = CallObservationTargetKind::NativeFunction {
            native: "hostPrint".to_string(),
            intrinsic: None,
        };
        native.outcome = CallObservationOutcome::Threw;
        native.may_call_js = false;
        tiering
            .record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: native,
            })
            .expect("native call observation metadata");

        let mut proxy = call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        proxy.target_kind = CallObservationTargetKind::Proxy;
        proxy.outcome = CallObservationOutcome::Returned;
        proxy.may_call_js = true;
        tiering
            .record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: proxy,
            })
            .expect("proxy call observation metadata");

        let mut non_callable = call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        non_callable.target_kind = CallObservationTargetKind::NonCallableOrError;
        non_callable.outcome = CallObservationOutcome::FailedOrOpaque;
        non_callable.may_call_js = false;
        tiering
            .record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: non_callable,
            })
            .expect("non-callable call observation metadata");

        let records = tiering.call_link_readiness_records();
        assert_eq!(records.len(), 3);
        assert_call_link_readiness_has_blockers(
            &records[0],
            &[
                CallLinkReadinessBlocker::UnsupportedTargetKind,
                CallLinkReadinessBlocker::UnsupportedOutcome,
            ],
        );
        assert!(!records[0]
            .blockers
            .contains(CallLinkReadinessBlocker::MayCallJsBoundary));
        assert_call_link_readiness_has_blockers(
            &records[1],
            &[
                CallLinkReadinessBlocker::UnsupportedTargetKind,
                CallLinkReadinessBlocker::MayCallJsBoundary,
            ],
        );
        assert_call_link_readiness_has_blockers(
            &records[2],
            &[
                CallLinkReadinessBlocker::UnsupportedTargetKind,
                CallLinkReadinessBlocker::UnsupportedOutcome,
            ],
        );
    }

