    #[test]
    fn vm_call_observation_rejects_forged_handoff_metadata() {
        let owner = CodeBlockId(CellId(10));
        let frame = CallFrameId(3);
        let bytecode_index = BytecodeIndex::from_offset(1);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut tiering = VmTieringIntegration::default();

        let wrong_owner = call_observation(
            CodeBlockId(CellId(99)),
            frame,
            bytecode_index,
            CoreOpcode::Call,
        );
        assert_eq!(
            tiering.record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: wrong_owner.clone(),
            }),
            Err(InlineCacheValidationError::CallObservationOwnerMismatch {
                observation: owner,
                handoff: wrong_owner.owner,
            })
        );

        let mut wrong_index = call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        wrong_index.bytecode_index = 7;
        assert_eq!(
            tiering.record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: wrong_index,
            }),
            Err(
                InlineCacheValidationError::CallObservationBytecodeIndexMismatch {
                    observation: bytecode_index.offset(),
                    handoff: 7,
                },
            )
        );

        let wrong_opcode = call_observation(owner, frame, bytecode_index, CoreOpcode::CallWithThis);
        assert_eq!(
            tiering.record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: wrong_opcode,
            }),
            Err(InlineCacheValidationError::CallObservationOpcodeMismatch {
                observation: CoreOpcode::Call,
                handoff: CoreOpcode::CallWithThis,
            })
        );

        let mut direct_ready = call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        direct_ready.direct_call_readiness = CallObservationDirectCallReadiness::Allowed;
        assert_eq!(
            tiering.record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: direct_ready,
            }),
            Err(InlineCacheValidationError::CallObservationDirectCallReadinessClaimed)
        );

        let non_call = call_observation(owner, frame, bytecode_index, CoreOpcode::Return);
        assert_eq!(
            tiering.record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Return,
                bytecode_snapshot,
                descriptor: non_call,
            }),
            Err(
                InlineCacheValidationError::CallObservationUnsupportedOpcode {
                    opcode: CoreOpcode::Return,
                }
            )
        );

        assert!(tiering.call_observations().is_empty());
        assert!(tiering.call_link_readiness_records().is_empty());
    }

