    #[test]
    fn call_observation_descriptor_validation_rejects_malformed_call_metadata() {
        let owner = CodeBlockId(CellId(10));
        let frame = CallFrameId(3);
        let bytecode_index = BytecodeIndex::from_offset(1);

        let mut argument_mismatch =
            call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        argument_mismatch.provided_argument_count = 1;
        argument_mismatch.argument_count_including_this = 1;
        assert!(argument_mismatch.validate().is_err());

        let mut argument_overflow =
            call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        argument_overflow.provided_argument_count = u32::MAX;
        argument_overflow.argument_count_including_this = u32::MAX;
        assert!(argument_overflow.validate().is_err());

        let mut implicit_call_with_this_object =
            call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        implicit_call_with_this_object.this_object = Some(crate::runtime::ObjectId(CellId(62)));
        assert!(implicit_call_with_this_object.validate().is_err());

        let mut call_with_this_without_explicit_register =
            call_observation(owner, frame, bytecode_index, CoreOpcode::CallWithThis);
        call_with_this_without_explicit_register.this_source =
            CallObservationThisSource::ImplicitUndefined;
        assert!(call_with_this_without_explicit_register.validate().is_err());

        let mut missing_rooted_callee =
            call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        missing_rooted_callee.callee_object = None;
        assert!(missing_rooted_callee.validate().is_err());

        let mut missing_rooted_this =
            call_observation(owner, frame, bytecode_index, CoreOpcode::CallWithThis);
        missing_rooted_this.this_object = None;
        assert!(missing_rooted_this.validate().is_err());

        let mut blocked_not_opaque =
            call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        blocked_not_opaque.root_safety = CallObservationRootSafety::Blocked;
        blocked_not_opaque.target_kind =
            CallObservationTargetKind::BytecodeFunction { function_index: 0 };
        blocked_not_opaque.may_call_js = true;
        assert!(blocked_not_opaque.validate().is_err());

        let mut blocked_cannot_call_js =
            call_observation(owner, frame, bytecode_index, CoreOpcode::Call);
        blocked_cannot_call_js.root_safety = CallObservationRootSafety::Blocked;
        blocked_cannot_call_js.target_kind = CallObservationTargetKind::Opaque;
        blocked_cannot_call_js.may_call_js = false;
        assert!(blocked_cannot_call_js.validate().is_err());
    }

