    fn property_load_attachment_request(
        record: &VmPropertyLoadAccessCasePlanRecord,
    ) -> VmPropertyInlineCacheAttachmentRequest {
        VmPropertyInlineCacheAttachmentRequest {
            owner: record.owner,
            bytecode_index: record.bytecode_index,
            bytecode_snapshot: record.bytecode_snapshot,
            slot: record.plan.slot,
            kind: VmPropertyInlineCacheAttachmentKind::OwnDataLoad,
            source_plan_ordinal: record.ordinal,
            store_install_recheck_ordinal: None,
            store_readiness_ordinal: None,
            guarded_materialization_ordinal: None,
            guarded_dependency_ordinals: Vec::new(),
            guarded_binding_set_ids: Vec::new(),
            requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
            key: record.plan.key,
            base_structure: record.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: record.plan.access_case.new_structure,
            offset: record.plan.access_case.offset,
        }
    }

    fn property_store_attachment_request(
        record: &VmPropertyStoreAccessCasePlanRecord,
        install_recheck_ordinal: u64,
        readiness_ordinal: u64,
    ) -> VmPropertyInlineCacheAttachmentRequest {
        VmPropertyInlineCacheAttachmentRequest {
            owner: record.owner,
            bytecode_index: record.bytecode_index,
            bytecode_snapshot: record.bytecode_snapshot,
            slot: record.plan.slot,
            kind: match record.plan.plan_kind {
                PropertyStoreAccessCasePlanKind::DataOnlyReplace => {
                    VmPropertyInlineCacheAttachmentKind::StoreReplace
                }
                PropertyStoreAccessCasePlanKind::DataOnlyTransition => {
                    VmPropertyInlineCacheAttachmentKind::StoreTransition
                }
                PropertyStoreAccessCasePlanKind::DataOnlyIndexedStore => {
                    unreachable!("indexed store plan has no bytecode IC attachment kind")
                }
                PropertyStoreAccessCasePlanKind::Unsupported => unreachable!("test store plan"),
            },
            source_plan_ordinal: record.ordinal,
            store_install_recheck_ordinal: Some(install_recheck_ordinal),
            store_readiness_ordinal: Some(readiness_ordinal),
            guarded_materialization_ordinal: None,
            guarded_dependency_ordinals: Vec::new(),
            guarded_binding_set_ids: Vec::new(),
            requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
            key: record.plan.key,
            base_structure: record.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: record.plan.access_case.new_structure,
            offset: record.plan.access_case.offset,
        }
    }

    fn property_guarded_attachment_request(
        tiering: &VmTieringIntegration,
        guard_plan: &VmPropertyLoadGuardPlanRecord,
        materialization: &VmPropertyLoadGuardWatchpointMaterializationRecord,
    ) -> VmPropertyInlineCacheAttachmentRequest {
        let projection = tiering.project_property_load_guarded_candidates(
            property_load_guarded_candidate_projection_request(guard_plan),
        );
        let record = projection
            .candidates
            .iter()
            .find(|record| record.materialization_ordinal == materialization.ordinal)
            .expect("guarded candidate for materialization");
        let binding_set_ids = materialization
            .bindings
            .iter()
            .map(|binding| binding.set_id)
            .collect::<Vec<_>>();

        match &record.candidate {
            VmPropertyLoadGuardedCandidate::PrototypeData {
                key,
                base_structure,
                holder_structure,
                offset,
                ..
            } => VmPropertyInlineCacheAttachmentRequest {
                owner: guard_plan.owner,
                bytecode_index: guard_plan.bytecode_index,
                bytecode_snapshot: guard_plan.bytecode_snapshot,
                slot: guard_plan.plan.slot,
                kind: VmPropertyInlineCacheAttachmentKind::GuardedPrototypeDataLoad,
                source_plan_ordinal: guard_plan.ordinal,
                store_install_recheck_ordinal: None,
                store_readiness_ordinal: None,
                guarded_materialization_ordinal: Some(materialization.ordinal),
                guarded_dependency_ordinals: materialization.dependency_ordinals.clone(),
                guarded_binding_set_ids: binding_set_ids,
                requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
                key: *key,
                base_structure: *base_structure,
                holder_structure: Some(*holder_structure),
                new_structure: None,
                offset: Some(*offset),
            },
            VmPropertyLoadGuardedCandidate::NegativeLookup {
                key,
                base_structure,
                ..
            } => VmPropertyInlineCacheAttachmentRequest {
                owner: guard_plan.owner,
                bytecode_index: guard_plan.bytecode_index,
                bytecode_snapshot: guard_plan.bytecode_snapshot,
                slot: guard_plan.plan.slot,
                kind: VmPropertyInlineCacheAttachmentKind::GuardedNegativeLookup,
                source_plan_ordinal: guard_plan.ordinal,
                store_install_recheck_ordinal: None,
                store_readiness_ordinal: None,
                guarded_materialization_ordinal: Some(materialization.ordinal),
                guarded_dependency_ordinals: materialization.dependency_ordinals.clone(),
                guarded_binding_set_ids: binding_set_ids,
                requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
                key: *key,
                base_structure: *base_structure,
                holder_structure: None,
                new_structure: None,
                offset: None,
            },
        }
    }

