    fn property_load_guard_watchpoint_materialization_request(
        recheck: &VmPropertyLoadGuardInstallRecheckRecord,
        snapshots: Vec<VmPropertyLoadGuardWatchpointSnapshot>,
    ) -> VmPropertyLoadGuardWatchpointMaterializationRequest {
        VmPropertyLoadGuardWatchpointMaterializationRequest {
            recheck_ordinal: recheck.ordinal,
            snapshots,
        }
    }

    fn property_load_guard_watchpoint_snapshots(
        guard_plan: &VmPropertyLoadGuardPlanRecord,
        state: WatchpointState,
        kind: Option<WatchpointKind>,
        first_generation: u64,
    ) -> Vec<VmPropertyLoadGuardWatchpointSnapshot> {
        guard_plan
            .plan
            .descriptor
            .chain
            .entries
            .iter()
            .enumerate()
            .map(|(index, entry)| VmPropertyLoadGuardWatchpointSnapshot {
                structure: entry.structure,
                state,
                generation: WatchpointGeneration(first_generation + index as u64),
                kind,
            })
            .collect()
    }

