    #[test]
    fn vm_property_guard_watchpoint_materialization_accepts_prototype_data_guard_with_clear_snapshots(
    ) {
        let (mut tiering, guard_plan, bytecode_snapshot) = record_prototype_data_guard_fixture();
        let recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        let dependencies = dependency_records_for_guard(&tiering, guard_plan.ordinal);
        let snapshots =
            property_load_guard_watchpoint_snapshots(&guard_plan, WatchpointState::Clear, None, 10);

        let materialization = tiering.record_property_load_guard_watchpoint_materialization(
            property_load_guard_watchpoint_materialization_request(&recheck, snapshots.clone()),
        );

        assert_eq!(materialization.guard_plan_ordinal, Some(guard_plan.ordinal));
        assert_eq!(
            materialization.dependency_ordinals,
            recheck.dependency_ordinals
        );
        assert_eq!(materialization.snapshots, snapshots);
        assert_eq!(
            materialization.outcome,
            VmPropertyLoadGuardWatchpointMaterializationOutcome::Accepted { binding_count: 2 }
        );
        assert_eq!(materialization.bindings.len(), dependencies.len());
        for (index, (binding, dependency)) in materialization
            .bindings
            .iter()
            .zip(dependencies.iter())
            .enumerate()
        {
            assert_eq!(binding.dependency_ordinal, dependency.ordinal);
            assert_eq!(binding.dependency_id, dependency.dependency.id);
            assert_eq!(binding.set_id, dependency.set.id);
            assert_eq!(
                binding.structure,
                guard_plan.plan.descriptor.chain.entries[index].structure
            );
            assert_eq!(
                binding.sampled_generation,
                WatchpointGeneration(10 + index as u64)
            );
            assert_eq!(binding.sampled_state, WatchpointState::Clear);
            assert_eq!(binding.sampled_kind, None);
            assert_eq!(
                binding.action,
                VmPropertyLoadGuardWatchpointMaterializationAction::WouldStartWatching
            );
        }
        assert_eq!(
            tiering.property_load_guard_watchpoint_materializations(),
            std::slice::from_ref(&materialization)
        );
        assert!(tiering.property_load_access_case_plans().is_empty());
        assert!(tiering
            .property_load_access_case_plan_table_for_owner(guard_plan.owner, bytecode_snapshot)
            .expect("prototype data guard access-case table")
            .is_empty());
    }

