    #[test]
    fn vm_property_guarded_candidate_projection_rejects_rejected_invalidated_materialization_and_retired_guard_plan(
    ) {
        let owner = CodeBlockId(CellId(12));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_index = BytecodeIndex::from_offset(1);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let recheck = tiering.record_property_load_guard_install_recheck(
            VmPropertyLoadGuardInstallRecheckRequest {
                owner,
                slot: InlineCacheSlotId(0),
                bytecode_index,
                bytecode_snapshot,
                guard_plan_ordinal: 999,
            },
        );
        let rejected_materialization = tiering
            .record_property_load_guard_watchpoint_materialization(
                property_load_guard_watchpoint_materialization_request(&recheck, Vec::new()),
            );
        assert_eq!(
            rejected_materialization.lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
        );
        let projection = tiering.project_property_load_guarded_candidates(
            VmPropertyLoadGuardedCandidateProjectionRequest {
                owner,
                bytecode_snapshot,
                bytecode_index: Some(bytecode_index),
            },
        );
        assert!(projection.candidates.is_empty());
        assert_eq!(projection.rejections.len(), 1);
        let rejected = &projection.rejections[0];
        assert_eq!(
            rejected.materialization_ordinal,
            rejected_materialization.ordinal
        );
        assert_guarded_candidate_rejected(
            rejected,
            VmPropertyLoadGuardedCandidateRejectionReason::MaterializationNotAccepted {
                outcome: rejected_materialization.outcome,
            },
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            100,
        );
        let binding = materialization.bindings[0].clone();
        let event = watchpoint_fire_event_for_binding(
            &binding,
            WatchpointGeneration(binding.sampled_generation.0 + 1),
        );
        let invalidation = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event,
            },
        );
        let invalidated_lifecycle =
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Invalidated {
                invalidation_ordinal: invalidation.ordinal,
                dependency_ordinal: binding.dependency_ordinal,
                set_id: binding.set_id,
                generation: event.generation,
            };
        let projection = tiering.project_property_load_guarded_candidates(
            property_load_guarded_candidate_projection_request(&guard_plan),
        );
        assert!(projection.candidates.is_empty());
        assert_eq!(projection.rejections.len(), 1);
        assert_guarded_candidate_rejected(
            &projection.rejections[0],
            VmPropertyLoadGuardedCandidateRejectionReason::MaterializationInvalidated {
                lifecycle: invalidated_lifecycle,
            },
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            110,
        );
        let retired = VmPropertyLoadGuardPlanLifecycle::Retired {
            invalidation_ordinal: 777,
            dependency_ordinal: materialization.dependency_ordinals[0],
            set_id: materialization.bindings[0].set_id,
            generation: WatchpointGeneration(111),
        };
        tiering.property_load_guard_plans[0].lifecycle = retired;
        let projection = tiering.project_property_load_guarded_candidates(
            property_load_guarded_candidate_projection_request(&guard_plan),
        );
        assert!(projection.candidates.is_empty());
        assert_eq!(projection.rejections.len(), 1);
        assert_guarded_candidate_rejected(
            &projection.rejections[0],
            VmPropertyLoadGuardedCandidateRejectionReason::GuardPlanRetired { lifecycle: retired },
        );
    }

