    #[test]
    fn vm_property_guarded_candidate_table_builder_returns_cloned_plans_and_provenance() {
        let (mut tiering, prototype_guard, bytecode_snapshot) =
            record_prototype_data_guard_fixture();
        let prototype_materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &prototype_guard,
            WatchpointState::Clear,
            None,
            160,
        );
        let negative_guard = record_negative_lookup_guard_for_owner(
            &mut tiering,
            prototype_guard.owner,
            bytecode_snapshot,
            BytecodeIndex::from_offset(22),
            InlineCacheSlotId(22),
        );
        let negative_materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &negative_guard,
            WatchpointState::Watching,
            Some(WatchpointKind::StructureTransition),
            170,
        );

        let table = tiering
            .property_load_guarded_candidate_table_for_owner(
                prototype_guard.owner,
                bytecode_snapshot,
            )
            .expect("guarded candidate table");

        assert_eq!(table.owner(), prototype_guard.owner);
        assert_eq!(table.len(), 2);
        let prototype_candidate = table
            .candidates()
            .iter()
            .find(|candidate| candidate.guard_plan_ordinal == prototype_guard.ordinal)
            .expect("prototype candidate");
        assert_eq!(
            prototype_candidate.candidate_kind,
            JitPropertyLoadGuardedCandidateKind::PrototypeData
        );
        assert_eq!(prototype_candidate.plan, prototype_guard.plan);
        assert_eq!(
            prototype_candidate.materialization_ordinal,
            prototype_materialization.ordinal
        );
        assert_eq!(
            prototype_candidate.dependency_ordinals,
            prototype_materialization.dependency_ordinals
        );
        assert_eq!(
            prototype_candidate.binding_set_ids,
            prototype_materialization
                .bindings
                .iter()
                .map(|binding| binding.set_id)
                .collect::<Vec<_>>()
        );

        let negative_candidate = table
            .candidates()
            .iter()
            .find(|candidate| candidate.guard_plan_ordinal == negative_guard.ordinal)
            .expect("negative lookup candidate");
        assert_eq!(
            negative_candidate.candidate_kind,
            JitPropertyLoadGuardedCandidateKind::NegativeLookup
        );
        assert_eq!(negative_candidate.plan, negative_guard.plan);
        assert_eq!(
            negative_candidate.materialization_ordinal,
            negative_materialization.ordinal
        );
        assert_eq!(
            negative_candidate.dependency_ordinals,
            negative_materialization.dependency_ordinals
        );

        tiering.property_load_guard_plans[0].plan.bytecode_index = 999;
        assert_eq!(
            prototype_candidate.plan.bytecode_index,
            prototype_guard.plan.bytecode_index
        );
    }

