    #[test]
    fn vm_generated_guarded_property_load_terminal_probe_miss_suppresses_all_active_materializations(
    ) {
        let (mut tiering, guard_plan, bytecode_snapshot) = record_prototype_data_guard_fixture();
        let first = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            173,
        );
        let second = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Watching,
            Some(WatchpointKind::StructureTransition),
            183,
        );
        let table = tiering
            .property_load_guarded_candidate_table_for_owner(guard_plan.owner, bytecode_snapshot)
            .expect("deduped guarded candidate table before terminal miss");
        let request = generated_guarded_property_load_probe_miss_request(
            &guard_plan,
            &table.candidates()[0],
            GeneratedGuardedPropertyLoadProbeMissReason::GuardStructureMismatch,
            Some(0),
        );

        let miss = tiering.record_generated_guarded_property_load_probe_miss(request);
        let retired = VmPropertyLoadGuardPlanLifecycle::RetiredByTerminalGuardedMiss {
            miss_ordinal: miss.ordinal,
            materialization_ordinal: first.ordinal,
            reason: GeneratedGuardedPropertyLoadProbeMissReason::GuardStructureMismatch,
            candidate_kind: JitPropertyLoadGuardedCandidateKind::PrototypeData,
            chain_index: Some(0),
        };
        let projection = tiering.project_property_load_guarded_candidates(
            property_load_guarded_candidate_projection_request(&guard_plan),
        );
        let table_after = tiering
            .property_load_guarded_candidate_table_for_owner(guard_plan.owner, bytecode_snapshot)
            .expect("guarded candidate table after terminal miss");

        assert_eq!(table.len(), 1);
        assert_eq!(table.candidates()[0].materialization_ordinal, first.ordinal);
        assert_eq!(miss.retired_guard_plan_ordinal, Some(guard_plan.ordinal));
        assert!(projection.candidates.is_empty());
        assert_eq!(projection.rejections.len(), 2);
        assert_eq!(
            projection
                .rejections
                .iter()
                .map(|record| record.materialization_ordinal)
                .collect::<Vec<_>>(),
            vec![first.ordinal, second.ordinal]
        );
        for rejection in &projection.rejections {
            assert_guarded_candidate_rejected(
                rejection,
                VmPropertyLoadGuardedCandidateRejectionReason::GuardPlanRetired {
                    lifecycle: retired,
                },
            );
        }
        assert!(table_after.is_empty());
        assert_eq!(
            tiering.property_load_guard_watchpoint_materializations()[0].lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
        );
        assert_eq!(
            tiering.property_load_guard_watchpoint_materializations()[1].lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
        );
    }

