    #[test]
    fn generated_guarded_property_load_terminal_probe_miss_retires_plan_without_generated_artifact_invalidation(
    ) {
        let (mut tiering, guard_plan, bytecode_snapshot) = record_prototype_data_guard_fixture();
        let owner = guard_plan.owner;
        let generated_artifact = tiering
            .record_baseline_generated_code_artifact(
                owner,
                baseline_generated_code_artifact(owner, 242),
            )
            .unwrap();
        accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            242,
        );
        let table = tiering
            .property_load_guarded_candidate_table_for_owner(owner, bytecode_snapshot)
            .expect("guarded candidate table");
        let candidate = table.candidates()[0].clone();

        let non_terminal_request = generated_guarded_property_load_probe_miss_request(
            &guard_plan,
            &candidate,
            GeneratedGuardedPropertyLoadProbeMissReason::UnknownGuardObject,
            None,
        );
        let non_terminal =
            tiering.record_generated_guarded_property_load_probe_miss(non_terminal_request);
        assert!(!non_terminal.terminal);
        assert!(tiering.baseline_generated_code_invalidations().is_empty());
        assert_eq!(
            tiering.baseline_generated_code_artifact_for(owner),
            Some(generated_artifact.clone())
        );

        let terminal_request = generated_guarded_property_load_probe_miss_request(
            &guard_plan,
            &candidate,
            GeneratedGuardedPropertyLoadProbeMissReason::GuardStructureMismatch,
            Some(0),
        );
        let terminal = tiering.record_generated_guarded_property_load_probe_miss(terminal_request);
        let entry = observe_baseline_entry(&mut tiering, owner, 242);

        assert!(terminal.terminal);
        assert_eq!(
            terminal.retired_guard_plan_ordinal,
            Some(guard_plan.ordinal)
        );
        assert!(tiering.baseline_generated_code_invalidations().is_empty());
        assert_eq!(
            tiering.baseline_generated_code_artifact_for(owner),
            Some(generated_artifact.clone())
        );
        assert_eq!(
            entry.baseline_entry_gate.as_ref().map(|gate| gate.outcome),
            Some(BaselineEntryGateOutcome::Eligible)
        );
        assert_eq!(
            entry
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.generated_artifact.as_ref())
                .map(|artifact| artifact.id),
            Some(generated_artifact.id)
        );
        assert_eq!(
            entry.decision,
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            entry.execution_path,
            TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
        );
    }

