    #[test]
    fn vm_property_guard_watchpoint_invalidation_invalidates_accepted_prototype_data_materialization(
    ) {
        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            10,
        );
        let binding = materialization.bindings[1].clone();
        let event = watchpoint_fire_event_for_binding(
            &binding,
            WatchpointGeneration(binding.sampled_generation.0 + 1),
        );

        let invalidation = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event,
            },
        );

        assert_eq!(
            invalidation.materialization_ordinal,
            materialization.ordinal
        );
        assert_eq!(invalidation.event, event);
        assert!(invalidation.retires_guard);
        assert_eq!(
            invalidation.outcome,
            VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted {
                dependency_ordinal: binding.dependency_ordinal,
                dependency_id: binding.dependency_id,
                set_id: binding.set_id,
                structure: binding.structure,
                sampled_generation: binding.sampled_generation,
                fired_generation: event.generation,
            }
        );
        assert_eq!(
            tiering.property_load_guard_watchpoint_materializations()[0].lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Invalidated {
                invalidation_ordinal: invalidation.ordinal,
                dependency_ordinal: binding.dependency_ordinal,
                set_id: binding.set_id,
                generation: event.generation,
            }
        );
        assert_eq!(
            tiering.property_load_guard_plans()[0].lifecycle,
            VmPropertyLoadGuardPlanLifecycle::Retired {
                invalidation_ordinal: invalidation.ordinal,
                dependency_ordinal: binding.dependency_ordinal,
                set_id: binding.set_id,
                generation: event.generation,
            }
        );
        for dependency in tiering.property_load_guard_dependencies() {
            assert_eq!(dependency.dependency.generation, None);
        }
        assert_eq!(
            tiering.property_load_guard_watchpoint_invalidations(),
            std::slice::from_ref(&invalidation)
        );
    }

