    #[test]
    fn property_load_guard_watchpoint_event_dispatch_records_no_active_materialization() {
        let mut tiering = VmTieringIntegration::default();
        let event = WatchpointFireEvent {
            set: WatchpointSetId(404),
            target: WatchpointTarget::StructureTransition {
                structure: StructureId(44),
            },
            generation: WatchpointGeneration(1),
        };

        let dispatch = tiering.record_property_load_guard_watchpoint_event_dispatch(event);

        assert_eq!(dispatch.event, event);
        assert!(dispatch.materialization_ordinals.is_empty());
        assert!(dispatch.invalidation_ordinals.is_empty());
        assert_eq!(
            dispatch.outcome,
            VmPropertyLoadGuardWatchpointEventDispatchOutcome::Rejected {
                reason:
                    VmPropertyLoadGuardWatchpointEventDispatchRejectionReason::NoActiveMaterialization {
                        set_id: event.set,
                    },
            }
        );
        assert_eq!(
            tiering.property_load_guard_watchpoint_event_dispatches(),
            std::slice::from_ref(&dispatch)
        );
        assert!(tiering
            .property_load_guard_watchpoint_invalidations()
            .is_empty());
    }

