    #[test]
    fn vm_property_guard_watchpoint_invalidation_retires_guard_plan_and_blocks_reuse() {
        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            25,
        );
        let binding = materialization.bindings[0].clone();
        let event = watchpoint_fire_event_for_binding(
            &binding,
            WatchpointGeneration(binding.sampled_generation.0 + 1),
        );

        let invalidation = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event,
            },
        );
        let retired = VmPropertyLoadGuardPlanLifecycle::Retired {
            invalidation_ordinal: invalidation.ordinal,
            dependency_ordinal: binding.dependency_ordinal,
            set_id: binding.set_id,
            generation: event.generation,
        };

        assert_eq!(tiering.property_load_guard_plans()[0].lifecycle, retired);

        let post_retirement_recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        assert_recheck_rejected(
            post_retirement_recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::GuardPlanRetired {
                lifecycle: retired,
            },
        );

        let accepted_recheck = tiering
            .property_load_guard_install_rechecks()
            .iter()
            .find(|record| record.ordinal == materialization.recheck_ordinal)
            .expect("accepted recheck")
            .clone();
        let snapshots =
            property_load_guard_watchpoint_snapshots(&guard_plan, WatchpointState::Clear, None, 30);
        let post_retirement_materialization = tiering
            .record_property_load_guard_watchpoint_materialization(
                property_load_guard_watchpoint_materialization_request(
                    &accepted_recheck,
                    snapshots,
                ),
            );
        assert_watchpoint_materialization_rejected(
            &post_retirement_materialization,
            VmPropertyLoadGuardWatchpointMaterializationRejectionReason::RecheckNoLongerAccepted {
                reason: VmPropertyLoadGuardInstallRecheckRejectionReason::GuardPlanRetired {
                    lifecycle: retired,
                },
            },
        );
    }

    #[test]
    fn vm_property_guard_watchpoint_invalidation_rejects_missing_rejected_and_already_invalidated_materializations(
    ) {
        let mut tiering = VmTieringIntegration::default();
        let missing = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: 999,
                event: dummy_watchpoint_fire_event(),
            },
        );
        assert_watchpoint_invalidation_rejected(
            &missing,
            VmPropertyLoadGuardWatchpointInvalidationRejectionReason::MaterializationMissing,
        );

        let owner = CodeBlockId(CellId(12));
        let mut tiering = VmTieringIntegration::default();
        let recheck = tiering.record_property_load_guard_install_recheck(
            VmPropertyLoadGuardInstallRecheckRequest {
                owner,
                slot: InlineCacheSlotId(0),
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot: baseline_bytecode_snapshot(owner),
                guard_plan_ordinal: 999,
            },
        );
        let materialization = tiering.record_property_load_guard_watchpoint_materialization(
            property_load_guard_watchpoint_materialization_request(&recheck, Vec::new()),
        );
        let rejected = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event: dummy_watchpoint_fire_event(),
            },
        );
        assert_watchpoint_invalidation_rejected(
            &rejected,
            VmPropertyLoadGuardWatchpointInvalidationRejectionReason::MaterializationNotAccepted {
                outcome: materialization.outcome,
            },
        );
        assert_eq!(
            tiering.property_load_guard_watchpoint_materializations()[0].lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            30,
        );
        let binding = materialization.bindings[0].clone();
        let first_event = watchpoint_fire_event_for_binding(
            &binding,
            WatchpointGeneration(binding.sampled_generation.0 + 1),
        );
        let first = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event: first_event,
            },
        );
        let lifecycle = VmPropertyLoadGuardWatchpointMaterializationLifecycle::Invalidated {
            invalidation_ordinal: first.ordinal,
            dependency_ordinal: binding.dependency_ordinal,
            set_id: binding.set_id,
            generation: first_event.generation,
        };
        assert_eq!(
            tiering.property_load_guard_watchpoint_materializations()[0].lifecycle,
            lifecycle
        );

        let second_event = watchpoint_fire_event_for_binding(
            &binding,
            WatchpointGeneration(binding.sampled_generation.0 + 2),
        );
        let already_invalidated = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event: second_event,
            },
        );
        assert_watchpoint_invalidation_rejected(
            &already_invalidated,
            VmPropertyLoadGuardWatchpointInvalidationRejectionReason::MaterializationAlreadyInvalidated {
                lifecycle,
            },
        );
    }

