    #[test]
    fn vm_property_guard_watchpoint_invalidation_keeps_own_data_projection_dependency_free_and_artifacts_untouched(
    ) {
        let (mut tiering, guard_plan, bytecode_snapshot) = record_prototype_data_guard_fixture();
        let owner = guard_plan.owner;
        let own_data_bytecode_index = BytecodeIndex::from_offset(5);
        let own_data =
            property_handoff_observation(owner, InlineCacheSlotId(5), own_data_bytecode_index);
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            own_data.clone(),
        );
        let materialization = accepted_watchpoint_materialization(
            &mut tiering,
            &guard_plan,
            WatchpointState::Clear,
            None,
            70,
        );
        let binding = materialization.bindings[0].clone();
        let event = watchpoint_fire_event_for_binding(
            &binding,
            WatchpointGeneration(binding.sampled_generation.0 + 1),
        );

        let invalidation = tiering.record_property_load_guard_watchpoint_invalidation(
            VmPropertyLoadGuardWatchpointInvalidationRequest {
                materialization_ordinal: materialization.ordinal,
                event,
            },
        );

        assert!(matches!(
            invalidation.outcome,
            VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted { .. }
        ));
        assert!(invalidation.retires_guard);
        let table = tiering
            .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("mixed guard invalidation access-case table");
        assert_eq!(table.len(), 1);
        assert_eq!(table.plans()[0].bytecode_index, own_data.bytecode_index);
        assert!(table.plans()[0].access_case.dependencies.is_empty());
        assert!(tiering.property_load_access_case_plans()[0]
            .plan
            .access_case
            .dependencies
            .is_empty());
        assert!(tiering.baseline_entry_artifacts().is_empty());
        assert!(tiering.baseline_generated_code_artifacts().is_empty());
        assert!(tiering.baseline_install_records().is_empty());
        assert!(tiering.generated_property_load_probe_misses().is_empty());
    }

    #[test]
    fn vm_property_guard_install_recheck_rejects_missing_guard_plan() {
        let owner = CodeBlockId(CellId(12));
        let mut tiering = VmTieringIntegration::default();

        let recheck = tiering.record_property_load_guard_install_recheck(
            VmPropertyLoadGuardInstallRecheckRequest {
                owner,
                slot: InlineCacheSlotId(0),
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot: baseline_bytecode_snapshot(owner),
                guard_plan_ordinal: 999,
            },
        );

        assert!(recheck.dependency_ordinals.is_empty());
        assert_recheck_rejected(
            recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::GuardPlanMissing,
        );
    }

    #[test]
    fn vm_property_guard_install_recheck_rejects_request_metadata_mismatches() {
        fn assert_request_rejection(
            mutate: impl FnOnce(&mut VmPropertyLoadGuardInstallRecheckRequest),
            reason: VmPropertyLoadGuardInstallRecheckRejectionReason,
        ) {
            let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
            let mut request = property_load_guard_install_recheck_request(&guard_plan);
            mutate(&mut request);

            let recheck = tiering.record_property_load_guard_install_recheck(request);

            assert!(recheck.dependency_ordinals.is_empty());
            assert_recheck_rejected(recheck, reason);
        }

        assert_request_rejection(
            |request| request.owner = CodeBlockId(CellId(99)),
            VmPropertyLoadGuardInstallRecheckRejectionReason::OwnerMismatch,
        );
        assert_request_rejection(
            |request| request.slot = InlineCacheSlotId(99),
            VmPropertyLoadGuardInstallRecheckRejectionReason::SlotMismatch,
        );
        assert_request_rejection(
            |request| request.bytecode_index = BytecodeIndex::from_offset(99),
            VmPropertyLoadGuardInstallRecheckRejectionReason::BytecodeIndexMismatch,
        );
        assert_request_rejection(
            |request| {
                request.bytecode_snapshot = alternate_baseline_bytecode_snapshot(request.owner);
            },
            VmPropertyLoadGuardInstallRecheckRejectionReason::BytecodeSnapshotMismatch,
        );
    }

    #[test]
    fn vm_property_guard_install_recheck_rejects_malformed_dependency_chain_indexes() {
        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        tiering.property_load_guard_dependencies.pop();
        let recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        assert_recheck_rejected(
            recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::MissingDependency { chain_index: 1 },
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let extra_dependency = tiering.property_load_guard_dependencies[0].clone();
        tiering
            .property_load_guard_dependencies
            .push(extra_dependency);
        let recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        assert_recheck_rejected(
            recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::DependencyCountMismatch {
                expected: 2,
                actual: 3,
            },
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        guard_dependency_mut(&mut tiering, guard_plan.ordinal, 1).chain_index = 0;
        let recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        assert_recheck_rejected(
            recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::DuplicateChainIndex {
                chain_index: 0,
            },
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        guard_dependency_mut(&mut tiering, guard_plan.ordinal, 1).chain_index = 2;
        let recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        assert_recheck_rejected(
            recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::OutOfRangeChainIndex {
                chain_index: 2,
                expected_len: 2,
            },
        );

        let (mut tiering, guard_plan, _) = record_prototype_data_guard_fixture();
        let first = tiering
            .property_load_guard_dependencies
            .iter()
            .position(|record| {
                record.guard_plan_ordinal == guard_plan.ordinal && record.chain_index == 0
            })
            .expect("first dependency");
        let second = tiering
            .property_load_guard_dependencies
            .iter()
            .position(|record| {
                record.guard_plan_ordinal == guard_plan.ordinal && record.chain_index == 1
            })
            .expect("second dependency");
        tiering.property_load_guard_dependencies.swap(first, second);
        let recheck = tiering.record_property_load_guard_install_recheck(
            property_load_guard_install_recheck_request(&guard_plan),
        );
        assert_recheck_rejected(
            recheck,
            VmPropertyLoadGuardInstallRecheckRejectionReason::WrongChainIndex {
                expected: 0,
                actual: 1,
            },
        );
    }

