    #[test]
    fn vm_property_handoff_observation_records_are_ordered_vm_owned_data() {
        let owner = CodeBlockId(CellId(10));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let first_descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(1),
        );
        let second_descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(1),
            BytecodeIndex::from_offset(2),
        );

        let first_warmup = tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot,
                descriptor: first_descriptor.clone(),
            })
            .expect("first property handoff warmup observation");
        let first = tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot,
                descriptor: first_descriptor.clone(),
            })
            .expect("first property handoff observation");
        let second_warmup = tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(2)),
                bytecode_index: BytecodeIndex::from_offset(2),
                bytecode_snapshot,
                descriptor: second_descriptor.clone(),
            })
            .expect("second property handoff warmup observation");
        let second = tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(2)),
                bytecode_index: BytecodeIndex::from_offset(2),
                bytecode_snapshot,
                descriptor: second_descriptor.clone(),
            })
            .expect("second property handoff observation");

        assert!(first.ordinal < second.ordinal);
        assert_eq!(
            tiering.property_load_observations(),
            &[
                first_warmup.clone(),
                first.clone(),
                second_warmup.clone(),
                second.clone()
            ]
        );
        assert_eq!(
            tiering.property_load_observations()[0].descriptor,
            first_descriptor
        );
        assert_eq!(
            tiering.property_load_observations()[2].descriptor,
            second_descriptor
        );

        let plans = tiering.property_load_access_case_plans();
        assert_eq!(plans.len(), 2);
        assert!(plans[0].ordinal < plans[1].ordinal);
        assert_eq!(plans[0].observation_ordinal, first.ordinal);
        assert_eq!(plans[1].observation_ordinal, second.ordinal);
        assert_eq!(plans[0].owner, owner);
        assert_eq!(plans[0].bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(plans[0].bytecode_snapshot, bytecode_snapshot);
        assert_eq!(
            plans[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Active
        );
        assert_eq!(plans[0].plan.owner, owner);
        assert_eq!(plans[0].plan.slot, InlineCacheSlotId(0));
        assert_eq!(plans[0].plan.access_case.kind, AccessCaseKind::Load);
        assert_eq!(plans[0].plan.access_case.key, first_descriptor.key);
        assert_eq!(
            plans[0].plan.access_case.base_structure,
            first_descriptor.base_structure
        );
        assert_eq!(plans[0].plan.access_case.offset, first_descriptor.offset);
        assert!(plans[0].plan.access_case.holder.is_none());
        assert!(plans[0].plan.access_case.dependencies.is_empty());
    }

    #[test]
    fn vm_property_handoff_blocks_prototype_observation_without_case_plan() {
        let owner = CodeBlockId(CellId(10));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(1),
        );
        descriptor.prototype_depth = 1;
        descriptor.holder_object = Some(crate::runtime::ObjectId(CellId(99)));
        descriptor.chain = vec![
            PropertyLoadObservationChainEntry {
                object: descriptor.base_object.unwrap(),
                structure: descriptor.base_structure.unwrap(),
                next_prototype: descriptor.holder_object,
            },
            PropertyLoadObservationChainEntry {
                object: descriptor.holder_object.unwrap(),
                structure: StructureId(8),
                next_prototype: None,
            },
        ];
        descriptor.readiness = descriptor.classify_readiness();

        let record = tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot,
                descriptor: descriptor.clone(),
            })
            .expect("prototype property handoff observation");

        assert_eq!(
            tiering.property_load_observations(),
            std::slice::from_ref(&record)
        );
        assert_eq!(
            tiering.property_load_observations()[0].descriptor,
            descriptor
        );
        assert!(tiering.property_load_access_case_plans().is_empty());
        let guard_plans = tiering.property_load_guard_plans();
        assert_eq!(guard_plans.len(), 1);
        assert!(record.ordinal < guard_plans[0].ordinal);
        assert_eq!(guard_plans[0].observation_ordinal, record.ordinal);
        assert_eq!(guard_plans[0].owner, owner);
        assert_eq!(guard_plans[0].frame, Some(CallFrameId(1)));
        assert_eq!(guard_plans[0].bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(guard_plans[0].bytecode_snapshot, bytecode_snapshot);
        assert_eq!(guard_plans[0].plan.owner, owner);
        assert_eq!(guard_plans[0].plan.slot, InlineCacheSlotId(0));
        assert_eq!(guard_plans[0].plan.bytecode_index, 1);
        assert_eq!(
            guard_plans[0].plan.descriptor.requirement,
            PropertyLoadGuardRequirement::PrototypeChain
        );
        assert_eq!(guard_plans[0].plan.descriptor.key, descriptor.key);
        assert_eq!(
            guard_plans[0].plan.descriptor.base_object,
            descriptor.base_object.unwrap()
        );
        assert_eq!(
            guard_plans[0].plan.descriptor.holder_object,
            descriptor.holder_object
        );
        assert_eq!(
            guard_plans[0].plan.descriptor.base_structure,
            descriptor.base_structure.unwrap()
        );
        assert_eq!(guard_plans[0].plan.descriptor.offset, descriptor.offset);
        assert_eq!(
            guard_plans[0].plan.descriptor.prototype_depth,
            descriptor.prototype_depth
        );
        assert_eq!(
            guard_plans[0].plan.descriptor.chain.outcome,
            PropertyLoadGuardChainOutcome::PrototypeData {
                holder_index: 1,
                offset: descriptor.offset.unwrap(),
            }
        );
        assert_eq!(guard_plans[0].plan.descriptor.chain.entries.len(), 2);
        assert_guard_dependency_records(&tiering, &guard_plans[0]);
        assert_eq!(tiering.property_load_guard_dependencies().len(), 2);
        assert!(tiering
            .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("prototype guard-only access-case table")
            .is_empty());
    }

    #[test]
    fn vm_property_handoff_records_own_missing_guard_without_case_plan_or_table_entry() {
        let owner = CodeBlockId(CellId(10));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(1),
        );
        descriptor.holder_object = None;
        descriptor.offset = None;
        descriptor.prototype_depth = 0;
        descriptor.observed_access_case_kind = Some(AccessCaseKind::Miss);
        descriptor.cacheability = crate::object::PropertyCacheability::Allowed;
        descriptor.readiness = descriptor.classify_readiness();

        let record = tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot,
                descriptor: descriptor.clone(),
            })
            .expect("own-missing property handoff observation");

        assert_eq!(
            tiering.property_load_observations(),
            std::slice::from_ref(&record)
        );
        assert!(tiering.property_load_access_case_plans().is_empty());
        let guard_plans = tiering.property_load_guard_plans();
        assert_eq!(guard_plans.len(), 1);
        assert!(record.ordinal < guard_plans[0].ordinal);
        assert_eq!(guard_plans[0].observation_ordinal, record.ordinal);
        assert_eq!(guard_plans[0].owner, owner);
        assert_eq!(guard_plans[0].frame, Some(CallFrameId(1)));
        assert_eq!(guard_plans[0].bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(guard_plans[0].bytecode_snapshot, bytecode_snapshot);
        assert_eq!(
            guard_plans[0].plan.descriptor.requirement,
            PropertyLoadGuardRequirement::NegativeLookup
        );
        assert_eq!(guard_plans[0].plan.descriptor.key, descriptor.key);
        assert_eq!(
            guard_plans[0].plan.descriptor.base_object,
            descriptor.base_object.unwrap()
        );
        assert_eq!(
            guard_plans[0].plan.descriptor.base_structure,
            descriptor.base_structure.unwrap()
        );
        assert_eq!(guard_plans[0].plan.descriptor.holder_object, None);
        assert_eq!(guard_plans[0].plan.descriptor.offset, None);
        assert_eq!(guard_plans[0].plan.descriptor.prototype_depth, 0);
        assert_eq!(
            guard_plans[0].plan.descriptor.chain.outcome,
            PropertyLoadGuardChainOutcome::Missing {
                terminal_null: true,
            }
        );
        assert_eq!(guard_plans[0].plan.descriptor.chain.entries.len(), 1);
        assert_guard_dependency_records(&tiering, &guard_plans[0]);
        assert_eq!(tiering.property_load_guard_dependencies().len(), 1);
        assert!(tiering
            .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("own-missing guard-only access-case table")
            .is_empty());
    }

    #[test]
