    #[test]
    fn vm_property_load_plan_table_projects_own_data_only_from_mixed_guard_metadata() {
        let owner = CodeBlockId(CellId(10));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let own_data = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(1),
        );
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            own_data.clone(),
        );

        let mut prototype = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(2),
        );
        prototype.prototype_depth = 1;
        prototype.holder_object = Some(crate::runtime::ObjectId(CellId(63)));
        prototype.chain = vec![
            PropertyLoadObservationChainEntry {
                object: prototype.base_object.unwrap(),
                structure: prototype.base_structure.unwrap(),
                next_prototype: prototype.holder_object,
            },
            PropertyLoadObservationChainEntry {
                object: prototype.holder_object.unwrap(),
                structure: StructureId(8),
                next_prototype: None,
            },
        ];
        prototype.readiness = prototype.classify_readiness();
        tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(2),
                bytecode_snapshot,
                descriptor: prototype,
            })
            .expect("prototype guard observation");

        let mut missing = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(3),
        );
        missing.holder_object = None;
        missing.offset = None;
        missing.observed_access_case_kind = Some(AccessCaseKind::Miss);
        missing.readiness = missing.classify_readiness();
        tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(3),
                bytecode_snapshot,
                descriptor: missing,
            })
            .expect("negative guard observation");

        assert_eq!(tiering.property_load_observations().len(), 4);
        assert_eq!(tiering.property_load_access_case_plans().len(), 1);
        assert_eq!(tiering.property_load_guard_plans().len(), 2);
        assert_eq!(tiering.property_load_guard_dependencies().len(), 3);
        for guard_plan in tiering.property_load_guard_plans() {
            assert_guard_dependency_records(&tiering, guard_plan);
        }
        let table = tiering
            .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("mixed metadata property-load table");
        assert_eq!(table.len(), 1);
        assert_eq!(table.plans()[0].bytecode_index, own_data.bytecode_index);
        assert!(table.plans()[0].access_case.dependencies.is_empty());
    }

    #[test]
    fn vm_property_load_plan_table_filters_owner_preserves_order_and_excludes_blocked_records() {
        let owner = CodeBlockId(CellId(30));
        let other_owner = CodeBlockId(CellId(31));
        let empty_owner = CodeBlockId(CellId(32));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let other_bytecode_snapshot = baseline_bytecode_snapshot(other_owner);

        let mut first_descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(3),
        );
        first_descriptor.base_structure = Some(StructureId(17));
        first_descriptor.offset = Some(PropertyOffset::new(5));
        first_descriptor.readiness = first_descriptor.classify_readiness();
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            first_descriptor.clone(),
        );

        let mut other_descriptor = property_handoff_observation(
            other_owner,
            InlineCacheSlotId(1),
            BytecodeIndex::from_offset(1),
        );
        other_descriptor.base_structure = Some(StructureId(27));
        other_descriptor.offset = Some(PropertyOffset::new(7));
        other_descriptor.readiness = other_descriptor.classify_readiness();
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            other_owner,
            other_bytecode_snapshot,
            other_descriptor,
        );

        let mut second_descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(2),
            BytecodeIndex::from_offset(1),
        );
        second_descriptor.base_structure = Some(StructureId(18));
        second_descriptor.offset = Some(PropertyOffset::new(6));
        second_descriptor.readiness = second_descriptor.classify_readiness();
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            second_descriptor.clone(),
        );

        let mut blocked_descriptor = property_handoff_observation(
            owner,
            InlineCacheSlotId(3),
            BytecodeIndex::from_offset(4),
        );
        blocked_descriptor.prototype_depth = 1;
        blocked_descriptor.holder_object = Some(crate::runtime::ObjectId(CellId(99)));
        blocked_descriptor.readiness = blocked_descriptor.classify_readiness();
        tiering
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: Some(CallFrameId(4)),
                bytecode_index: BytecodeIndex::from_offset(4),
                bytecode_snapshot,
                descriptor: blocked_descriptor.clone(),
            })
            .expect("blocked prototype property handoff observation");

        assert_eq!(tiering.property_load_observations().len(), 7);
        assert_eq!(tiering.property_load_access_case_plans().len(), 3);

        let table = tiering
            .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("owner property-load plan table");

        assert_eq!(table.owner(), owner);
        assert_eq!(table.len(), 2);
        assert_eq!(table.plans()[0].owner, owner);
        assert_eq!(table.plans()[0].bytecode_index, 3);
        assert_eq!(
            table.plans()[0].access_case.base_structure,
            first_descriptor.base_structure
        );
        assert_eq!(table.plans()[1].owner, owner);
        assert_eq!(table.plans()[1].bytecode_index, 1);
        assert_eq!(
            table.plans()[1].access_case.base_structure,
            second_descriptor.base_structure
        );
        assert!(table
            .plans()
            .iter()
            .all(|plan| plan.bytecode_index != blocked_descriptor.bytecode_index));

        assert_eq!(
            tiering
                .property_load_access_case_candidates_for_bytecode(
                    owner,
                    bytecode_snapshot,
                    BytecodeIndex::from_offset(3)
                )
                .expect("owner bytecode candidates"),
            vec![table.plans()[0].clone()]
        );
        assert!(tiering
            .property_load_access_case_plan_table_for_owner(empty_owner, bytecode_snapshot)
            .expect("empty owner table")
            .is_empty());
    }

