    #[test]
    fn vm_property_store_observation_record_only_for_unsupported_or_unsafe_metadata() {
        let owner = CodeBlockId(CellId(52));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let mut next_offset = 1;

        let mut record_without_plan = |mut descriptor: PropertyStoreObservationDescriptor| {
            let bytecode_index = BytecodeIndex::from_offset(next_offset);
            descriptor.bytecode_index = bytecode_index.offset();
            descriptor.cold_miss_handoff.bytecode_index = bytecode_index.offset();
            descriptor.slot = InlineCacheSlotId(next_offset);
            descriptor.cold_miss_handoff.slot = InlineCacheSlotId(next_offset);
            next_offset += 1;

            record_property_store_descriptor(&mut tiering, owner, bytecode_snapshot, descriptor);
            assert!(tiering.property_store_access_case_plans().is_empty());
        };

        for outcome in [
            PropertyStoreObservationOutcome::Setter,
            PropertyStoreObservationOutcome::Proxy,
            PropertyStoreObservationOutcome::Ignored,
            PropertyStoreObservationOutcome::Opaque,
            PropertyStoreObservationOutcome::Throw,
            PropertyStoreObservationOutcome::Error,
        ] {
            let mut descriptor = property_store_observation(
                owner,
                InlineCacheSlotId(0),
                BytecodeIndex::from_offset(0),
                outcome,
            );
            descriptor.may_call_js = matches!(
                outcome,
                PropertyStoreObservationOutcome::Setter
                    | PropertyStoreObservationOutcome::Proxy
                    | PropertyStoreObservationOutcome::Throw
            );
            record_without_plan(descriptor);
        }

        let mut may_call = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        may_call.may_call_js = true;
        record_without_plan(may_call);

        let mut missing_barrier = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        missing_barrier.stored_value = cell_runtime_value_for_test(0x5200);
        missing_barrier.write_barrier_count = 0;
        missing_barrier.last_write_barrier = None;
        record_without_plan(missing_barrier);

        let mut missing_base = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        missing_base.base_object = None;
        record_without_plan(missing_base);

        let mut missing_before = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        missing_before.base_structure_before = None;
        record_without_plan(missing_before);

        let mut missing_after = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        missing_after.base_structure_after = None;
        record_without_plan(missing_after);

        let mut invalid_structure = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        invalid_structure.base_structure_before = Some(StructureId::INVALID);
        invalid_structure.base_structure_after = Some(StructureId::INVALID);
        record_without_plan(invalid_structure);

        let mut missing_offset = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        missing_offset.offset_after = None;
        record_without_plan(missing_offset);

        let mut invalid_offset = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            BytecodeIndex::from_offset(0),
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        invalid_offset.offset_after = Some(PropertyOffset::INVALID);
        record_without_plan(invalid_offset);

        assert_eq!(
            tiering.property_store_observations().len(),
            next_offset as usize - 1
        );
        assert!(tiering.property_store_access_case_plans().is_empty());
    }

    #[test]
    fn vm_property_store_plan_table_filters_owner_snapshot_and_dedupes_repeated_observations() {
        let owner = CodeBlockId(CellId(53));
        let other_owner = CodeBlockId(CellId(54));
        let mut tiering = VmTieringIntegration::default();
        let first_snapshot = baseline_bytecode_snapshot(owner);
        let second_snapshot = alternate_baseline_bytecode_snapshot(owner);
        let other_snapshot = baseline_bytecode_snapshot(other_owner);
        let first_bytecode_index = BytecodeIndex::from_offset(3);
        let second_bytecode_index = BytecodeIndex::from_offset(1);

        let first_descriptor = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            first_bytecode_index,
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        let mut duplicate_descriptor = first_descriptor.clone();
        duplicate_descriptor.slot = InlineCacheSlotId(7);
        duplicate_descriptor.cold_miss_handoff.slot = InlineCacheSlotId(7);
        let mut second_snapshot_duplicate = first_descriptor.clone();
        second_snapshot_duplicate.slot = InlineCacheSlotId(8);
        second_snapshot_duplicate.cold_miss_handoff.slot = InlineCacheSlotId(8);
        let mut second_descriptor = property_store_observation(
            owner,
            InlineCacheSlotId(2),
            second_bytecode_index,
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        second_descriptor.base_structure_before = Some(StructureId(41));
        second_descriptor.base_structure_after = Some(StructureId(41));
        let mut other_descriptor = property_store_observation(
            other_owner,
            InlineCacheSlotId(3),
            first_bytecode_index,
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        other_descriptor.base_structure_before = Some(StructureId(51));
        other_descriptor.base_structure_after = Some(StructureId(52));

        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            first_snapshot,
            first_descriptor,
        );
        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            second_snapshot,
            second_snapshot_duplicate,
        );
        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            first_snapshot,
            duplicate_descriptor,
        );
        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            first_snapshot,
            second_descriptor,
        );
        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            other_owner,
            other_snapshot,
            other_descriptor,
        );

        assert_eq!(tiering.property_store_access_case_plans().len(), 5);

        let first_table = tiering
            .property_store_access_case_plan_table_for_owner(owner, first_snapshot)
            .expect("first snapshot store table");
        let second_table = tiering
            .property_store_access_case_plan_table_for_owner(owner, second_snapshot)
            .expect("second snapshot store table");
        let other_table = tiering
            .property_store_access_case_plan_table_for_owner(other_owner, other_snapshot)
            .expect("other owner store table");

        assert_eq!(first_table.owner(), owner);
        assert_eq!(first_table.len(), 2);
        assert_eq!(first_table.plans()[0].slot, InlineCacheSlotId(0));
        assert_eq!(
            first_table.plans()[0].bytecode_index,
            first_bytecode_index.offset()
        );
        assert_eq!(first_table.plans()[1].slot, InlineCacheSlotId(2));
        assert_eq!(
            first_table.plans()[1].bytecode_index,
            second_bytecode_index.offset()
        );
        assert_eq!(second_table.len(), 1);
        assert_eq!(second_table.plans()[0].slot, InlineCacheSlotId(8));
        assert_eq!(other_table.len(), 1);
        assert_eq!(other_table.plans()[0].owner, other_owner);
    }

    #[test]
    fn vm_property_store_plan_table_suppresses_new_case_replaced_by_existing_handler_case() {
        let owner = CodeBlockId(CellId(57));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_index = BytecodeIndex::from_offset(4);
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);

        let mut first_descriptor = property_store_observation(
            owner,
            InlineCacheSlotId(0),
            bytecode_index,
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        first_descriptor.base_structure_before = Some(StructureId(17));
        first_descriptor.base_structure_after = Some(StructureId(17));
        first_descriptor.offset_after = Some(PropertyOffset::new(5));
        let mut second_descriptor = first_descriptor.clone();
        second_descriptor.slot = InlineCacheSlotId(7);
        second_descriptor.cold_miss_handoff.slot = InlineCacheSlotId(7);
        second_descriptor.base_structure_before = Some(StructureId(18));
        second_descriptor.base_structure_after = Some(StructureId(18));
        second_descriptor.offset_after = Some(PropertyOffset::new(9));

        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            first_descriptor,
        );
        record_property_store_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            second_descriptor,
        );

        assert_eq!(tiering.property_store_access_case_plans().len(), 2);
        tiering.property_store_access_case_plans[1].plan.slot = InlineCacheSlotId(0);
        tiering.property_store_access_case_plans[1]
            .plan
            .access_case
            .base_structure = Some(StructureId(17));

        let table = tiering
            .property_store_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("canReplace-projected property-store plan table");

        assert_eq!(table.len(), 1);
        assert_eq!(table.plans()[0].slot, InlineCacheSlotId(0));
        assert_eq!(
            table.plans()[0].access_case.offset,
            Some(PropertyOffset::new(5))
        );
    }

