    #[test]
    fn vm_property_store_access_case_install_recheck_rejects_missing_plan_and_request_mismatches() {
        let (mut tiering, _, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::OwnDataStore,
        );

        let mut missing_plan_request = property_store_access_case_install_recheck_request(&plan);
        missing_plan_request.store_plan_ordinal += 100;
        let missing_plan =
            tiering.record_property_store_access_case_install_recheck(missing_plan_request);
        assert_eq!(missing_plan.observation_ordinal, None);
        assert_store_install_recheck_rejected(
            missing_plan,
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::PlanMissing,
        );

        macro_rules! assert_request_rejection {
            ($mutate:expr, $reason:expr) => {{
                let mut request = property_store_access_case_install_recheck_request(&plan);
                $mutate(&mut request);
                let recheck = tiering.record_property_store_access_case_install_recheck(request);
                assert_eq!(recheck.observation_ordinal, Some(plan.observation_ordinal));
                assert_store_install_recheck_rejected(recheck, $reason);
            }};
        }

        assert_request_rejection!(
            |request: &mut VmPropertyStoreAccessCaseInstallRecheckRequest| {
                request.owner = CodeBlockId(CellId(501));
            },
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::OwnerMismatch
        );
        assert_request_rejection!(
            |request: &mut VmPropertyStoreAccessCaseInstallRecheckRequest| {
                request.slot = InlineCacheSlotId(99);
            },
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::SlotMismatch
        );
        assert_request_rejection!(
            |request: &mut VmPropertyStoreAccessCaseInstallRecheckRequest| {
                request.bytecode_index = BytecodeIndex::from_offset(99);
            },
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::BytecodeIndexMismatch
        );
        assert_request_rejection!(
            |request: &mut VmPropertyStoreAccessCaseInstallRecheckRequest| {
                request.bytecode_snapshot = alternate_baseline_bytecode_snapshot(plan.owner);
            },
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::BytecodeSnapshotMismatch
        );
    }

