    #[test]
    fn vm_property_store_access_case_install_recheck_rejects_barrier_contract_and_malformed_plan() {
        let (mut unsupported_barrier, _, unsupported_plan, _) =
            record_property_store_install_recheck_fixture(
                PropertyStoreObservationOutcome::OwnDataStore,
            );
        unsupported_barrier.property_store_access_case_plans[0]
            .plan
            .effect_contract
            .barrier = PropertyStoreBarrierEffect::Unsupported;
        let recheck = unsupported_barrier.record_property_store_access_case_install_recheck(
            property_store_access_case_install_recheck_request(&unsupported_plan),
        );
        assert_store_install_recheck_rejected(
            recheck,
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::UnsupportedBarrierEffect {
                barrier: PropertyStoreBarrierEffect::Unsupported,
            },
        );

        let (mut mismatched_barrier, _, mismatched_plan, _) =
            record_property_store_install_recheck_fixture(
                PropertyStoreObservationOutcome::OwnDataStore,
            );
        mismatched_barrier.property_store_access_case_plans[0]
            .plan
            .effect_contract
            .barrier =
            PropertyStoreBarrierEffect::RequiresRuntimeStoredValueAndStructureTransitionBarrierProof;
        let recheck = mismatched_barrier.record_property_store_access_case_install_recheck(
            property_store_access_case_install_recheck_request(&mismatched_plan),
        );
        assert_store_install_recheck_rejected(
            recheck,
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::BarrierContractMismatch {
                expected: PropertyStoreBarrierEffect::RequiresRuntimeStoredValueBarrierProof,
                actual:
                    PropertyStoreBarrierEffect::RequiresRuntimeStoredValueAndStructureTransitionBarrierProof,
            },
        );

        let (mut malformed, _, malformed_plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        malformed.property_store_access_case_plans[0]
            .plan
            .access_case
            .may_call_js = true;
        let recheck = malformed.record_property_store_access_case_install_recheck(
            property_store_access_case_install_recheck_request(&malformed_plan),
        );
        assert_store_install_recheck_rejected(
            recheck,
            VmPropertyStoreAccessCaseInstallRecheckRejectionReason::PlanValidationRejected {
                error: InlineCacheValidationError::PropertyStorePlanMayCallJs,
            },
        );
    }

