    #[test]
    fn vm_generated_property_store_mutation_readiness_accepts_accepted_recheck_barrier_evidence() {
        let (mut tiering, observation, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        let recheck = tiering.record_property_store_access_case_install_recheck(
            property_store_access_case_install_recheck_request(&plan),
        );
        let barrier_evidence = recheck
            .barrier_evidence
            .expect("accepted store recheck barrier evidence");

        let readiness = tiering.record_generated_property_store_mutation_readiness(
            generated_property_store_mutation_readiness_request(&plan, recheck.ordinal),
        );

        assert!(recheck.ordinal < readiness.ordinal);
        assert_eq!(readiness.owner, plan.owner);
        assert_eq!(readiness.bytecode_index, plan.bytecode_index);
        assert_eq!(readiness.bytecode_snapshot, plan.bytecode_snapshot);
        assert_eq!(readiness.slot, plan.plan.slot);
        assert_eq!(readiness.store_plan_ordinal, plan.ordinal);
        assert_eq!(readiness.install_recheck_ordinal, recheck.ordinal);
        assert_eq!(readiness.observation_ordinal, Some(observation.ordinal));
        assert_eq!(readiness.barrier_evidence, Some(barrier_evidence));
        assert_eq!(readiness.key, plan.plan.key);
        assert_eq!(readiness.plan_kind, plan.plan.plan_kind);
        assert_eq!(
            readiness.base_structure,
            plan.plan.access_case.base_structure
        );
        assert_eq!(
            readiness.planned_new_structure,
            plan.plan.access_case.new_structure
        );
        assert_eq!(readiness.planned_offset, plan.plan.access_case.offset);
        assert_eq!(readiness.stored_value_kind, ValueKind::Int32);
        assert_eq!(
            readiness.outcome,
            VmGeneratedPropertyStoreMutationReadinessOutcome::Accepted {
                observation_ordinal: observation.ordinal,
                barrier_evidence
            }
        );
        assert_eq!(
            tiering.generated_property_store_mutation_readiness_records(),
            std::slice::from_ref(&readiness)
        );
    }

