    #[test]
    fn vm_generated_property_store_probe_miss_records_ordered_coherent_non_terminal_telemetry() {
        let (mut tiering, observation, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::CreatedProperty,
        );

        let mut first_request = generated_property_store_probe_miss_request(
            &plan,
            GeneratedPropertyStoreProbeMissReason::HostUnavailable,
        );
        first_request.stored_value_kind = ValueKind::Boolean;
        let first = tiering.record_generated_property_store_probe_miss(first_request);

        let second_request = generated_property_store_probe_miss_request(
            &plan,
            GeneratedPropertyStoreProbeMissReason::StructureMismatch,
        );
        let second = tiering.record_generated_property_store_probe_miss(second_request);

        assert!(first.ordinal < second.ordinal);
        assert!(!first.terminal);
        assert!(!second.terminal);
        assert_eq!(first.owner, plan.owner);
        assert_eq!(first.bytecode_index, plan.bytecode_index);
        assert_eq!(first.bytecode_snapshot, plan.bytecode_snapshot);
        assert_eq!(first.slot, plan.plan.slot);
        assert_eq!(first.store_plan_ordinal, plan.ordinal);
        assert_eq!(first.observation_ordinal, Some(observation.ordinal));
        assert_eq!(first.key, plan.plan.key);
        assert_eq!(
            first.plan_kind,
            PropertyStoreAccessCasePlanKind::DataOnlyTransition
        );
        assert_eq!(first.base_structure, plan.plan.access_case.base_structure);
        assert_eq!(
            first.planned_new_structure,
            plan.plan.access_case.new_structure
        );
        assert_eq!(first.planned_offset, plan.plan.access_case.offset);
        assert_eq!(first.stored_value_kind, ValueKind::Boolean);
        assert_eq!(
            first.outcome,
            VmGeneratedPropertyStoreProbeMissOutcome::Accepted {
                observation_ordinal: observation.ordinal
            }
        );
        assert_eq!(
            tiering.generated_property_store_probe_misses(),
            &[first.clone(), second]
        );
    }

    #[test]
    fn vm_generated_property_store_probe_miss_rejects_missing_plan_and_request_mismatches() {
        let (mut tiering, _, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::OwnDataStore,
        );

        let mut missing_plan_request = generated_property_store_probe_miss_request(
            &plan,
            GeneratedPropertyStoreProbeMissReason::HostUnavailable,
        );
        missing_plan_request.store_plan_ordinal += 100;
        let missing_plan = tiering.record_generated_property_store_probe_miss(missing_plan_request);
        assert_store_probe_miss_rejected(
            missing_plan,
            None,
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMissing,
        );

        macro_rules! assert_request_rejection {
            ($mutate:expr, $reason:expr) => {{
                let mut request = generated_property_store_probe_miss_request(
                    &plan,
                    GeneratedPropertyStoreProbeMissReason::HostUnavailable,
                );
                $mutate(&mut request);
                let miss = tiering.record_generated_property_store_probe_miss(request);
                assert_store_probe_miss_rejected(miss, Some(plan.observation_ordinal), $reason);
            }};
        }

        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.owner = CodeBlockId(CellId(601));
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::OwnerMismatch
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.slot = InlineCacheSlotId(99);
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::SlotMismatch
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.bytecode_index = BytecodeIndex::from_offset(99);
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::BytecodeIndexMismatch
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.bytecode_snapshot = alternate_baseline_bytecode_snapshot(plan.owner);
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::BytecodeSnapshotMismatch
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.key = CacheKey::Dynamic;
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMetadataMismatch {
                field: VmGeneratedPropertyStoreProbeMissMetadataMismatchField::Key
            }
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.base_structure = Some(StructureId(601));
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMetadataMismatch {
                field: VmGeneratedPropertyStoreProbeMissMetadataMismatchField::BaseStructure
            }
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.planned_offset = Some(PropertyOffset::new(601));
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMetadataMismatch {
                field: VmGeneratedPropertyStoreProbeMissMetadataMismatchField::Offset
            }
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.planned_new_structure = Some(StructureId(601));
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMetadataMismatch {
                field: VmGeneratedPropertyStoreProbeMissMetadataMismatchField::NewStructure
            }
        );
        assert_request_rejection!(
            |request: &mut VmGeneratedPropertyStoreProbeMissRequest| {
                request.plan_kind = PropertyStoreAccessCasePlanKind::DataOnlyTransition;
            },
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMetadataMismatch {
                field: VmGeneratedPropertyStoreProbeMissMetadataMismatchField::PlanKind
            }
        );
    }

    #[test]
    fn vm_generated_property_store_probe_miss_rejects_plan_metadata_drift_and_invalid_plan() {
        let (mut drifted, _, drifted_plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        drifted.property_store_access_case_plans[0]
            .plan
            .access_case
            .offset = Some(PropertyOffset::new(602));

        let drifted_miss = drifted.record_generated_property_store_probe_miss(
            generated_property_store_probe_miss_request(
                &drifted_plan,
                GeneratedPropertyStoreProbeMissReason::StructureMismatch,
            ),
        );

        assert_store_probe_miss_rejected(
            drifted_miss,
            Some(drifted_plan.observation_ordinal),
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanMetadataMismatch {
                field: VmGeneratedPropertyStoreProbeMissMetadataMismatchField::Offset,
            },
        );

        let (mut invalid, _, _, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        invalid.property_store_access_case_plans[0]
            .plan
            .access_case
            .may_call_js = true;
        let invalid_plan = invalid.property_store_access_case_plans()[0].clone();

        let invalid_miss = invalid.record_generated_property_store_probe_miss(
            generated_property_store_probe_miss_request(
                &invalid_plan,
                GeneratedPropertyStoreProbeMissReason::UnsupportedPlanMetadata,
            ),
        );

        assert_store_probe_miss_rejected(
            invalid_miss,
            Some(invalid_plan.observation_ordinal),
            VmGeneratedPropertyStoreProbeMissRejectionReason::PlanValidationRejected {
                error: InlineCacheValidationError::PropertyStorePlanMayCallJs,
            },
        );
    }

    #[test]
    fn vm_generated_property_store_probe_miss_does_not_mutate_store_plan_or_generated_artifact_state(
    ) {
        let (mut tiering, observation, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        let generated_artifact = tiering
            .record_baseline_generated_code_artifact(
                plan.owner,
                baseline_generated_code_artifact(plan.owner, 602),
            )
            .expect("baseline generated artifact");
        let original_lifecycle = tiering.property_store_access_case_plans()[0].lifecycle;
        let original_plan = tiering.property_store_access_case_plans()[0].plan.clone();
        let original_observations = tiering.property_store_observations().to_vec();

        let accepted = tiering.record_generated_property_store_probe_miss(
            generated_property_store_probe_miss_request(
                &plan,
                GeneratedPropertyStoreProbeMissReason::StructureMismatch,
            ),
        );

        let mut rejected_request = generated_property_store_probe_miss_request(
            &plan,
            GeneratedPropertyStoreProbeMissReason::ExistingPropertyMismatch,
        );
        rejected_request.key = CacheKey::Dynamic;
        let rejected = tiering.record_generated_property_store_probe_miss(rejected_request);

        assert_eq!(
            accepted.outcome,
            VmGeneratedPropertyStoreProbeMissOutcome::Accepted {
                observation_ordinal: observation.ordinal
            }
        );
        assert!(matches!(
            rejected.outcome,
            VmGeneratedPropertyStoreProbeMissOutcome::Rejected { .. }
        ));
        assert_eq!(
            tiering.property_store_access_case_plans()[0].lifecycle,
            original_lifecycle
        );
        assert_eq!(
            tiering.property_store_access_case_plans()[0].plan,
            original_plan
        );
        assert_eq!(tiering.property_store_observations(), original_observations);
        assert!(tiering
            .property_store_access_case_install_rechecks()
            .is_empty());
        assert!(tiering.generated_property_load_probe_misses().is_empty());
        assert!(tiering
            .generated_guarded_property_load_probe_misses()
            .is_empty());
        assert!(tiering.baseline_generated_code_invalidations().is_empty());
        assert_eq!(
            tiering.baseline_generated_code_artifact_for(plan.owner),
            Some(generated_artifact.clone())
        );
        let entry = observe_baseline_entry(&mut tiering, plan.owner, 602);
        assert_eq!(
            entry.decision,
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            entry.baseline_entry_gate.as_ref().map(|gate| gate.outcome),
            Some(BaselineEntryGateOutcome::Eligible)
        );
        assert_eq!(
            tiering.generated_property_store_probe_misses(),
            &[accepted, rejected]
        );
    }

    #[test]
    fn vm_generated_property_store_mutation_rejection_records_coherent_record_only_telemetry() {
        let (mut tiering, observation, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::CreatedProperty,
        );
        let recheck = tiering.record_property_store_access_case_install_recheck(
            property_store_access_case_install_recheck_request(&plan),
        );
        let readiness = tiering.record_generated_property_store_mutation_readiness(
            generated_property_store_mutation_readiness_request(&plan, recheck.ordinal),
        );
        let generated_artifact = tiering
            .record_baseline_generated_code_artifact(
                plan.owner,
                baseline_generated_code_artifact(plan.owner, 605),
            )
            .expect("baseline generated artifact");

        let original_lifecycle = tiering.property_store_access_case_plans()[0].lifecycle;
        let original_plan = tiering.property_store_access_case_plans()[0].plan.clone();
        let original_observations = tiering.property_store_observations().to_vec();
        let original_rechecks = tiering
            .property_store_access_case_install_rechecks()
            .to_vec();
        let original_readiness = tiering
            .generated_property_store_mutation_readiness_records()
            .to_vec();

        let rejection = tiering.record_generated_property_store_mutation_rejection(
            generated_property_store_mutation_rejection_request(
                &plan,
                readiness.ordinal,
                GeneratedPropertyStoreMutationMissReason::BarrierRejected,
            ),
        );

        assert_eq!(rejection.owner, plan.owner);
        assert_eq!(rejection.bytecode_index, plan.bytecode_index);
        assert_eq!(rejection.bytecode_snapshot, plan.bytecode_snapshot);
        assert_eq!(rejection.slot, plan.plan.slot);
        assert_eq!(rejection.store_plan_ordinal, plan.ordinal);
        assert_eq!(rejection.readiness_ordinal, readiness.ordinal);
        assert_eq!(rejection.observation_ordinal, Some(observation.ordinal));
        assert_eq!(rejection.key, plan.plan.key);
        assert_eq!(rejection.plan_kind, plan.plan.plan_kind);
        assert_eq!(
            rejection.base_structure,
            plan.plan.access_case.base_structure
        );
        assert_eq!(
            rejection.planned_new_structure,
            plan.plan.access_case.new_structure
        );
        assert_eq!(rejection.planned_offset, plan.plan.access_case.offset);
        assert_eq!(rejection.stored_value_kind, ValueKind::Int32);
        assert_eq!(
            rejection.reason,
            GeneratedPropertyStoreMutationMissReason::BarrierRejected
        );
        assert_eq!(
            rejection.outcome,
            VmGeneratedPropertyStoreMutationRejectionOutcome::Accepted {
                observation_ordinal: observation.ordinal
            }
        );
        assert_eq!(
            tiering.property_store_access_case_plans()[0].lifecycle,
            original_lifecycle
        );
        assert_eq!(
            tiering.property_store_access_case_plans()[0].plan,
            original_plan
        );
        assert_eq!(tiering.property_store_observations(), original_observations);
        assert_eq!(
            tiering.property_store_access_case_install_rechecks(),
            original_rechecks
        );
        assert_eq!(
            tiering.generated_property_store_mutation_readiness_records(),
            original_readiness
        );
        assert!(tiering.generated_property_store_probe_misses().is_empty());
        assert!(tiering.baseline_generated_code_invalidations().is_empty());
        assert_eq!(
            tiering.baseline_generated_code_artifact_for(plan.owner),
            Some(generated_artifact.clone())
        );
        let entry = observe_baseline_entry(&mut tiering, plan.owner, 605);
        assert_eq!(
            entry.decision,
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline
            }
        );
    }

    #[test]
    fn vm_generated_property_store_mutation_rejection_rejects_mismatched_readiness_without_probe_miss(
    ) {
        let (mut tiering, _, plan, _) = record_property_store_install_recheck_fixture(
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        let recheck = tiering.record_property_store_access_case_install_recheck(
            property_store_access_case_install_recheck_request(&plan),
        );
        let readiness = tiering.record_generated_property_store_mutation_readiness(
            generated_property_store_mutation_readiness_request(&plan, recheck.ordinal),
        );

        let mut missing_request = generated_property_store_mutation_rejection_request(
            &plan,
            readiness.ordinal + 100,
            GeneratedPropertyStoreMutationMissReason::BarrierRejected,
        );
        let missing = tiering.record_generated_property_store_mutation_rejection(missing_request);
        assert_store_mutation_rejection_rejected(
            missing,
            Some(plan.observation_ordinal),
            VmGeneratedPropertyStoreMutationRejectionRecordRejectionReason::ReadinessMissing,
        );

        missing_request.readiness_ordinal = readiness.ordinal;
        missing_request.stored_value_kind = ValueKind::Boolean;
        let mismatched =
            tiering.record_generated_property_store_mutation_rejection(missing_request);
        assert_store_mutation_rejection_rejected(
            mismatched,
            Some(plan.observation_ordinal),
            VmGeneratedPropertyStoreMutationRejectionRecordRejectionReason::ReadinessMetadataMismatch {
                field:
                    VmGeneratedPropertyStoreMutationRejectionMetadataMismatchField::StoredValueKind,
            },
        );
        assert!(tiering.generated_property_store_probe_misses().is_empty());
        assert_eq!(
            tiering.generated_property_store_mutation_rejections().len(),
            2
        );
    }

    #[test]
    fn vm_property_load_terminal_probe_miss_invalidates_active_plan_projection() {
        let owner = CodeBlockId(CellId(42));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let bytecode_index = BytecodeIndex::from_offset(6);
        let descriptor = property_handoff_observation(owner, InlineCacheSlotId(0), bytecode_index);

        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            descriptor,
        );

        let structure_mismatch_request = generated_property_load_probe_miss_request(
            &tiering.property_load_access_case_plans()[0],
            GeneratedPropertyLoadProbeMissReason::StructureMismatch,
        );
        let structure_mismatch =
            tiering.record_generated_property_load_probe_miss(structure_mismatch_request);
        assert!(!structure_mismatch.terminal);
        assert!(structure_mismatch.invalidated_plan_ordinals.is_empty());
        assert_eq!(
            tiering.property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Active
        );
        assert_eq!(
            tiering
                .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
                .expect("active table after non-terminal miss")
                .len(),
            1
        );

        let active_plan_ordinal = tiering.property_load_access_case_plans()[0].ordinal;
        let missing_property_request = generated_property_load_probe_miss_request(
            &tiering.property_load_access_case_plans()[0],
            GeneratedPropertyLoadProbeMissReason::MissingProperty,
        );
        let missing_property =
            tiering.record_generated_property_load_probe_miss(missing_property_request);

        assert!(missing_property.terminal);
        assert_eq!(
            missing_property.invalidated_plan_ordinals,
            vec![active_plan_ordinal]
        );
        assert_eq!(
            tiering.property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Invalidated {
                reason: GeneratedPropertyLoadProbeMissReason::MissingProperty,
                miss_ordinal: missing_property.ordinal,
            }
        );
        assert!(tiering
            .property_load_access_case_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("terminally invalidated table")
            .is_empty());
        assert!(tiering
            .generated_guarded_property_load_probe_misses()
            .is_empty());
    }

    #[test]
    fn generated_property_load_probe_miss_feeds_generated_artifact_invalidation_only_when_terminal()
    {
        let owner = CodeBlockId(CellId(142));
        let mut tiering = VmTieringIntegration::default();
        let bytecode_snapshot = baseline_bytecode_snapshot(owner);
        let bytecode_index = BytecodeIndex::from_offset(6);
        let generated_artifact = tiering
            .record_baseline_generated_code_artifact(
                owner,
                baseline_generated_code_artifact(owner, 142),
            )
            .unwrap();
        let descriptor = property_handoff_observation(owner, InlineCacheSlotId(0), bytecode_index);
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            bytecode_snapshot,
            descriptor,
        );

        let non_terminal_request = generated_property_load_probe_miss_request(
            &tiering.property_load_access_case_plans()[0],
            GeneratedPropertyLoadProbeMissReason::StructureMismatch,
        );
        let non_terminal = tiering.record_generated_property_load_probe_miss(non_terminal_request);
        assert!(!non_terminal.terminal);
        assert!(tiering.baseline_generated_code_invalidations().is_empty());
        assert_eq!(
            tiering.baseline_generated_code_artifact_for(owner),
            Some(generated_artifact.clone())
        );

        let terminal_request = generated_property_load_probe_miss_request(
            &tiering.property_load_access_case_plans()[0],
            GeneratedPropertyLoadProbeMissReason::MissingProperty,
        );
        let terminal = tiering.record_generated_property_load_probe_miss(terminal_request);
        let generated_invalidation = tiering
            .baseline_generated_code_invalidations()
            .last()
            .copied()
            .expect("terminal property-load generated invalidation");
        let entry = observe_baseline_entry(&mut tiering, owner, 142);

        assert!(terminal.terminal);
        assert_eq!(
            generated_invalidation.outcome,
            BaselineGeneratedCodeInvalidationOutcome::Accepted
        );
        assert_eq!(
            generated_invalidation.source,
            BaselineGeneratedCodeInvalidationSource::PropertyLoadProbeMiss
        );
        assert_eq!(
            generated_invalidation.reason,
            CodeInvalidationReason::GeneratedInlineCacheDependencyInvalidated
        );
        assert_eq!(
            generated_invalidation.artifact_id,
            Some(generated_artifact.id)
        );
        assert_eq!(
            generated_invalidation.bytecode_snapshot,
            Some(bytecode_snapshot)
        );
        assert_eq!(
            entry.baseline_entry_gate.as_ref().map(|gate| gate.outcome),
            Some(BaselineEntryGateOutcome::InvalidatedGeneratedArtifact)
        );
    }

    #[test]
    fn generated_property_load_probe_miss_targets_generated_artifact_when_ic_snapshot_differs() {
        let owner = CodeBlockId(CellId(143));
        let mut tiering = VmTieringIntegration::default();
        let ic_snapshot = baseline_bytecode_snapshot(owner);
        let bytecode_index = BytecodeIndex::from_offset(6);
        let generated_artifact = tiering
            .record_baseline_generated_code_artifact(
                owner,
                alternate_snapshot_baseline_generated_code_artifact(owner, 143),
            )
            .unwrap();
        let artifact_snapshot = generated_artifact
            .eligibility_proof
            .bytecode_snapshot_fingerprint();
        assert_ne!(ic_snapshot, artifact_snapshot);
        let descriptor = property_handoff_observation(owner, InlineCacheSlotId(0), bytecode_index);
        record_property_load_descriptor_after_initial_countdown(
            &mut tiering,
            owner,
            ic_snapshot,
            descriptor,
        );

        let terminal_request = generated_property_load_probe_miss_request(
            &tiering.property_load_access_case_plans()[0],
            GeneratedPropertyLoadProbeMissReason::MissingProperty,
        );
        assert_eq!(
            tiering.property_load_access_case_plans()[0].bytecode_snapshot,
            ic_snapshot
        );
        assert_eq!(terminal_request.bytecode_snapshot, ic_snapshot);
        let terminal = tiering.record_generated_property_load_probe_miss(terminal_request);
        let generated_invalidation = tiering
            .baseline_generated_code_invalidations()
            .last()
            .copied()
            .expect("terminal property-load generated invalidation with mismatched IC snapshot");

        assert!(terminal.terminal);
        assert_eq!(
            generated_invalidation.outcome,
            BaselineGeneratedCodeInvalidationOutcome::Accepted
        );
        assert_eq!(
            generated_invalidation.source,
            BaselineGeneratedCodeInvalidationSource::PropertyLoadProbeMiss
        );
        assert_eq!(
            generated_invalidation.artifact_id,
            Some(generated_artifact.id)
        );
        assert_eq!(
            generated_invalidation.bytecode_snapshot,
            Some(artifact_snapshot)
        );
        assert!(tiering
            .baseline_generated_code_artifact_for(owner)
            .is_none());
    }

