    #[test]
    fn baseline_native_entry_readiness_lookup_by_gate_requires_exact_ready_disabled_record() {
        let owner = CodeBlockId(CellId(115));
        let other_owner = CodeBlockId(CellId(116));
        let mut tiering = VmTieringIntegration::default();
        let artifact = baseline_artifact(owner, 115);
        let materialization = accepted_materialization(&mut tiering, owner, &artifact);
        let install = tiering.record_baseline_install(BaselineInstallRequest {
            owner,
            artifact: &artifact,
            materialization: Some(&materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::Succeeded,
            eligibility: baseline_eligibility(owner),
        });
        let entry_artifact = install.artifact.expect("installed native artifact");
        let readiness = tiering
            .baseline_native_entry_readiness_records()
            .last()
            .expect("ready-disabled native entry")
            .clone();
        let gate = BaselineEntryGateRecord {
            owner,
            requested_tier: JitType::Baseline,
            native_artifact: Some(entry_artifact),
            native_entry_readiness_ordinal: Some(readiness.ordinal),
            generated_artifact: None,
            outcome: BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled,
        };

        assert_eq!(
            tiering
                .baseline_native_entry_readiness_by_ordinal(readiness.ordinal)
                .map(|record| record.ordinal),
            Some(readiness.ordinal)
        );
        assert_eq!(
            tiering
                .baseline_native_entry_readiness_for_gate(&gate)
                .map(|record| record.ordinal),
            Some(readiness.ordinal)
        );

        let mut wrong_ordinal = gate.clone();
        wrong_ordinal.native_entry_readiness_ordinal = Some(readiness.ordinal + 1);
        assert!(tiering
            .baseline_native_entry_readiness_for_gate(&wrong_ordinal)
            .is_none());

        let mut wrong_artifact = gate.clone();
        wrong_artifact.native_artifact = Some(
            baseline_artifact(owner, 116)
                .validate_baseline_entry_artifact(owner)
                .expect("alternate native artifact"),
        );
        assert!(tiering
            .baseline_native_entry_readiness_for_gate(&wrong_artifact)
            .is_none());

        let rejected =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner: other_owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Disabled,
                callable: None,
            });
        assert!(matches!(
            rejected.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected { .. }
        ));
        assert!(tiering
            .baseline_native_entry_readiness_by_ordinal(rejected.ordinal)
            .is_none());
    }

