    #[test]
    fn baseline_machine_code_emission_provenance_is_not_required_for_disabled_native_readiness() {
        let owner = CodeBlockId(CellId(442));
        let artifact = baseline_artifact(owner, 442);
        let mut tiering = VmTieringIntegration::default();
        let materialization = accepted_materialization(&mut tiering, owner, &artifact);
        let install = installed_native_entry(&mut tiering, owner, &artifact, &materialization);
        let readiness = tiering
            .baseline_native_entry_readiness_records()
            .last()
            .expect("descriptor-only readiness");

        assert_eq!(
            install.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::ReadyButExecutionDisabled
        );
        assert!(readiness.callable.is_none());
        assert!(materialization
            .link_finalization
            .as_ref()
            .and_then(|record| record.byte_copy_evidence.as_ref())
            .is_none());
        assert!(tiering
            .baseline_machine_code_emission_provenance_records()
            .is_empty());

        let record = observe_baseline_entry(&mut tiering, owner, 442);
        assert_eq!(
            record.baseline_entry_gate.as_ref().map(|gate| gate.outcome),
            Some(BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled)
        );
        assert_eq!(
            record.decision,
            TierEntryDecision::FallbackToInterpreter {
                attempted_tier: JitType::Baseline,
                reason: TierEntryFallbackReason::NativeEntryDisabled,
            }
        );
    }

