    #[test]
    fn baseline_native_entry_readiness_enabled_requires_sealed_callable_authority() {
        let owner = CodeBlockId(CellId(338));
        let artifact = baseline_artifact(owner, 338);
        let mut tiering = VmTieringIntegration::default();
        let materialization =
            accepted_byte_evidence_materialization(&mut tiering, owner, &artifact);
        let install = installed_native_entry(&mut tiering, owner, &artifact, &materialization);
        let descriptor = install
            .artifact
            .expect("installed native artifact")
            .validate_native_entry_descriptor()
            .expect("native entry descriptor");

        let missing =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: None,
            });
        assert_eq!(
            missing.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::CallableAuthorityMissing
            }
        );

        let other_owner = CodeBlockId(CellId(339));
        let wrong_owner_descriptor = baseline_artifact(other_owner, 338)
            .validate_baseline_entry_artifact(other_owner)
            .expect("wrong-owner native artifact")
            .validate_native_entry_descriptor()
            .expect("wrong-owner native descriptor");
        let owner_mismatch =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(
                    BaselineNativeEntryCallableAuthority::new_p6_pure_baseline_native_entry_shim(
                        wrong_owner_descriptor,
                    ),
                ),
            });
        assert_eq!(
            owner_mismatch.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::CallableAuthorityMismatch {
                    reason: Box::new(BaselineNativeEntryCallableValidationError::OwnerMismatch {
                        expected: descriptor.owner,
                        actual: wrong_owner_descriptor.owner,
                    }),
                }
            }
        );

        let wrong_artifact = baseline_artifact(owner, 339)
            .validate_baseline_entry_artifact(owner)
            .expect("alternate native artifact");
        let wrong_descriptor = wrong_artifact
            .validate_native_entry_descriptor()
            .expect("alternate native descriptor");
        let wrong_callable =
            BaselineNativeEntryCallableAuthority::new_p6_pure_baseline_native_entry_shim(
                wrong_descriptor,
            );
        let artifact_mismatch =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(wrong_callable),
            });
        assert_eq!(
            artifact_mismatch.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::CallableAuthorityMismatch {
                    reason: Box::new(
                        BaselineNativeEntryCallableValidationError::ArtifactIdMismatch {
                            expected: descriptor.artifact_id,
                            actual: wrong_descriptor.artifact_id,
                        },
                    ),
                }
            }
        );

        let mut wrong_native_descriptor = descriptor;
        wrong_native_descriptor.native_symbol = NativeCodeId(999_001);
        let native_mismatch =
            BaselineNativeEntryCallableAuthority::for_test_with_descriptor_and_token(
                wrong_callable.kind(),
                wrong_native_descriptor,
                descriptor.normal_entry,
            );
        let rejected_native =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(native_mismatch),
            });
        assert_eq!(
            rejected_native.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::CallableAuthorityMismatch {
                    reason: Box::new(
                        BaselineNativeEntryCallableValidationError::NativeCodeMismatch {
                            expected: descriptor.native_symbol,
                            actual: wrong_native_descriptor.native_symbol,
                        },
                    ),
                }
            }
        );

        let mut wrong_machine_descriptor = descriptor;
        wrong_machine_descriptor.machine_code.range.size_bytes += 1;
        let machine_mismatch =
            BaselineNativeEntryCallableAuthority::for_test_with_descriptor_and_token(
                wrong_callable.kind(),
                wrong_machine_descriptor,
                descriptor.normal_entry,
            );
        let rejected_machine =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(machine_mismatch),
            });
        assert_eq!(
            rejected_machine.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::CallableAuthorityMismatch {
                    reason: Box::new(
                        BaselineNativeEntryCallableValidationError::MachineCodeMismatch {
                            expected: Box::new(descriptor.machine_code),
                            actual: Box::new(wrong_machine_descriptor.machine_code),
                        },
                    ),
                }
            }
        );

        let mut wrong_token = descriptor.normal_entry;
        wrong_token.artifact_id = JitCodeId(u64::MAX);
        let token_mismatch =
            BaselineNativeEntryCallableAuthority::for_test_with_descriptor_and_token(
                wrong_callable.kind(),
                descriptor,
                wrong_token,
            );
        let rejected_token =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(token_mismatch),
            });
        assert_eq!(
            rejected_token.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::CallableAuthorityMismatch {
                    reason: Box::new(BaselineNativeEntryCallableValidationError::TokenMismatch {
                        expected: Box::new(descriptor.normal_entry),
                        actual: Box::new(wrong_token),
                    }),
                }
            }
        );

        let accepted =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(
                    BaselineNativeEntryCallableAuthority::new_p6_pure_baseline_native_entry_shim(
                        descriptor,
                    ),
                ),
            });
        assert_eq!(accepted.outcome, BaselineNativeEntryReadinessOutcome::Ready);
        assert!(accepted.callable.is_some());
        let install_proof = install
            .eligibility_proof
            .as_ref()
            .expect("enabled native readiness keeps install proof");
        let body_capability = accepted
            .body_capability
            .expect("enabled native readiness records body capability");
        assert_eq!(
            body_capability,
            BaselineGeneratedCodeBodyCapability::from_eligibility_proof(install_proof)
        );
        assert_ne!(
            body_capability.supported_opcode_subset,
            accepted
                .callable
                .expect("enabled callable")
                .kind()
                .supported_opcode_subset()
        );
    }

    #[test]
    fn baseline_native_entry_readiness_rejects_unowned_rejected_and_mismatched_materialization() {
        let owner = CodeBlockId(CellId(39));
        let artifact = baseline_artifact(owner, 39);
        let mut tiering = VmTieringIntegration::default();
        let materialization = accepted_materialization(&mut tiering, owner, &artifact);
        let install = tiering.record_baseline_install(BaselineInstallRequest {
            owner,
            artifact: &artifact,
            materialization: Some(&materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::Succeeded,
            eligibility: baseline_eligibility(owner),
        });

        let mut fabricated = materialization.clone();
        fabricated.ordinal += 100;
        let unowned =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &fabricated,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Disabled,
                callable: None,
            });
        assert_eq!(
            unowned.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::MaterializationRecordNotVmOwned {
                    ordinal: fabricated.ordinal,
                }
            }
        );

        let rejected_materialization = tiering.record_baseline_executable_materialization(
            BaselineExecutableMaterializationRequest::from_artifact(
                owner,
                &artifact,
                Some(baseline_bytecode_snapshot(owner)),
                BaselineExecutableMaterializationAuthority::VmMainThread,
            ),
        );
        let rejected =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &rejected_materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Disabled,
                callable: None,
            });
        assert_eq!(
            rejected.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::MaterializationRecordNotAccepted {
                    ordinal: rejected_materialization.ordinal,
                }
            }
        );

        let other_artifact = baseline_artifact(owner, 40);
        let other_materialization = accepted_materialization(&mut tiering, owner, &other_artifact);
        let mismatched =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &other_materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Disabled,
                callable: None,
            });
        assert_eq!(
            mismatched.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason: BaselineNativeEntryReadinessRejection::ArtifactIdMismatch {
                    expected: artifact.id,
                    actual: Some(other_artifact.id),
                }
            }
        );

        let enabled =
            tiering.record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: None,
            });
        assert_eq!(
            enabled.outcome,
            BaselineNativeEntryReadinessOutcome::Rejected {
                reason:
                    BaselineNativeEntryReadinessRejection::MaterializationLinkFinalizationInvalid {
                        reason: Box::new(
                            ExecutableLedgerValidationError::FinalizationByteEvidenceMissing
                        ),
                    }
            }
        );
    }

    #[test]
    fn baseline_install_records_p5_outcomes() {
        let owner = CodeBlockId(CellId(16));
        let mut tiering = VmTieringIntegration::default();

        let artifact = baseline_artifact(owner, 16);
        let materialization = accepted_materialization(&mut tiering, owner, &artifact);
        let installed = tiering.record_baseline_install(BaselineInstallRequest {
            owner,
            artifact: &artifact,
            materialization: Some(&materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::Succeeded,
            eligibility: baseline_eligibility(owner),
        });
        assert_eq!(
            installed.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        assert_eq!(
            installed.artifact.map(|artifact| artifact.owner),
            Some(owner)
        );
        assert!(!installed.generated_code_entry_enabled);
        assert_eq!(tiering.baseline_entry_artifacts().len(), 1);

        let dead_owner = CodeBlockId(CellId(17));
        let dead_artifact = baseline_artifact(dead_owner, 17);
        let dead_owner_record = tiering.record_baseline_install(BaselineInstallRequest {
            owner: dead_owner,
            artifact: &dead_artifact,
            materialization: None,
            owner_liveness: BaselineInstallOwnerLiveness::NotLive,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::NotAttempted,
            eligibility: baseline_eligibility(dead_owner),
        });
        assert_eq!(
            dead_owner_record.outcome,
            BaselineInstallOutcome::RejectedOwnerNotLive
        );
        assert!(dead_owner_record.artifact.is_none());

        let invalid_owner = CodeBlockId(CellId(18));
        let mut invalid_artifact = baseline_artifact(invalid_owner, 18);
        invalid_artifact.tier = JitType::Dfg;
        invalid_artifact.origin.kind = CodeOriginKind::DfgReplacement;
        let invalid_materialization = tiering.record_baseline_executable_materialization(
            BaselineExecutableMaterializationRequest::from_artifact(
                invalid_owner,
                &invalid_artifact,
                Some(baseline_bytecode_snapshot(invalid_owner)),
                BaselineExecutableMaterializationAuthority::VmMainThread,
            ),
        );
        let invalid_record = tiering.record_baseline_install(BaselineInstallRequest {
            owner: invalid_owner,
            artifact: &invalid_artifact,
            materialization: Some(&invalid_materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::NotAttempted,
            eligibility: baseline_eligibility(invalid_owner),
        });
        assert_eq!(
            invalid_record.outcome,
            BaselineInstallOutcome::RejectedInvalidArtifactOrAbiProof {
                error: JitCodeValidationError::BaselineEntryTierMismatch
            }
        );

        let dependency_owner = CodeBlockId(CellId(19));
        let dependency_artifact = baseline_artifact(dependency_owner, 19);
        let dependency_materialization =
            accepted_materialization(&mut tiering, dependency_owner, &dependency_artifact);
        let dependency_record = tiering.record_baseline_install(BaselineInstallRequest {
            owner: dependency_owner,
            artifact: &dependency_artifact,
            materialization: Some(&dependency_materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Reject,
            code_block_mutation: BaselineInstallCodeBlockMutation::NotAttempted,
            eligibility: baseline_eligibility(dependency_owner),
        });
        assert_eq!(
            dependency_record.outcome,
            BaselineInstallOutcome::RejectedDependencyPolicy
        );
        assert_eq!(
            dependency_record.artifact.map(|artifact| artifact.owner),
            Some(dependency_owner)
        );
        assert!(tiering
            .baseline_entry_artifact_for(dependency_owner)
            .is_none());

        let deferred_owner = CodeBlockId(CellId(20));
        let deferred_artifact = baseline_artifact(deferred_owner, 20);
        let deferred_materialization =
            accepted_materialization(&mut tiering, deferred_owner, &deferred_artifact);
        let deferred = tiering.record_baseline_install(BaselineInstallRequest {
            owner: deferred_owner,
            artifact: &deferred_artifact,
            materialization: Some(&deferred_materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Defer,
            code_block_mutation: BaselineInstallCodeBlockMutation::NotAttempted,
            eligibility: baseline_eligibility(deferred_owner),
        });
        assert_eq!(
            deferred.outcome,
            BaselineInstallOutcome::Deferred {
                reason: BaselineInstallDeferReason::DependencyPolicy
            }
        );
        assert!(tiering
            .baseline_entry_artifact_for(deferred_owner)
            .is_none());

        let ineligible_owner = CodeBlockId(CellId(22));
        let ineligible_artifact = baseline_artifact(ineligible_owner, 22);
        let ineligible_materialization =
            accepted_materialization(&mut tiering, ineligible_owner, &ineligible_artifact);
        let ineligible = tiering.record_baseline_install(BaselineInstallRequest {
            owner: ineligible_owner,
            artifact: &ineligible_artifact,
            materialization: Some(&ineligible_materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::NotAttempted,
            eligibility: BaselineInstallEligibility::Rejected(
                BaselineInstallEligibilityRejection::DerivationFailed {
                    error: JitPlanValidationError::BaselineEligibilityEmptyBytecode,
                },
            ),
        });
        assert_eq!(
            ineligible.outcome,
            BaselineInstallOutcome::RejectedEligibilityProof {
                reason: BaselineInstallEligibilityRejection::DerivationFailed {
                    error: JitPlanValidationError::BaselineEligibilityEmptyBytecode,
                },
            }
        );
        assert!(ineligible.eligibility_proof.is_none());
        assert!(tiering
            .baseline_entry_artifact_for(ineligible_owner)
            .is_none());

        let invalidated = tiering.record_baseline_invalidation(BaselineInvalidationRequest {
            owner,
            artifact_id: installed.artifact_id,
            reason: CodeInvalidationReason::OwnerCodeBlockJettisoned,
        });
        assert_eq!(
            invalidated.outcome,
            BaselineInstallOutcome::Invalidated {
                reason: CodeInvalidationReason::OwnerCodeBlockJettisoned
            }
        );
        assert_eq!(
            invalidated.artifact.map(|artifact| artifact.owner),
            Some(owner)
        );
        assert!(tiering.baseline_entry_artifacts().is_empty());
    }

    #[test]
    fn installed_and_deferred_baseline_metadata_keep_interpreter_execution_path() {
        let installed_owner = CodeBlockId(CellId(21));
        let mut installed_tiering = VmTieringIntegration::default();
        let installed_artifact = baseline_artifact(installed_owner, 21);
        let installed_materialization =
            accepted_materialization(&mut installed_tiering, installed_owner, &installed_artifact);
        let install_record = installed_tiering.record_baseline_install(BaselineInstallRequest {
            owner: installed_owner,
            artifact: &installed_artifact,
            materialization: Some(&installed_materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Allow,
            code_block_mutation: BaselineInstallCodeBlockMutation::Succeeded,
            eligibility: baseline_eligibility(installed_owner),
        });
        assert_eq!(
            install_record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        let readiness = installed_tiering
            .baseline_native_entry_readiness_records()
            .last()
            .expect("installed native entry readiness");
        let readiness_ordinal = readiness.ordinal;
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::ReadyButExecutionDisabled
        );

        let installed_entry = installed_tiering.observe_interpreter_entry(
            TierEntryRequest {
                owner: installed_owner,
                entry_kind: ExecutionEntryKind::Function,
                bytecode_index: Some(BytecodeIndex::from_offset(0)),
                frame: Some(CallFrameId(7)),
                stack_frame: None,
                bytecode_size: Some(3),
                inline_cache_count: 0,
                policy: TieringPolicy::BaselineAllowed,
            },
            boundary,
        );
        assert_eq!(
            installed_entry
                .baseline_entry_gate
                .as_ref()
                .map(|gate| gate.outcome),
            Some(BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled)
        );
        assert_eq!(
            installed_entry
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.native_entry_readiness_ordinal),
            Some(readiness_ordinal)
        );
        assert_eq!(
            installed_entry.execution_path,
            TierEntryExecutionPath::Interpreter
        );

        let deferred_owner = CodeBlockId(CellId(22));
        let mut deferred_tiering = VmTieringIntegration::default();
        let deferred_artifact = baseline_artifact(deferred_owner, 22);
        let deferred_materialization =
            accepted_materialization(&mut deferred_tiering, deferred_owner, &deferred_artifact);
        let deferred_record = deferred_tiering.record_baseline_install(BaselineInstallRequest {
            owner: deferred_owner,
            artifact: &deferred_artifact,
            materialization: Some(&deferred_materialization),
            owner_liveness: BaselineInstallOwnerLiveness::Live,
            dependency_policy: BaselineInstallDependencyPolicy::Defer,
            code_block_mutation: BaselineInstallCodeBlockMutation::NotAttempted,
            eligibility: baseline_eligibility(deferred_owner),
        });
        assert_eq!(
            deferred_record.outcome,
            BaselineInstallOutcome::Deferred {
                reason: BaselineInstallDeferReason::DependencyPolicy
            }
        );

        let deferred_entry = deferred_tiering.observe_interpreter_entry(
            TierEntryRequest {
                owner: deferred_owner,
                entry_kind: ExecutionEntryKind::Function,
                bytecode_index: Some(BytecodeIndex::from_offset(0)),
                frame: Some(CallFrameId(8)),
                stack_frame: None,
                bytecode_size: Some(3),
                inline_cache_count: 0,
                policy: TieringPolicy::BaselineAllowed,
            },
            boundary,
        );
        assert_eq!(
            deferred_entry
                .baseline_entry_gate
                .as_ref()
                .map(|gate| gate.outcome),
            Some(BaselineEntryGateOutcome::MissingArtifact)
        );
        assert_eq!(
            deferred_entry.execution_path,
            TierEntryExecutionPath::Interpreter
        );
    }

    #[test]
